import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Rating {
  SI = 'SI',
  NO = 'NO',
  PARCIAL = 'PARCIAL',
  NA = 'N/A'
}

export interface Question {
  id: number;
  text: string;
}

export interface Answer {
  questionId: number;
  rating: Rating;
}

export interface AuditRecord {
  id: string;
  area: string;
  auditor: string;
  date: string; // ISO string
  answers: Answer[];
  score: number; // 0-100
}

export type ViewState = 'form' | 'dashboard' | 'history' | 'ai-editor';

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const editImageWithGemini = async (base64Image: string, prompt: string): Promise<string> => {
  try {
    // Determine mimeType (simplified assumption for base64 strings usually starting with data:image/...)
    const mimeType = base64Image.match(/data:([a-zA-Z0-9]+\/[a-zA-Z0-9-.+]+).*,.*/)?.[1] || 'image/png';
    const data = base64Image.split(',')[1]; // Remove header

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: data,
              mimeType: mimeType,
            },
          },
          {
            text: prompt,
          },
        ],
      },
    });

    let resultImage = '';

    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
            resultImage = `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
            break;
        }
      }
    }

    if (!resultImage) {
        throw new Error("No image returned from Gemini. Ensure the prompt asks for an image modification.");
    }

    return resultImage;

  } catch (error) {
    console.error("Error editing image with Gemini:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Rating, Answer, AuditRecord } from '../types';
import { QUESTIONS, AREAS } from '../constants';
import { Save, AlertCircle } from 'lucide-react';

interface AuditFormProps {
  initialData?: AuditRecord | null;
  onSave: (record: AuditRecord) => void;
  onCancel: () => void;
}

export const AuditForm: React.FC<AuditFormProps> = ({ initialData, onSave, onCancel }) => {
  const [area, setArea] = useState(AREAS[0]);
  const [auditor, setAuditor] = useState('');
  const [answers, setAnswers] = useState<Record<number, Rating>>({});

  useEffect(() => {
    if (initialData) {
      setArea(initialData.area);
      setAuditor(initialData.auditor);
      const loadedAnswers: Record<number, Rating> = {};
      initialData.answers.forEach(a => {
        loadedAnswers[a.questionId] = a.rating;
      });
      setAnswers(loadedAnswers);
    }
  }, [initialData]);

  const handleRatingChange = (questionId: number, rating: Rating) => {
    setAnswers(prev => ({ ...prev, [questionId]: rating }));
  };

  const calculateScore = () => {
    let totalPoints = 0;
    let maxPoints = 0;

    Object.values(answers).forEach(rating => {
      if (rating === Rating.SI) {
        totalPoints += 1;
        maxPoints += 1;
      } else if (rating === Rating.PARCIAL) {
        totalPoints += 0.5;
        maxPoints += 1;
      } else if (rating === Rating.NO) {
        maxPoints += 1;
      }
      // N/A does not contribute to maxPoints
    });

    return maxPoints === 0 ? 0 : Math.round((totalPoints / maxPoints) * 100);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!auditor.trim()) {
      alert("Por favor ingrese el nombre del auditor");
      return;
    }

    const answerList: Answer[] = Object.entries(answers).map(([qId, rating]) => ({
      questionId: parseInt(qId),
      rating
    }));

    if (answerList.length !== QUESTIONS.length) {
      if(!confirm("No ha respondido todas las preguntas. ¿Desea guardar de todos modos?")) {
        return;
      }
    }

    const record: AuditRecord = {
      id: initialData ? initialData.id : crypto.randomUUID(),
      area,
      auditor,
      date: initialData ? initialData.date : new Date().toISOString(),
      answers: answerList,
      score: calculateScore(),
    };

    onSave(record);
  };

  return (
    <div className="bg-white rounded-lg shadow-lg p-6 max-w-4xl mx-auto mb-20">
      <h2 className="text-2xl font-bold mb-6 text-gray-800 border-b pb-2">
        {initialData ? 'Editar Auditoría' : 'Nueva Auditoría'}
      </h2>

      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Área</label>
            <select
              value={area}
              onChange={(e) => setArea(e.target.value)}
              className="w-full border border-gray-300 rounded-md p-2 focus:ring-blue-500 focus:border-blue-500"
            >
              {AREAS.map(a => <option key={a} value={a}>{a}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Auditor</label>
            <input
              type="text"
              value={auditor}
              onChange={(e) => setAuditor(e.target.value)}
              placeholder="Nombre del responsable"
              className="w-full border border-gray-300 rounded-md p-2 focus:ring-blue-500 focus:border-blue-500"
            />
          </div>
        </div>

        <div className="space-y-6">
          {QUESTIONS.map((q) => (
            <div key={q.id} className="bg-gray-50 p-4 rounded-md border border-gray-200">
              <p className="text-gray-900 font-medium mb-3">{q.id}. {q.text}</p>
              <div className="flex flex-wrap gap-2 sm:gap-4">
                {Object.values(Rating).map((rating) => (
                  <label key={rating} className="flex items-center space-x-2 cursor-pointer">
                    <input
                      type="radio"
                      name={`q-${q.id}`}
                      value={rating}
                      checked={answers[q.id] === rating}
                      onChange={() => handleRatingChange(q.id, rating)}
                      className="text-blue-600 focus:ring-blue-500 h-4 w-4"
                    />
                    <span className={`text-sm px-2 py-1 rounded-full ${
                      rating === Rating.SI ? 'bg-green-100 text-green-800' :
                      rating === Rating.NO ? 'bg-red-100 text-red-800' :
                      rating === Rating.PARCIAL ? 'bg-yellow-100 text-yellow-800' :
                      'bg-gray-200 text-gray-800'
                    }`}>
                      {rating}
                    </span>
                  </label>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-8 flex justify-end gap-4 sticky bottom-0 bg-white p-4 border-t shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
          <button
            type="button"
            onClick={onCancel}
            className="px-4 py-2 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50"
          >
            Cancelar
          </button>
          <button
            type="submit"
            className="flex items-center px-6 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 shadow-sm"
          >
            <Save className="w-4 h-4 mr-2" />
            Guardar Auditoría
          </button>
        </div>
      </form>
    </div>
  );
};

import React from 'react';
import { AuditRecord } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell } from 'recharts';

interface DashboardProps {
  records: AuditRecord[];
}

export const Dashboard: React.FC<DashboardProps> = ({ records }) => {
  // Aggregate average score by Area
  const areaStats: Record<string, { totalScore: number; count: number }> = {};

  records.forEach(r => {
    if (!areaStats[r.area]) {
      areaStats[r.area] = { totalScore: 0, count: 0 };
    }
    areaStats[r.area].totalScore += r.score;
    areaStats[r.area].count += 1;
  });

  const chartData = Object.entries(areaStats).map(([area, stats]) => ({
    name: area,
    score: Math.round(stats.totalScore / stats.count),
    audits: stats.count
  }));

  // Color logic for bars
  const getBarColor = (score: number) => {
    if (score >= 90) return '#22c55e'; // Green
    if (score >= 70) return '#eab308'; // Yellow
    return '#ef4444'; // Red
  };

  return (
    <div className="space-y-6 mb-20">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <div className="bg-white p-6 rounded-lg shadow-md border-l-4 border-blue-500">
          <h3 className="text-gray-500 text-sm font-medium">Total Auditorías</h3>
          <p className="text-3xl font-bold text-gray-800">{records.length}</p>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md border-l-4 border-green-500">
          <h3 className="text-gray-500 text-sm font-medium">Promedio General</h3>
          <p className="text-3xl font-bold text-gray-800">
            {records.length > 0
              ? Math.round(records.reduce((acc, r) => acc + r.score, 0) / records.length)
              : 0}%
          </p>
        </div>
        <div className="bg-white p-6 rounded-lg shadow-md border-l-4 border-purple-500">
          <h3 className="text-gray-500 text-sm font-medium">Áreas Auditadas</h3>
          <p className="text-3xl font-bold text-gray-800">{chartData.length}</p>
        </div>
      </div>

      <div className="bg-white p-6 rounded-lg shadow-md">
        <h3 className="text-lg font-bold text-gray-800 mb-6">Desempeño por Área (%)</h3>
        <div className="h-80 w-full">
          {chartData.length > 0 ? (
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={chartData} layout="vertical" margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" />
                <XAxis type="number" domain={[0, 100]} />
                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12}} />
                <Tooltip 
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.1)' }}
                    cursor={{fill: '#f3f4f6'}}
                />
                <Legend />
                <Bar dataKey="score" name="Puntaje Promedio" radius={[0, 4, 4, 0]} barSize={30}>
                    {chartData.map((entry, index) => (
                        <Cell key={`cell-${index}`} fill={getBarColor(entry.score)} />
                    ))}
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          ) : (
            <div className="flex items-center justify-center h-full text-gray-400">
              No hay datos suficientes para mostrar el gráfico
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React from 'react';
import { AuditRecord } from '../types';
import { QUESTIONS } from '../constants';
import * as XLSX from 'xlsx';
import { Edit2, Trash2, Download, FileSpreadsheet } from 'lucide-react';

interface HistoryProps {
  records: AuditRecord[];
  onEdit: (record: AuditRecord) => void;
  onDelete: (id: string) => void;
}

export const History: React.FC<HistoryProps> = ({ records, onEdit, onDelete }) => {

  const handleExportExcel = () => {
    // Flatten data for Excel
    const data = records.map(r => {
      const row: any = {
        'Fecha': new Date(r.date).toLocaleString(),
        'Área': r.area,
        'Auditor': r.auditor,
        'Puntaje': `${r.score}%`
      };

      // Add questions columns
      r.answers.forEach(a => {
        const qText = QUESTIONS.find(q => q.id === a.questionId)?.text || `P${a.questionId}`;
        row[qText] = a.rating;
      });

      return row;
    });

    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Auditorías");
    XLSX.writeFile(wb, "Reporte_Auditorias.xlsx");
  };

  return (
    <div className="bg-white rounded-lg shadow-lg p-6 mb-20">
      <div className="flex justify-between items-center mb-6">
        <h2 className="text-2xl font-bold text-gray-800">Historial de Auditorías</h2>
        <button 
          onClick={handleExportExcel}
          className="flex items-center px-4 py-2 bg-green-600 text-white rounded-md hover:bg-green-700 transition-colors"
        >
          <FileSpreadsheet className="w-4 h-4 mr-2" />
          Exportar a Excel
        </button>
      </div>

      <div className="overflow-x-auto">
        <table className="min-w-full divide-y divide-gray-200">
          <thead className="bg-gray-50">
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Fecha</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Área</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Auditor</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Puntaje</th>
              <th className="px-6 py-3 text-right text-xs font-medium text-gray-500 uppercase tracking-wider">Acciones</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {records.length === 0 ? (
                <tr>
                    <td colSpan={5} className="px-6 py-10 text-center text-gray-500">
                        No hay registros guardados aún.
                    </td>
                </tr>
            ) : (
                records.map((record) => (
                <tr key={record.id} className="hover:bg-gray-50">
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-700">
                    {new Date(record.date).toLocaleDateString()}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900 font-medium">
                    {record.area}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-700">
                    {record.auditor}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-sm">
                    <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                        record.score >= 90 ? 'bg-green-100 text-green-800' : 
                        record.score >= 70 ? 'bg-yellow-100 text-yellow-800' : 
                        'bg-red-100 text-red-800'
                    }`}>
                        {record.score}%
                    </span>
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-right text-sm font-medium">
                    <button 
                        onClick={() => onEdit(record)}
                        className="text-blue-600 hover:text-blue-900 mr-4" 
                        title="Editar"
                    >
                        <Edit2 className="w-5 h-5" />
                    </button>
                    <button 
                        onClick={() => onDelete(record.id)}
                        className="text-red-600 hover:text-red-900"
                        title="Eliminar"
                    >
                        <Trash2 className="w-5 h-5" />
                    </button>
                    </td>
                </tr>
                ))
            )}
          </tbody>
        </table>
      </div>
      <p className="mt-4 text-xs text-gray-500">
        * Para cargar datos a SharePoint, exporte el Excel y súbalo manualmente a su lista o biblioteca.
      </p>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { editImageWithGemini } from '../services/geminiService';
import { Upload, Wand2, RefreshCw, Download, Image as ImageIcon } from 'lucide-react';

export const AIEditor: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setOriginalImage(reader.result as string);
        setGeneratedImage(null); // Reset previous generation
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!originalImage || !prompt.trim()) return;

    setIsLoading(true);
    try {
      const result = await editImageWithGemini(originalImage, prompt);
      setGeneratedImage(result);
    } catch (error) {
      alert("Error al procesar la imagen. Intenta con un prompt diferente o verifica tu API Key.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="bg-white rounded-lg shadow-lg p-6 max-w-4xl mx-auto mb-20">
      <div className="flex items-center gap-3 mb-6 border-b pb-4">
        <div className="bg-purple-100 p-2 rounded-lg">
          <Wand2 className="w-6 h-6 text-purple-600" />
        </div>
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Editor de Evidencia con IA</h2>
          <p className="text-sm text-gray-500">Sube una foto de la auditoría y usa Gemini para resaltar fallos o visualizar mejoras.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        {/* Input Section */}
        <div className="space-y-4">
          <div 
            className={`border-2 border-dashed rounded-xl h-64 flex flex-col items-center justify-center cursor-pointer transition-colors ${
              originalImage ? 'border-blue-300 bg-blue-50' : 'border-gray-300 hover:border-purple-400 hover:bg-purple-50'
            }`}
            onClick={() => fileInputRef.current?.click()}
          >
            {originalImage ? (
              <img src={originalImage} alt="Original" className="h-full w-full object-contain rounded-lg" />
            ) : (
              <div className="text-center p-4">
                <Upload className="w-10 h-10 text-gray-400 mx-auto mb-2" />
                <p className="text-sm text-gray-500">Clic para subir imagen</p>
                <p className="text-xs text-gray-400 mt-1">Soporta JPG, PNG</p>
              </div>
            )}
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileChange} 
              accept="image/*" 
              className="hidden" 
            />
          </div>

          <div className="flex gap-2">
            <input
              type="text"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Ej: 'Resalta con rojo la caja en el suelo' o 'Elimina la basura del pasillo'"
              className="flex-1 border border-gray-300 rounded-md p-2 focus:ring-purple-500 focus:border-purple-500"
            />
            <button
              onClick={handleGenerate}
              disabled={!originalImage || !prompt || isLoading}
              className={`px-4 py-2 rounded-md text-white font-medium flex items-center ${
                !originalImage || !prompt || isLoading 
                  ? 'bg-gray-400 cursor-not-allowed' 
                  : 'bg-purple-600 hover:bg-purple-700'
              }`}
            >
              {isLoading ? <RefreshCw className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
            </button>
          </div>
        </div>

        {/* Output Section */}
        <div className="border border-gray-200 rounded-xl h-64 md:h-auto flex items-center justify-center bg-gray-50 relative overflow-hidden">
          {isLoading ? (
            <div className="text-center">
              <RefreshCw className="w-10 h-10 text-purple-600 animate-spin mx-auto mb-2" />
              <p className="text-sm text-purple-600 font-medium">Gemini está pensando...</p>
            </div>
          ) : generatedImage ? (
            <div className="relative w-full h-full group">
              <img src={generatedImage} alt="Generada por IA" className="w-full h-full object-contain" />
              <a 
                href={generatedImage} 
                download="evidencia_editada.png"
                className="absolute top-2 right-2 p-2 bg-white/90 rounded-full shadow-sm opacity-0 group-hover:opacity-100 transition-opacity hover:text-purple-600"
              >
                <Download className="w-5 h-5" />
              </a>
            </div>
          ) : (
            <div className="text-center text-gray-400 p-4">
              <ImageIcon className="w-10 h-10 mx-auto mb-2 opacity-30" />
              <p className="text-sm">La imagen editada aparecerá aquí</p>
            </div>
          )}
        </div>
      </div>

      <div className="mt-4 p-3 bg-blue-50 text-blue-800 rounded-md text-xs">
        <strong>Nota:</strong> Esta función utiliza el modelo <code>gemini-2.5-flash-image</code>. Describe claramente qué cambio quieres ver en la imagen.
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from 'lucide-react';
import { ViewState, AuditRecord } from './types';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ClipboardList, LayoutDashboard, History as HistoryIcon, Camera } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('dashboard');
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('audit_records');
    if (saved) {
      try {
        setRecords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse records", e);
      }
    }
  }, []);

  // Save to local storage whenever records change
  useEffect(() => {
    localStorage.setItem('audit_records', JSON.stringify(records));
  }, [records]);

  const handleSaveAudit = (record: AuditRecord) => {
    if (editingRecord) {
      setRecords(prev => prev.map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...prev]);
    }
    setView('dashboard');
  };

  const handleEdit = (record: AuditRecord) => {
    setEditingRecord(record);
    setView('form');
  };

  const handleDelete = (id: string) => {
    if (confirm("¿Está seguro de eliminar este registro?")) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleCancelForm = () => {
    setEditingRecord(null);
    setView('dashboard');
  };

  const renderContent = () => {
    switch (view) {
      case 'form':
        return <AuditForm initialData={editingRecord} onSave={handleSaveAudit} onCancel={handleCancelForm} />;
      case 'dashboard':
        return <Dashboard records={records} />;
      case 'history':
        return <History records={records} onEdit={handleEdit} onDelete={handleDelete} />;
      case 'ai-editor':
        return <AIEditor />;
      default:
        return <Dashboard records={records} />;
    }
  };

  return (
    <div className="min-h-screen bg-gray-100 text-gray-900 font-sans">
      {/* Header */}
      <header className="bg-slate-900 text-white shadow-lg sticky top-0 z-10">
        <div className="max-w-7xl mx-auto px-4 py-4 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-blue-600 p-2 rounded-lg">
              <ClipboardList className="w-6 h-6 text-white" />
            </div>
            <h1 className="text-xl font-bold tracking-tight">AuditCheck <span className="text-blue-400">Pro</span></h1>
          </div>
          <div className="text-xs text-gray-400 hidden sm:block">
