import React, { useState, useEffect } from 'react';
import { Rating, Answer, AuditRecord } from '../types';
import { QUESTIONS, AREAS } from '../constants';
import { Save, AlertCircle } from 'lucide-react';

interface AuditFormProps {
  initialData?: AuditRecord | null;
  onSave: (record: AuditRecord) => void;
  onCancel: () => void;
}

export const AuditForm: React.FC<AuditFormProps> = ({ initialData, onSave, onCancel }) => {
  const [area, setArea] = useState(AREAS[0]);
  const [auditor, setAuditor] = useState('');
  const [answers, setAnswers] = useState<Record<number, Rating>>({});

  useEffect(() => {
    if (initialData) {
      setArea(initialData.area);
      setAuditor(initialData.auditor);
      const loadedAnswers: Record<number, Rating> = {};
      initialData.answers.forEach(a => {
        loadedAnswers[a.questionId] = a.rating;
      });
      setAnswers(loadedAnswers);
    }
  }, [initialData]);

  const handleRatingChange = (questionId: number, rating: Rating) => {
    setAnswers(prev => ({ ...prev, [questionId]: rating }));
  };

  const calculateScore = () => {
    let totalPoints = 0;
    let maxPoints = 0;

    Object.values(answers).forEach(rating => {
      if (rating === Rating.SI) {
        totalPoints += 1;
        maxPoints += 1;
      } else if (rating === Rating.PARCIAL) {
        totalPoints += 0.5;
        maxPoints += 1;
      } else if (rating === Rating.NO) {
        maxPoints += 1;
      }
      // N/A does not contribute to maxPoints
    });

    return maxPoints === 0 ? 0 : Math.round((totalPoints / maxPoints) * 100);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!auditor.trim()) {
      alert("Por favor ingrese el nombre del auditor");
      return;
    }

    const answerList: Answer[] = Object.entries(answers).map(([qId, rating]) => ({
      questionId: parseInt(qId),
      rating: rating as Rating
    }));

    if (answerList.length !== QUESTIONS.length) {
      if(!confirm("No ha respondido todas las preguntas. ¿Desea guardar de todos modos?")) {
        return;
      }
    }

    const record: AuditRecord = {
      id: initialData ? initialData.id : crypto.randomUUID(),
      area,
      auditor,
      date: initialData ? initialData.date : new Date().toISOString(),
      answers: answerList,
      score: calculateScore(),
    };

    onSave(record);
  };

  return (
    <div className="bg-white rounded-lg shadow-lg p-6 max-w-4xl mx-auto mb-20">
      <h2 className="text-2xl font-bold mb-6 text-gray-800 border-b pb-2">
        {initialData ? 'Editar Auditoría' : 'Nueva Auditoría'}
      </h2>

      <form onSubmit={handleSubmit}>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Área</label>
            <select
              value={area}
              onChange={(e) => setArea(e.target.value)}
              className="w-full border border-gray-300 rounded-md p-2 focus:ring-blue-500 focus:border-blue-500"
            >
              {AREAS.map(a => <option key={a} value={a}>{a}</option>)}
            </select>
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-1">Auditor</label>
            <input
              type="text"
              value={auditor}
              onChange={(e) => setAuditor(e.target.value)}
              placeholder="Nombre del responsable"
              className="w-full border border-gray-300 rounded-md p-2 focus:ring-blue-500 focus:border-blue-500"
            />
          </div>
        </div>

        <div className="space-y-6">
          {QUESTIONS.map((q) => (
            <div key={q.id} className="bg-gray-50 p-4 rounded-md border border-gray-200">
              <p className="text-gray-900 font-medium mb-3">{q.id}. {q.text}</p>
              <div className="flex flex-wrap gap-2 sm:gap-4">
                {Object.values(Rating).map((rating) => (
                  <label key={rating} className="flex items-center space-x-2 cursor-pointer">
                    <input
                      type="radio"
                      name={`q-${q.id}`}
                      value={rating}
                      checked={answers[q.id] === rating}
                      onChange={() => handleRatingChange(q.id, rating)}
                      className="text-blue-600 focus:ring-blue-500 h-4 w-4"
                    />
                    <span className={`text-sm px-2 py-1 rounded-full ${
                      rating === Rating.SI ? 'bg-green-100 text-green-800' :
                      rating === Rating.NO ? 'bg-red-100 text-red-800' :
                      rating === Rating.PARCIAL ? 'bg-yellow-100 text-yellow-800' :
                      'bg-gray-200 text-gray-800'
                    }`}>
                      {rating}
                    </span>
                  </label>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="mt-8 flex justify-end gap-4 sticky bottom-0 bg-white p-4 border-t shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)]">
          <button
            type="button"
            onClick={onCancel}
            className="px-4 py-2 border border-gray-300 rounded-md text-gray-700 hover:bg-gray-50"
          >
            Cancelar
          </button>
          <button
            type="submit"
            className="flex items-center px-6 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 shadow-sm"
          >
            <Save className="w-4 h-4 mr-2" />
            Guardar Auditoría
          </button>
        </div>
      </form>
    </div>
  );
};

export enum Rating {
  SI = 'SI',
