                        index === 2 ? 'bg-orange-100 text-orange-800' : 'bg-gray-50 text-gray-500'
                      }`}>
                        {index + 1}
                      </div>
                      <div>
                        <p className="font-medium text-gray-800 text-sm md:text-base">{item.name}</p>
                        <p className="text-xs text-gray-400">{item.audits} auditoría(s)</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="w-24 h-2 bg-gray-100 rounded-full hidden sm:block overflow-hidden">
                        <div 
                          className="h-full rounded-full" 
                          style={{ 
                            width: `${item.score}%`,
                            backgroundColor: getBarColor(item.score) 
                          }} 
                        />
                      </div>
                      <span className={`px-3 py-1 rounded-full text-xs font-bold border ${getScoreColor(item.score)}`}>
                        {item.score}%
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="p-8 text-center text-gray-400">Sin datos registrados</div>
            )}
          </div>
        </div>

        {/* Chart */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Tendencia General</h3>
          <div className="h-80 w-full">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                  <XAxis type="number" domain={[0, 100]} hide />
                  <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 11}} />
                  <Tooltip 
                      contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                      cursor={{fill: '#f8fafc'}}
                  />
                  <Bar dataKey="score" name="Puntaje" radius={[0, 4, 4, 0]} barSize={20}>
                      {chartData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={getBarColor(entry.score)} />
                      ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-gray-400">
                Gráfico vacío
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Rating, Answer, AuditRecord } from '../types';
import { QUESTIONS, AREAS, AREA_MAPPING } from '../constants';
import { Save, User, MapPin, ClipboardCheck, AlertCircle, UserCircle } from 'lucide-react';

interface AuditFormProps {
  initialData?: AuditRecord | null;
  onSave: (record: AuditRecord) => void;
  onCancel: () => void;
}

export const AuditForm: React.FC<AuditFormProps> = ({ initialData, onSave, onCancel }) => {
  const [area, setArea] = useState(AREAS[0]);
  const [auditor, setAuditor] = useState('');
  const [responsable, setResponsable] = useState('');
  const [answers, setAnswers] = useState<Record<number, Rating>>({});
  const [activeStep, setActiveStep] = useState(0); // For future multi-step, simple for now

  // Initialize data for editing or new form
  useEffect(() => {
    if (initialData) {
      setArea(initialData.area);
      setAuditor(initialData.auditor);
      setResponsable(initialData.responsable || getResponsableForArea(initialData.area));
      const loadedAnswers: Record<number, Rating> = {};
      initialData.answers.forEach(a => {
        loadedAnswers[a.questionId] = a.rating;
      });
      setAnswers(loadedAnswers);
    } else {
      // Set initial responsable for default area
      setResponsable(getResponsableForArea(AREAS[0]));
    }
  }, [initialData]);

  // Update responsable when area changes
  useEffect(() => {
    if (!initialData || (initialData && area !== initialData.area)) {
       setResponsable(getResponsableForArea(area));
    }
  }, [area, initialData]);

  const getResponsableForArea = (areaName: string) => {
    const mapping = AREA_MAPPING.find(m => m.area === areaName);
    return mapping ? mapping.responsable : '';
  };

  const handleRatingChange = (questionId: number, rating: Rating) => {
    setAnswers(prev => ({ ...prev, [questionId]: rating }));
  };

  const calculateScore = () => {
    let totalPoints = 0;
    let maxPoints = 0;

    Object.values(answers).forEach(rating => {
      if (rating === Rating.SI) {
        totalPoints += 1;
        maxPoints += 1;
      } else if (rating === Rating.PARCIAL) {
        totalPoints += 0.5;
        maxPoints += 1;
      } else if (rating === Rating.NO) {
        maxPoints += 1;
      }
      // N/A does not contribute to maxPoints
    });

    return maxPoints === 0 ? 0 : Math.round((totalPoints / maxPoints) * 100);
  };

  const currentScore = calculateScore();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!auditor.trim()) {
      alert("Por favor ingrese el nombre del auditor");
      return;
    }

    const answerList: Answer[] = Object.entries(answers).map(([qId, rating]) => ({
      questionId: parseInt(qId),
      rating: rating as Rating
    }));

    if (answerList.length !== QUESTIONS.length) {
      if(!confirm("No ha respondido todas las preguntas. ¿Desea guardar de todos modos?")) {
        return;
      }
    }

    const record: AuditRecord = {
      id: initialData ? initialData.id : crypto.randomUUID(),
      area,
      auditor,
      responsable,
      date: initialData ? initialData.date : new Date().toISOString(),
      answers: answerList,
      score: currentScore,
    };

    onSave(record);
  };

  const getRatingColorClass = (rating: Rating, isSelected: boolean) => {
    if (!isSelected) return 'bg-white border-gray-200 text-gray-500 hover:bg-gray-50';
    switch (rating) {
      case Rating.SI: return 'bg-green-600 border-green-600 text-white shadow-md shadow-green-200';
      case Rating.NO: return 'bg-red-600 border-red-600 text-white shadow-md shadow-red-200';
      case Rating.PARCIAL: return 'bg-yellow-500 border-yellow-500 text-white shadow-md shadow-yellow-200';
      case Rating.NA: return 'bg-gray-600 border-gray-600 text-white';
      default: return '';
    }
  };

  return (
    <div className="max-w-4xl mx-auto mb-24">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-gray-800">
          {initialData ? 'Editar Auditoría' : 'Nueva Auditoría'}
        </h2>
        <div className={`px-4 py-2 rounded-lg font-bold text-lg border ${
            currentScore >= 90 ? 'bg-green-50 text-green-700 border-green-200' :
            currentScore >= 70 ? 'bg-yellow-50 text-yellow-700 border-yellow-200' :
            'bg-red-50 text-red-700 border-red-200'
        }`}>
            {currentScore}% pts
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Info Card */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-4 border-b pb-2 flex items-center gap-2">
            <ClipboardCheck className="w-4 h-4" /> Información General
          </h3>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">

            {/* Area Selection */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700 flex items-center gap-2">
                <MapPin className="w-4 h-4 text-blue-500" /> Área a Auditar
              </label>
              <div className="relative">
                <select
                  value={area}
                  onChange={(e) => setArea(e.target.value)}
                  className="w-full appearance-none bg-gray-50 border border-gray-300 text-gray-900 rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-3 pr-8"
                >
                  {AREAS.map(a => <option key={a} value={a}>{a}</option>)}
                </select>
                <div className="pointer-events-none absolute inset-y-0 right-0 flex items-center px-2 text-gray-700">
                  <svg className="fill-current h-4 w-4" xmlns="http://www.w3.org/2000/svg" viewBox="0 0 20 20"><path d="M9.293 12.95l.707.707L15.657 8l-1.414-1.414L10 10.828 5.757 6.586 4.343 8z"/></svg>
                </div>
              </div>
            </div>

            {/* Responsable Field (Editable but Auto-filled) */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-gray-700 flex items-center gap-2">
                <UserCircle className="w-4 h-4 text-purple-500" /> Responsable del Área
              </label>
              <input
                type="text"
                value={responsable}
                onChange={(e) => setResponsable(e.target.value)}
                className="w-full bg-purple-50 border border-purple-200 text-purple-900 rounded-lg focus:ring-purple-500 focus:border-purple-500 block w-full p-3 font-medium"
                placeholder="Nombre del responsable"
              />
              <p className="text-xs text-gray-400">Se llena automáticamente, pero puede editarlo.</p>
            </div>

            {/* Auditor Field */}
            <div className="space-y-2 md:col-span-2">
              <label className="text-sm font-medium text-gray-700 flex items-center gap-2">
                <User className="w-4 h-4 text-gray-500" /> Auditor (Evaluador)
              </label>
              <input
                type="text"
                value={auditor}
                onChange={(e) => setAuditor(e.target.value)}
                placeholder="Ingrese su nombre completo"
                className="bg-white border border-gray-300 text-gray-900 rounded-lg focus:ring-blue-500 focus:border-blue-500 block w-full p-3"
              />
            </div>
          </div>
        </div>

        {/* Questions */}
        <div className="space-y-4">
          {QUESTIONS.map((q, index) => (
            <div key={q.id} className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm hover:shadow-md transition-shadow">
              <div className="flex justify-between items-start mb-4">
                <div className="flex gap-3">
                  <span className="flex-shrink-0 w-6 h-6 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center text-xs font-bold mt-0.5">
                    {index + 1}
                  </span>
                  <p className="text-gray-800 font-medium leading-tight pt-0.5">{q.text}</p>
                </div>
              </div>

              <div className="grid grid-cols-2 sm:grid-cols-4 gap-2 sm:gap-4 mt-2 pl-9">
                {Object.values(Rating).map((rating) => (
                  <button
                    key={rating}
                    type="button"
                    onClick={() => handleRatingChange(q.id, rating)}
                    className={`
                      py-2 px-3 rounded-lg border text-sm font-semibold transition-all duration-200
                      ${getRatingColorClass(rating, answers[q.id] === rating)}
                    `}
                  >
                    {rating}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="flex justify-end gap-4 sticky bottom-20 z-10">
          <div className="bg-white/80 backdrop-blur-md p-2 rounded-xl shadow-lg border border-gray-200 flex gap-3">
            <button
              type="button"
              onClick={onCancel}
              className="px-5 py-2.5 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 font-medium transition-colors"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="flex items-center px-6 py-2.5 bg-blue-600 text-white rounded-lg hover:bg-blue-700 shadow-md hover:shadow-lg font-medium transition-all"
            >
              <Save className="w-4 h-4 mr-2" />
              Guardar
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

import React from 'react';
import { AuditRecord } from '../types';
import { QUESTIONS } from '../constants';
import * as XLSX from 'xlsx';
import { Edit2, Trash2, Download, FileSpreadsheet, Calendar, User, MapPin } from 'lucide-react';

interface HistoryProps {
  records: AuditRecord[];
  onEdit: (record: AuditRecord) => void;
  onDelete: (id: string) => void;
}

export const History: React.FC<HistoryProps> = ({ records, onEdit, onDelete }) => {

  const handleExportExcel = () => {
    // Flatten data for Excel
    const data = records.map(r => {
      const row: any = {
        'Fecha': new Date(r.date).toLocaleString(),
        'Área': r.area,
        'Responsable': r.responsable || 'N/A',
        'Auditor': r.auditor,
        'Puntaje': `${r.score}%`
      };

      // Add questions columns
      r.answers.forEach(a => {
        const qText = QUESTIONS.find(q => q.id === a.questionId)?.text || `P${a.questionId}`;
        row[qText] = a.rating;
      });

      return row;
    });

    const ws = XLSX.utils.json_to_sheet(data);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, "Auditorías");
    XLSX.writeFile(wb, "Reporte_Auditorias.xlsx");
  };

  const getScoreBadge = (score: number) => {
    let colorClass = '';
    if (score >= 90) colorClass = 'bg-green-100 text-green-800 border-green-200';
    else if (score >= 70) colorClass = 'bg-yellow-100 text-yellow-800 border-yellow-200';
    else colorClass = 'bg-red-100 text-red-800 border-red-200';

    return (
      <span className={`px-2.5 py-0.5 inline-flex text-xs leading-5 font-bold rounded-full border ${colorClass}`}>
        {score}%
      </span>
    );
  };

  return (
    <div className="space-y-6 mb-24">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-white p-5 rounded-xl shadow-sm border border-gray-100">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Historial</h2>
          <p className="text-sm text-gray-500">{records.length} auditorías registradas</p>
        </div>
        <button 
          onClick={handleExportExcel}
          className="w-full sm:w-auto flex items-center justify-center px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-all shadow-sm hover:shadow-md"
        >
          <FileSpreadsheet className="w-4 h-4 mr-2" />
          Exportar Excel
        </button>
      </div>

      {records.length === 0 ? (
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-12 text-center">
            <div className="w-16 h-16 bg-gray-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <FileSpreadsheet className="w-8 h-8 text-gray-400" />
            </div>
            <h3 className="text-lg font-medium text-gray-900">No hay registros</h3>
            <p className="text-gray-500 mt-1">Comience una nueva auditoría para ver los datos aquí.</p>
        </div>
      ) : (
        <>
          {/* Mobile Card View */}
          <div className="grid grid-cols-1 gap-4 sm:hidden">
            {records.map((record) => (
              <div key={record.id} className="bg-white rounded-xl shadow-sm border border-gray-200 p-4 relative overflow-hidden">
                <div className={`absolute top-0 left-0 w-1 h-full ${
                    record.score >= 90 ? 'bg-green-500' : record.score >= 70 ? 'bg-yellow-500' : 'bg-red-500'
                }`}></div>

                <div className="flex justify-between items-start pl-3 mb-3">
                  <div>
                    <h3 className="font-bold text-gray-900">{record.area}</h3>
                    <p className="text-xs text-gray-500 flex items-center mt-1">
                      <Calendar className="w-3 h-3 mr-1" />
                      {new Date(record.date).toLocaleDateString()}
                    </p>
                  </div>
                  {getScoreBadge(record.score)}
                </div>

                <div className="pl-3 grid grid-cols-2 gap-2 text-sm text-gray-600 mb-4 bg-gray-50 p-2 rounded-lg">
                    <div className="flex flex-col">
                        <span className="text-[10px] uppercase text-gray-400 font-semibold">Responsable</span>
                        <span className="font-medium truncate">{record.responsable || '-'}</span>
                    </div>
                    <div className="flex flex-col">
                        <span className="text-[10px] uppercase text-gray-400 font-semibold">Auditor</span>
                        <span className="font-medium truncate">{record.auditor}</span>
                    </div>
                </div>

                <div className="pl-3 flex justify-end gap-3 border-t border-gray-100 pt-3">
                    <button 
