                        </td>
                    </tr>
                ))}
              </tbody>
            </table>
          </div>
        </>
      )}

      <p className="text-center text-xs text-gray-400">
        * Para cargar datos a SharePoint, exporte el Excel y súbalo manualmente a su lista o biblioteca.
      </p>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState, AuditRecord } from './types';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ClipboardList, LayoutDashboard, History as HistoryIcon, Camera, PlusCircle } from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('dashboard');
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);

  // Load from local storage on mount
  useEffect(() => {
    const saved = localStorage.getItem('audit_records');
    if (saved) {
      try {
        setRecords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse records", e);
      }
    }
  }, []);

  // Save to local storage whenever records change
  useEffect(() => {
    localStorage.setItem('audit_records', JSON.stringify(records));
  }, [records]);

  const handleSaveAudit = (record: AuditRecord) => {
    if (editingRecord) {
      setRecords(prev => prev.map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...prev]);
    }
    setView('dashboard');
  };

  const handleEdit = (record: AuditRecord) => {
    setEditingRecord(record);
    setView('form');
  };

  const handleDelete = (id: string) => {
    if (confirm("¿Está seguro de eliminar este registro?")) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleCancelForm = () => {
    setEditingRecord(null);
    setView('dashboard');
  };

  const renderContent = () => {
    switch (view) {
      case 'form':
        return <AuditForm initialData={editingRecord} onSave={handleSaveAudit} onCancel={handleCancelForm} />;
      case 'dashboard':
        return <Dashboard records={records} />;
      case 'history':
        return <History records={records} onEdit={handleEdit} onDelete={handleDelete} />;
      case 'ai-editor':
        return <AIEditor />;
      default:
        return <Dashboard records={records} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-gray-900 font-sans selection:bg-blue-100 selection:text-blue-900">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-30">
        <div className="max-w-5xl mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-2 rounded-xl shadow-md shadow-blue-200">
              <ClipboardList className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-slate-800 leading-none">AuditCheck <span className="text-blue-600">Pro</span></h1>
              <span className="text-[10px] text-gray-400 font-medium">System Manager</span>
            </div>
          </div>
          <div className="hidden sm:block">
            <div className="flex items-center gap-2 bg-slate-100 px-3 py-1 rounded-full text-xs font-medium text-slate-600">
                <span className="w-2 h-2 rounded-full bg-green-500 animate-pulse"></span>
                Online
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-5xl mx-auto px-4 py-8">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-lg border-t border-gray-200 shadow-[0_-5px_15px_-5px_rgba(0,0,0,0.05)] z-40 pb-safe">
        <div className="max-w-md mx-auto flex justify-around items-center h-16 px-2">

          <NavButton 
            active={view === 'dashboard'} 
            onClick={() => setView('dashboard')}
            icon={<LayoutDashboard className="w-5 h-5" />}
            label="Dashboard"
          />

          <button 
            onClick={() => { setEditingRecord(null); setView('form'); }}
            className="flex flex-col items-center justify-center -mt-8"
          >
            <div className={`p-4 rounded-full shadow-lg transition-transform hover:scale-105 active:scale-95 ${
                view === 'form' 
                ? 'bg-blue-600 text-white shadow-blue-300 ring-4 ring-blue-100' 
                : 'bg-white text-blue-600 border border-gray-100'
            }`}>
              {view === 'form' ? <ClipboardList className="w-6 h-6" /> : <PlusCircle className="w-6 h-6" />}
            </div>
            <span className={`text-[10px] font-medium mt-1 ${view === 'form' ? 'text-blue-600' : 'text-gray-500'}`}>
              Auditar
            </span>
          </button>

           <NavButton 
            active={view === 'ai-editor'} 
            onClick={() => setView('ai-editor')}
            icon={<Camera className="w-5 h-5" />}
            label="IA Editor"
            color="purple"
          />

          <NavButton 
            active={view === 'history'} 
            onClick={() => setView('history')}
            icon={<HistoryIcon className="w-5 h-5" />}
            label="Historial"
          />
        </div>
      </nav>
    </div>
  );
};

interface NavButtonProps {
    active: boolean;
    onClick: () => void;
    icon: React.ReactNode;
    label: string;
    color?: 'blue' | 'purple';
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label, color = 'blue' }) => {
    const activeClass = color === 'purple' ? 'text-purple-600' : 'text-blue-600';

    return (
        <button 
            onClick={onClick}
            className={`flex flex-col items-center justify-center w-16 h-full space-y-1 transition-colors ${
                active ? activeClass : 'text-gray-400 hover:text-gray-600'
            }`}
        >
            <div className={`transition-all duration-300 ${active ? '-translate-y-1' : ''}`}>
                {icon}
            </div>
            <span className={`text-[10px] font-medium transition-opacity ${active ? 'opacity-100' : 'opacity-70'}`}>
                {label}
            </span>
            {active && (
                <span className={`absolute bottom-0 w-8 h-1 rounded-t-full ${
                    color === 'purple' ? 'bg-purple-600' : 'bg-blue-600'
                }`} />
            )}
        </button>
    );
};

