import React from 'react';
import { AuditRecord, Rating } from '../types';
import { QUESTIONS } from '../constants';
import { TrendingDown, TrendingUp, AlertOctagon, CheckCircle2, BarChart3, ArrowLeft } from 'lucide-react';

interface ConsolidatedViewProps {
  records: AuditRecord[];
  onBack: () => void;
}

export const ConsolidatedView: React.FC<ConsolidatedViewProps> = ({ records, onBack }) => {
  // Calculate statistics per question
  const questionStats = QUESTIONS.map(q => {
    let totalPoints = 0;
    let maxPoints = 0;

    records.forEach(record => {
      const answer = record.answers.find(a => a.questionId === q.id);
      if (answer) {
        if (answer.rating === Rating.SI) {
          totalPoints += 1;
          maxPoints += 1;
        } else if (answer.rating === Rating.PARCIAL) {
          totalPoints += 0.5;
          maxPoints += 1;
        } else if (answer.rating === Rating.NO) {
          maxPoints += 1;
        }
        // N/A is ignored
      }
    });

    const percentage = maxPoints === 0 ? 0 : Math.round((totalPoints / maxPoints) * 100);
    return { ...q, percentage, count: maxPoints };
  });

  // Filter out questions with 0 responses to avoid noise, then sort
  const activeQuestions = questionStats.filter(q => q.count > 0);

  const topLowest = [...activeQuestions].sort((a, b) => a.percentage - b.percentage).slice(0, 5);
  const topHighest = [...activeQuestions].sort((a, b) => b.percentage - a.percentage).slice(0, 5);

  return (
    <div className="space-y-6 mb-24 animate-fade-in">
      <div className="flex items-center gap-4 mb-6">
        <button 
          onClick={onBack}
          className="p-2 hover:bg-gray-100 rounded-full transition-colors"
        >
          <ArrowLeft className="w-6 h-6 text-gray-600" />
        </button>
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Análisis Consolidado</h2>
          <p className="text-sm text-gray-500">Desglose de cumplimiento por preguntas críticas y mejores prácticas.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
        {/* Low Compliance Card (Red Zone) */}
        <div className="bg-white rounded-xl shadow-md border border-red-100 overflow-hidden">
          <div className="p-5 border-b border-red-100 bg-red-50/50 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="bg-red-100 p-2 rounded-lg">
                <AlertOctagon className="w-5 h-5 text-red-600" />
              </div>
              <h3 className="font-bold text-gray-800">Atención Inmediata</h3>
            </div>
            <span className="text-xs font-semibold uppercase tracking-wider text-red-600 bg-red-100 px-2 py-1 rounded">Top 5 Bajo</span>
          </div>
          <div className="p-5 space-y-5">
            {topLowest.length > 0 ? (
              topLowest.map((item, idx) => (
                <div key={item.id} className="space-y-1">
                  <div className="flex justify-between text-sm">
                    <span className="font-medium text-gray-700 w-10/12 truncate" title={item.text}>
                      {item.id}. {item.text}
                    </span>
                    <span className="font-bold text-red-600">{item.percentage}%</span>
                  </div>
                  <div className="w-full bg-red-100 rounded-full h-2.5">
                    <div 
                      className="bg-red-500 h-2.5 rounded-full transition-all duration-500" 
                      style={{ width: `${item.percentage}%` }}
                    ></div>
                  </div>
                  <p className="text-xs text-gray-400 text-right">Base: {item.count} respuestas</p>
                </div>
              ))
            ) : (
              <p className="text-center text-gray-400 py-4">No hay datos suficientes.</p>
            )}
          </div>
        </div>

        {/* High Compliance Card (Green Zone) */}
        <div className="bg-white rounded-xl shadow-md border border-green-100 overflow-hidden">
          <div className="p-5 border-b border-green-100 bg-green-50/50 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <div className="bg-green-100 p-2 rounded-lg">
                <CheckCircle2 className="w-5 h-5 text-green-600" />
              </div>
              <h3 className="font-bold text-gray-800">Mejores Prácticas</h3>
            </div>
            <span className="text-xs font-semibold uppercase tracking-wider text-green-600 bg-green-100 px-2 py-1 rounded">Top 5 Alto</span>
          </div>
          <div className="p-5 space-y-5">
            {topHighest.length > 0 ? (
              topHighest.map((item, idx) => (
                <div key={item.id} className="space-y-1">
                  <div className="flex justify-between text-sm">
                    <span className="font-medium text-gray-700 w-10/12 truncate" title={item.text}>
                       {item.id}. {item.text}
                    </span>
                    <span className="font-bold text-green-600">{item.percentage}%</span>
                  </div>
                  <div className="w-full bg-green-100 rounded-full h-2.5">
                    <div 
                      className="bg-green-500 h-2.5 rounded-full transition-all duration-500" 
                      style={{ width: `${item.percentage}%` }}
                    ></div>
                  </div>
                   <p className="text-xs text-gray-400 text-right">Base: {item.count} respuestas</p>
                </div>
              ))
            ) : (
              <p className="text-center text-gray-400 py-4">No hay datos suficientes.</p>
            )}
          </div>
        </div>
      </div>

      <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 flex items-start gap-3">
        <BarChart3 className="w-5 h-5 text-blue-600 mt-0.5" />
        <div>
            <h4 className="font-semibold text-blue-800 text-sm">Resumen Ejecutivo</h4>
