import { AppConfig, Question } from '../types';
import { Plus, Trash2, Save, Settings as SettingsIcon, Users, MapPin, HelpCircle } from 'lucide-react';

interface SettingsViewProps {
  config: AppConfig;
  onUpdateConfig: (newConfig: AppConfig) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({ config, onUpdateConfig }) => {
  const [activeTab, setActiveTab] = useState<'areas' | 'responsables' | 'questions'>('areas');

  // Local state for inputs
  const [newArea, setNewArea] = useState('');
  const [newResponsable, setNewResponsable] = useState('');
  const [newQuestion, setNewQuestion] = useState('');

  const handleAddArea = () => {
    if (newArea.trim()) {
      onUpdateConfig({
        ...config,
        areas: [...config.areas, newArea.trim().toUpperCase()]
      });
      setNewArea('');
    }
  };

  const handleDeleteArea = (area: string) => {
    if (confirm(`¿Eliminar área ${area}?`)) {
      onUpdateConfig({
        ...config,
        areas: config.areas.filter(a => a !== area)
      });
    }
  };

  const handleAddResponsable = () => {
    if (newResponsable.trim()) {
      onUpdateConfig({
        ...config,
        responsables: [...config.responsables, { name: newResponsable.trim().toUpperCase() }]
      });
      setNewResponsable('');
    }
  };

  const handleDeleteResponsable = (name: string) => {
    if (confirm(`¿Eliminar responsable ${name}?`)) {
      onUpdateConfig({
        ...config,
        responsables: config.responsables.filter(r => r.name !== name)
      });
    }
  };

  const handleAddQuestion = () => {
    if (newQuestion.trim()) {
      const nextId = config.questions.length > 0 
        ? Math.max(...config.questions.map(q => q.id)) + 1 
        : 1;

      onUpdateConfig({
        ...config,
        questions: [...config.questions, { id: nextId, text: newQuestion.trim() }]
      });
      setNewQuestion('');
    }
  };

  const handleDeleteQuestion = (id: number) => {
    if (confirm(`¿Eliminar pregunta ID ${id}?`)) {
      onUpdateConfig({
        ...config,
        questions: config.questions.filter(q => q.id !== id)
      });
    }
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 mb-24 overflow-hidden">
      <div className="p-6 border-b border-gray-200 bg-gray-50 flex items-center gap-3">
        <div className="bg-gray-200 p-2 rounded-lg">
            <SettingsIcon className="w-6 h-6 text-gray-700" />
        </div>
        <div>
            <h2 className="text-xl font-bold text-gray-800">Configuración del Sistema</h2>
            <p className="text-sm text-gray-500">Gestione los parámetros globales de la auditoría.</p>
        </div>
      </div>

      <div className="flex border-b border-gray-200">
        <button
          onClick={() => setActiveTab('areas')}
          className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${
            activeTab === 'areas' ? 'border-blue-600 text-blue-600 bg-blue-50/50' : 'border-transparent text-gray-500 hover:text-gray-700'
          }`}
        >
          <MapPin className="w-4 h-4" /> Áreas
        </button>
        <button
          onClick={() => setActiveTab('responsables')}
          className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${
            activeTab === 'responsables' ? 'border-blue-600 text-blue-600 bg-blue-50/50' : 'border-transparent text-gray-500 hover:text-gray-700'
          }`}
        >
          <Users className="w-4 h-4" /> Responsables
        </button>
        <button
          onClick={() => setActiveTab('questions')}
          className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${
            activeTab === 'questions' ? 'border-blue-600 text-blue-600 bg-blue-50/50' : 'border-transparent text-gray-500 hover:text-gray-700'
          }`}
        >
          <HelpCircle className="w-4 h-4" /> Preguntas
        </button>
      </div>

      <div className="p-6">
        {/* AREAS TAB */}
        {activeTab === 'areas' && (
          <div className="space-y-4">
            <div className="flex gap-2">
              <input
                type="text"
                value={newArea}
                onChange={(e) => setNewArea(e.target.value)}
                placeholder="Nombre de nueva área..."
                className="flex-1 border border-gray-300 rounded-lg p-2 focus:ring-blue-500 focus:border-blue-500"
              />
              <button
                onClick={handleAddArea}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2"
              >
                <Plus className="w-4 h-4" /> Agregar
              </button>
            </div>
            <ul className="divide-y divide-gray-100 border rounded-lg overflow-hidden">
              {config.areas.map((area) => (
                <li key={area} className="p-3 hover:bg-gray-50 flex justify-between items-center group">
                  <span className="font-medium text-gray-700">{area}</span>
                  <button onClick={() => handleDeleteArea(area)} className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* RESPONSABLES TAB */}
        {activeTab === 'responsables' && (
          <div className="space-y-4">
            <div className="flex gap-2">
              <input
                type="text"
                value={newResponsable}
                onChange={(e) => setNewResponsable(e.target.value)}
                placeholder="Nombre del responsable..."
                className="flex-1 border border-gray-300 rounded-lg p-2 focus:ring-blue-500 focus:border-blue-500"
              />
              <button
                onClick={handleAddResponsable}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2"
              >
                <Plus className="w-4 h-4" /> Agregar
              </button>
            </div>
            <ul className="divide-y divide-gray-100 border rounded-lg overflow-hidden">
              {config.responsables.map((resp) => (
                <li key={resp.name} className="p-3 hover:bg-gray-50 flex justify-between items-center group">
                  <span className="font-medium text-gray-700">{resp.name}</span>
                  <button onClick={() => handleDeleteResponsable(resp.name)} className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </li>
              ))}
            </ul>
          </div>
        )}

        {/* QUESTIONS TAB */}
        {activeTab === 'questions' && (
          <div className="space-y-4">
            <div className="flex gap-2">
              <input
                type="text"
                value={newQuestion}
                onChange={(e) => setNewQuestion(e.target.value)}
                placeholder="Texto de la nueva pregunta..."
                className="flex-1 border border-gray-300 rounded-lg p-2 focus:ring-blue-500 focus:border-blue-500"
              />
              <button
                onClick={handleAddQuestion}
                className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2"
              >
                <Plus className="w-4 h-4" /> Agregar
              </button>
            </div>
            <ul className="divide-y divide-gray-100 border rounded-lg overflow-hidden">
              {config.questions.map((q) => (
                <li key={q.id} className="p-3 hover:bg-gray-50 flex justify-between items-center group">
                  <div className="flex items-center gap-3">
                    <span className="w-6 h-6 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center text-xs font-bold flex-shrink-0">
                      {q.id}
                    </span>
                    <span className="text-gray-700 text-sm">{q.text}</span>
                  </div>
                  <button onClick={() => handleDeleteQuestion(q.id)} className="text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity flex-shrink-0">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { ActionItem, ActionStatus } from '../types';
import { CheckCircle2, Circle, Clock, AlertCircle, Search, Filter, Save, X } from 'lucide-react';

interface ActionPlanViewProps {
  actions: ActionItem[];
  onUpdateAction: (action: ActionItem) => void;
}

export const ActionPlanView: React.FC<ActionPlanViewProps> = ({ actions, onUpdateAction }) => {
  const [filterStatus, setFilterStatus] = useState<ActionStatus | 'ALL'>('ALL');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingAction, setEditingAction] = useState<ActionItem | null>(null);

  const filteredActions = actions.filter(a => {
    const matchesStatus = filterStatus === 'ALL' || a.status === filterStatus;
    const matchesSearch = 
        a.area.toLowerCase().includes(searchTerm.toLowerCase()) || 
        a.suggestedAction.toLowerCase().includes(searchTerm.toLowerCase()) ||
        a.responsable.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const getStatusIcon = (status: ActionStatus) => {
    switch (status) {
      case 'PENDING': return <AlertCircle className="w-5 h-5 text-red-500" />;
      case 'IN_PROGRESS': return <Clock className="w-5 h-5 text-yellow-500" />;
      case 'CLOSED': return <CheckCircle2 className="w-5 h-5 text-green-500" />;
    }
  };

  const getStatusLabel = (status: ActionStatus) => {
    switch (status) {
      case 'PENDING': return 'Pendiente';
      case 'IN_PROGRESS': return 'En Proceso';
      case 'CLOSED': return 'Cerrado';
    }
  };

  const handleSaveEdit = () => {
    if (editingAction) {
      onUpdateAction(editingAction);
      setEditingAction(null);
    }
  };

  return (
    <div className="space-y-6 mb-24 animate-fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Planes de Acción</h2>
          <p className="text-sm text-gray-500">Gestión de hallazgos y acciones correctivas.</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-2">
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input 
                    type="text" 
                    placeholder="Buscar..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-9 pr-4 py-2 border border-gray-300 rounded-lg text-sm w-full sm:w-48 focus:ring-blue-500 focus:border-blue-500"
                />
            </div>
            <select 
                value={filterStatus}
                onChange={(e) => setFilterStatus(e.target.value as any)}
                className="px-4 py-2 border border-gray-300 rounded-lg text-sm bg-white focus:ring-blue-500 focus:border-blue-500"
            >
                <option value="ALL">Todos los estados</option>
                <option value="PENDING">Pendientes</option>
                <option value="IN_PROGRESS">En Proceso</option>
                <option value="CLOSED">Cerrados</option>
            </select>
        </div>
      </div>

      {/* Action Stats */}
      <div className="grid grid-cols-3 gap-4">
        <div className="bg-red-50 border border-red-100 p-4 rounded-xl text-center">
            <div className="text-2xl font-bold text-red-600">{actions.filter(a => a.status === 'PENDING').length}</div>
            <div className="text-xs font-medium text-red-800 uppercase tracking-wide">Pendientes</div>
        </div>
        <div className="bg-yellow-50 border border-yellow-100 p-4 rounded-xl text-center">
            <div className="text-2xl font-bold text-yellow-600">{actions.filter(a => a.status === 'IN_PROGRESS').length}</div>
            <div className="text-xs font-medium text-yellow-800 uppercase tracking-wide">En Proceso</div>
        </div>
        <div className="bg-green-50 border border-green-100 p-4 rounded-xl text-center">
            <div className="text-2xl font-bold text-green-600">{actions.filter(a => a.status === 'CLOSED').length}</div>
            <div className="text-xs font-medium text-green-800 uppercase tracking-wide">Cerrados</div>
        </div>
      </div>

      {/* List */}
      <div className="space-y-4">
        {filteredActions.length === 0 ? (
            <div className="text-center py-10 bg-white rounded-xl border border-gray-200">
                <p className="text-gray-400">No se encontraron acciones.</p>
            </div>
        ) : (
            filteredActions.map(action => (
                <div key={action.id} className="bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden hover:shadow-md transition-shadow">
                    {editingAction?.id === action.id ? (
                        // EDIT MODE
                        <div className="p-4 space-y-4 bg-blue-50">
                            <div className="flex justify-between items-center">
                                <h3 className="font-bold text-blue-900">Editando Acción</h3>
                                <button onClick={() => setEditingAction(null)} className="text-gray-500 hover:text-gray-700">
                                    <X className="w-5 h-5" />
                                </button>
                            </div>

                            <div className="space-y-2">
                                <label className="text-xs font-semibold text-gray-500">Acción Correctiva Sugerida</label>
                                <textarea 
                                    value={editingAction.suggestedAction}
                                    onChange={(e) => setEditingAction({...editingAction, suggestedAction: e.target.value})}
                                    className="w-full p-2 border border-blue-200 rounded-md text-sm"
                                    rows={2}
                                />
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <label className="text-xs font-semibold text-gray-500">Responsable</label>
                                    <input 
                                        type="text" 
                                        value={editingAction.responsable}
                                        onChange={(e) => setEditingAction({...editingAction, responsable: e.target.value})}
                                        className="w-full p-2 border border-blue-200 rounded-md text-sm"
                                    />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-xs font-semibold text-gray-500">Fecha Compromiso</label>
                                    <input 
                                        type="date" 
                                        value={editingAction.dueDate.split('T')[0]}
                                        onChange={(e) => setEditingAction({...editingAction, dueDate: new Date(e.target.value).toISOString()})}
                                        className="w-full p-2 border border-blue-200 rounded-md text-sm"
                                    />
                                </div>
                            </div>

                            <div className="space-y-1">
                                <label className="text-xs font-semibold text-gray-500">Comentarios</label>
                                <textarea 
                                    value={editingAction.comments || ''}
                                    onChange={(e) => setEditingAction({...editingAction, comments: e.target.value})}
                                    placeholder="Agregar notas de seguimiento..."
                                    className="w-full p-2 border border-blue-200 rounded-md text-sm"
                                    rows={2}
                                />
                            </div>

                             <div className="space-y-1">
                                <label className="text-xs font-semibold text-gray-500">Estado</label>
                                <div className="flex gap-2">
                                    {(['PENDING', 'IN_PROGRESS', 'CLOSED'] as ActionStatus[]).map(s => (
                                        <button
                                            key={s}
                                            onClick={() => setEditingAction({...editingAction, status: s})}
                                            className={`px-3 py-1 rounded-full text-xs font-bold border transition-colors ${
                                                editingAction.status === s 
                                                ? (s === 'CLOSED' ? 'bg-green-600 text-white' : s === 'IN_PROGRESS' ? 'bg-yellow-500 text-white' : 'bg-red-500 text-white')
                                                : 'bg-white text-gray-500 border-gray-300'
                                            }`}
                                        >
                                            {getStatusLabel(s)}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            <button 
                                onClick={handleSaveEdit}
                                className="w-full bg-blue-600 text-white py-2 rounded-lg font-medium hover:bg-blue-700 flex items-center justify-center gap-2"
                            >
                                <Save className="w-4 h-4" /> Guardar Cambios
                            </button>
                        </div>
                    ) : (
                        // VIEW MODE
                        <div className="p-4 flex flex-col md:flex-row gap-4">
                            <div className="flex-1 space-y-2">
                                <div className="flex items-start justify-between">
                                    <div className="flex items-center gap-2">
                                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wide ${
                                            action.status === 'PENDING' ? 'bg-red-100 text-red-700' :
                                            action.status === 'IN_PROGRESS' ? 'bg-yellow-100 text-yellow-700' :
                                            'bg-green-100 text-green-700'
                                        }`}>
                                            {getStatusLabel(action.status)}
                                        </span>
                                        <span className="text-xs text-gray-400">
                                            {new Date(action.createdAt).toLocaleDateString()}
                                        </span>
                                    </div>
                                    <div className="text-xs font-bold text-gray-500">{action.area}</div>
                                </div>

                                <div>
                                    <p className="text-sm text-gray-900 font-medium mb-1">
                                        <span className="text-red-500 font-bold mr-1">Hallazgo:</span> 
                                        {action.questionText}
                                    </p>
                                    <p className="text-sm text-gray-600 bg-gray-50 p-2 rounded border border-gray-100">
                                        <span className="font-semibold text-gray-700">Acción:</span> {action.suggestedAction}
                                    </p>
                                </div>

                                <div className="flex flex-wrap gap-4 text-xs text-gray-500 pt-1">
                                    <span className="flex items-center gap-1">
                                        <Users className="w-3 h-3" /> {action.responsable}
                                    </span>
                                    <span className="flex items-center gap-1">
                                        <Clock className="w-3 h-3" /> Vence: {new Date(action.dueDate).toLocaleDateString()}
                                    </span>
                                </div>
                                {action.comments && (
                                    <div className="text-xs text-gray-500 italic border-l-2 border-blue-200 pl-2 mt-2">
                                        "{action.comments}"
                                    </div>
                                )}
                            </div>

                            <div className="flex md:flex-col justify-center border-t md:border-t-0 md:border-l border-gray-100 pt-3 md:pt-0 md:pl-4">
                                <button 
                                    onClick={() => setEditingAction(action)}
                                    className="text-blue-600 hover:text-blue-800 font-medium text-sm"
                                >
                                    Gestionar
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Rating, Answer, AuditRecord, AppConfig, ActionItem } from '../types';
import { Save, User, MapPin, ClipboardCheck, AlertCircle, UserCircle } from 'lucide-react';

interface AuditFormProps {
  initialData?: AuditRecord | null;
  config: AppConfig;
  onSave: (record: AuditRecord, newActions: ActionItem[]) => void;
  onCancel: () => void;
}

export const AuditForm: React.FC<AuditFormProps> = ({ initialData, config, onSave, onCancel }) => {
  const [area, setArea] = useState(config.areas[0] || '');
  const [auditor, setAuditor] = useState('');
  const [responsable, setResponsable] = useState('');
  const [answers, setAnswers] = useState<Record<number, Rating>>({});

  // Initialize data for editing or new form
  useEffect(() => {
    if (initialData) {
      setArea(initialData.area);
      setAuditor(initialData.auditor);
      setResponsable(initialData.responsable || getResponsableForArea(initialData.area));
      const loadedAnswers: Record<number, Rating> = {};
      initialData.answers.forEach(a => {
        loadedAnswers[a.questionId] = a.rating;
      });
      setAnswers(loadedAnswers);
    } else {
      if (config.areas.length > 0) {
        const defaultArea = config.areas[0];
        setArea(defaultArea);
        setResponsable(getResponsableForArea(defaultArea));
      }
    }
  }, [initialData, config]);

  // Update responsable when area changes
  useEffect(() => {
    if (!initialData || (initialData && area !== initialData.area)) {
       setResponsable(getResponsableForArea(area));
    }
  }, [area, initialData]);

  const getResponsableForArea = (areaName: string) => {
    const found = config.responsables.find(r => r.area === areaName);
    return found ? found.name : (config.responsables[0]?.name || '');
  };

  const handleRatingChange = (questionId: number, rating: Rating) => {
    setAnswers(prev => ({ ...prev, [questionId]: rating }));
  };

  const calculateScore = () => {
    let totalPoints = 0;
    let maxPoints = 0;

    Object.values(answers).forEach(rating => {
      if (rating === Rating.SI) {
        totalPoints += 1;
        maxPoints += 1;
      } else if (rating === Rating.PARCIAL) {
        totalPoints += 0.5;
        maxPoints += 1;
      } else if (rating === Rating.NO) {
        maxPoints += 1;
      }
      // N/A does not contribute to maxPoints
    });

    return maxPoints === 0 ? 0 : Math.round((totalPoints / maxPoints) * 100);
  };

  const currentScore = calculateScore();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!auditor.trim()) {
      alert("Por favor ingrese el nombre del auditor");
      return;
    }

    const answerList: Answer[] = Object.entries(answers).map(([qId, rating]) => ({
      questionId: parseInt(qId),
      rating: rating as Rating
    }));

    if (answerList.length !== config.questions.length) {
      if(!confirm("No ha respondido todas las preguntas. ¿Desea guardar de todos modos?")) {
        return;
      }
    }

    const newId = initialData ? initialData.id : crypto.randomUUID();
    const date = initialData ? initialData.date : new Date().toISOString();

    const record: AuditRecord = {
      id: newId,
      area,
      auditor,
      responsable,
      date,
      answers: answerList,
      score: currentScore,
    };

    // Generate Action Items
    const newActions: ActionItem[] = [];
    if (!initialData) { // Only generate actions for new audits to avoid duplicates on edit
        answerList.forEach(ans => {
            if (ans.rating === Rating.NO || ans.rating === Rating.PARCIAL) {
                const q = config.questions.find(q => q.id === ans.questionId);
                if (q) {
                    const dueDate = new Date();
                    dueDate.setDate(dueDate.getDate() + 7); // Default 7 days

                    newActions.push({
                        id: crypto.randomUUID(),
                        auditId: newId,
                        area: area,
                        questionId: q.id,
                        questionText: q.text,
                        issueType: ans.rating === Rating.NO ? 'NO' : 'PARCIAL',
                        suggestedAction: `Corregir hallazgo: "${q.text}"`,
                        responsable: responsable,
                        dueDate: dueDate.toISOString(),
                        status: 'PENDING',
                        createdAt: new Date().toISOString()
                    });
                }
            }
        });
    }

    onSave(record, newActions);
  };

  const getRatingColorClass = (rating: Rating, isSelected: boolean) => {
    if (!isSelected) return 'bg-white border-gray-200 text-gray-500 hover:bg-gray-50';
    switch (rating) {
      case Rating.SI: return 'bg-green-600 border-green-600 text-white shadow-md shadow-green-200';
      case Rating.NO: return 'bg-red-600 border-red-600 text-white shadow-md shadow-red-200';
      case Rating.PARCIAL: return 'bg-yellow-500 border-yellow-500 text-white shadow-md shadow-yellow-200';
      case Rating.NA: return 'bg-gray-600 border-gray-600 text-white';
      default: return '';
    }
  };

  return (
    <div className="max-w-4xl mx-auto mb-24 animate-fade-in">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-2xl font-bold text-gray-800">
          {initialData ? 'Editar Auditoría' : 'Nueva Auditoría'}
        </h2>
        <div className={`px-4 py-2 rounded-lg font-bold text-lg border ${
            currentScore >= 90 ? 'bg-green-50 text-green-700 border-green-200' :
            currentScore >= 70 ? 'bg-yellow-50 text-yellow-700 border-yellow-200' :
            'bg-red-50 text-red-700 border-red-200'
        }`}>
            {currentScore}% pts
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">

        {/* Info Card */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
          <h3 className="text-sm font-semibold text-gray-500 uppercase tracking-wider mb-4 border-b pb-2 flex items-center gap-2">
