import React from 'react';
import { AuditRecord, ActionItem } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, Cell } from 'recharts';
import { Trophy, TrendingUp, AlertTriangle, CheckCircle, PieChart, ClipboardList } from 'lucide-react';

interface DashboardProps {
  records: AuditRecord[];
  actions: ActionItem[];
  onViewConsolidated: () => void;
  onViewActions: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ records, actions, onViewConsolidated, onViewActions }) => {
  // Aggregate average score by Area
  const areaStats: Record<string, { totalScore: number; count: number }> = {};

  records.forEach(r => {
    if (!areaStats[r.area]) {
      areaStats[r.area] = { totalScore: 0, count: 0 };
    }
    areaStats[r.area].totalScore += r.score;
    areaStats[r.area].count += 1;
  });

  const chartData = Object.entries(areaStats)
    .map(([area, stats]) => ({
      name: area,
      score: Math.round(stats.totalScore / stats.count),
      audits: stats.count
    }))
    .sort((a, b) => b.score - a.score); // Sort by score descending

  // Color logic
  const getScoreColor = (score: number) => {
    if (score >= 90) return 'text-green-600 bg-green-50 border-green-200';
    if (score >= 70) return 'text-yellow-600 bg-yellow-50 border-yellow-200';
    return 'text-red-600 bg-red-50 border-red-200';
  };

  const getBarColor = (score: number) => {
    if (score >= 90) return '#22c55e';
    if (score >= 70) return '#eab308';
    return '#ef4444';
  };

  const averageScore = records.length > 0
    ? Math.round(records.reduce((acc, r) => acc + r.score, 0) / records.length)
    : 0;

  const openActions = actions.filter(a => a.status !== 'CLOSED').length;
  const closedActions = actions.filter(a => a.status === 'CLOSED').length;

  return (
    <div className="space-y-6 mb-24 animate-fade-in">
      {/* KPI Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between">
            <div className="flex justify-between items-start">
                <p className="text-xs font-bold text-gray-500 uppercase">Auditorías</p>
                <div className="bg-blue-100 p-1.5 rounded-lg">
                    <CheckCircle className="w-4 h-4 text-blue-600" />
                </div>
            </div>
            <p className="text-2xl font-bold text-gray-800 mt-2">{records.length}</p>
        </div>

        <div className="bg-white p-4 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between">
             <div className="flex justify-between items-start">
                <p className="text-xs font-bold text-gray-500 uppercase">Promedio</p>
                <div className={`${averageScore >= 90 ? 'bg-green-100' : 'bg-yellow-100'} p-1.5 rounded-lg`}>
                    <TrendingUp className={`w-4 h-4 ${averageScore >= 90 ? 'text-green-600' : 'text-yellow-600'}`} />
                </div>
            </div>
            <p className={`text-2xl font-bold mt-2 ${averageScore >= 90 ? 'text-green-600' : averageScore >= 70 ? 'text-yellow-600' : 'text-red-600'}`}>
              {averageScore}%
            </p>
        </div>

        <div 
            onClick={onViewActions}
            className="bg-white p-4 rounded-xl shadow-sm border border-red-100 flex flex-col justify-between cursor-pointer hover:shadow-md transition-all"
        >
            <div className="flex justify-between items-start">
                <p className="text-xs font-bold text-red-500 uppercase">Acciones Abiertas</p>
                <div className="bg-red-100 p-1.5 rounded-lg">
                    <AlertTriangle className="w-4 h-4 text-red-600" />
                </div>
            </div>
            <p className="text-2xl font-bold text-gray-800 mt-2">{openActions}</p>
            <p className="text-[10px] text-gray-400">Click para gestionar</p>
        </div>

        <div className="bg-white p-4 rounded-xl shadow-sm border border-green-100 flex flex-col justify-between">
             <div className="flex justify-between items-start">
                <p className="text-xs font-bold text-green-500 uppercase">Cerradas</p>
                <div className="bg-green-100 p-1.5 rounded-lg">
                    <CheckCircle className="w-4 h-4 text-green-600" />
                </div>
            </div>
             <p className="text-2xl font-bold text-gray-800 mt-2">{closedActions}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Action Button for Analysis */}
        <button 
            onClick={onViewConsolidated}
            className="w-full py-4 px-6 bg-orange-500 hover:bg-orange-600 text-white rounded-xl shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-3 font-bold text-lg"
        >
            <PieChart className="w-6 h-6" />
            Análisis Consolidado
        </button>

        {/* Action Button for Plans */}
        <button 
            onClick={onViewActions}
            className="w-full py-4 px-6 bg-blue-600 hover:bg-blue-700 text-white rounded-xl shadow-md hover:shadow-lg transition-all flex items-center justify-center gap-3 font-bold text-lg"
        >
            <ClipboardList className="w-6 h-6" />
            Ver Planes de Acción
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Ranking List */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
          <div className="p-5 border-b border-gray-100 flex items-center gap-2">
            <Trophy className="w-5 h-5 text-yellow-500" />
            <h3 className="text-lg font-bold text-gray-800">Ranking de Cumplimiento</h3>
          </div>
          <div className="p-0">
            {chartData.length > 0 ? (
              <div className="divide-y divide-gray-50">
                {chartData.map((item, index) => (
                  <div key={item.name} className="p-4 flex items-center justify-between hover:bg-gray-50 transition-colors">
                    <div className="flex items-center gap-4">
                      <div className={`w-8 h-8 flex items-center justify-center rounded-full font-bold text-sm ${
                        index === 0 ? 'bg-yellow-100 text-yellow-700' : 
                        index === 1 ? 'bg-gray-200 text-gray-700' : 
                        index === 2 ? 'bg-orange-100 text-orange-800' : 'bg-gray-50 text-gray-500'
                      }`}>
                        {index + 1}
                      </div>
                      <div>
                        <p className="font-medium text-gray-800 text-sm md:text-base">{item.name}</p>
                        <p className="text-xs text-gray-400">{item.audits} auditoría(s)</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-3">
                      <div className="w-24 h-2 bg-gray-100 rounded-full hidden sm:block overflow-hidden">
                        <div 
                          className="h-full rounded-full" 
                          style={{ 
                            width: `${item.score}%`,
                            backgroundColor: getBarColor(item.score) 
                          }} 
                        />
                      </div>
                      <span className={`px-3 py-1 rounded-full text-xs font-bold border ${getScoreColor(item.score)}`}>
                        {item.score}%
                      </span>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <div className="p-8 text-center text-gray-400">Sin datos registrados</div>
            )}
          </div>
        </div>

        {/* Chart */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100 p-5">
          <h3 className="text-lg font-bold text-gray-800 mb-6">Tendencia General</h3>
          <div className="h-80 w-full">
            {chartData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} layout="vertical" margin={{ top: 5, right: 30, left: 40, bottom: 5 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} />
                  <XAxis type="number" domain={[0, 100]} hide />
                  <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 11}} />
                  <Tooltip 
                      contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                      cursor={{fill: '#f8fafc'}}
                  />
                  <Bar dataKey="score" name="Puntaje" radius={[0, 4, 4, 0]} barSize={20}>
                      {chartData.map((entry, index) => (
                          <Cell key={`cell-${index}`} fill={getBarColor(entry.score)} />
                      ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="flex items-center justify-center h-full text-gray-400">
                Gráfico vacío
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ViewState, AuditRecord, ActionItem, AppConfig } from './types';
import { QUESTIONS, AREA_MAPPING, AREAS } from './constants';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ConsolidatedView } from './components/ConsolidatedView';
import { ActionPlanView } from './components/ActionPlanView';
import { SettingsView } from './components/SettingsView';
import { ClipboardList, LayoutDashboard, History as HistoryIcon, Camera, PlusCircle, PieChart, Settings, ListTodo } from 'lucide-react';

// Initial default config based on constants
const DEFAULT_CONFIG: AppConfig = {
  questions: QUESTIONS,
  areas: AREAS,
  responsables: AREA_MAPPING.map(am => ({ name: am.responsable, area: am.area }))
};

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('dashboard');

  // State
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [actions, setActions] = useState<ActionItem[]>([]);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);

  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);

  // Load from local storage on mount
  useEffect(() => {
    const savedRecords = localStorage.getItem('audit_records');
    const savedActions = localStorage.getItem('audit_actions');
    const savedConfig = localStorage.getItem('audit_config');

    if (savedRecords) {
      try { setRecords(JSON.parse(savedRecords)); } catch (e) { console.error(e); }
    }
    if (savedActions) {
      try { setActions(JSON.parse(savedActions)); } catch (e) { console.error(e); }
    }
    if (savedConfig) {
      try { setConfig(JSON.parse(savedConfig)); } catch (e) { console.error(e); }
    }
  }, []);

  // Save to local storage whenever state changes
  useEffect(() => {
    localStorage.setItem('audit_records', JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem('audit_actions', JSON.stringify(actions));
  }, [actions]);

  useEffect(() => {
    localStorage.setItem('audit_config', JSON.stringify(config));
  }, [config]);

  const handleSaveAudit = (record: AuditRecord, newActions: ActionItem[]) => {
    if (editingRecord) {
      setRecords(prev => prev.map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...prev]);
      // Add generated actions
      setActions(prev => [...newActions, ...prev]);
      if (newActions.length > 0) {
        alert(`Se han generado ${newActions.length} acciones correctivas automáticamente.`);
      }
    }
    setView('dashboard');
  };

  const handleUpdateAction = (updatedAction: ActionItem) => {
    setActions(prev => prev.map(a => a.id === updatedAction.id ? updatedAction : a));
  };

  const handleUpdateConfig = (newConfig: AppConfig) => {
    setConfig(newConfig);
  };

  const handleEdit = (record: AuditRecord) => {
    setEditingRecord(record);
    setView('form');
  };

  const handleDelete = (id: string) => {
    if (confirm("¿Está seguro de eliminar este registro? Esto NO eliminará las acciones generadas.")) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleCancelForm = () => {
    setEditingRecord(null);
    setView('dashboard');
  };

  const renderContent = () => {
    switch (view) {
      case 'form':
        return <AuditForm initialData={editingRecord} config={config} onSave={handleSaveAudit} onCancel={handleCancelForm} />;
      case 'dashboard':
        return <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} />;
      case 'history':
        return <History records={records} actions={actions} onEdit={handleEdit} onDelete={handleDelete} />;
      case 'ai-editor':
        return <AIEditor />;
      case 'consolidated':
        return <ConsolidatedView records={records} onBack={() => setView('dashboard')} />;
      case 'actions':
        return <ActionPlanView actions={actions} onUpdateAction={handleUpdateAction} />;
      case 'settings':
        return <SettingsView config={config} onUpdateConfig={handleUpdateConfig} />;
      default:
        return <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-gray-900 font-sans selection:bg-blue-100 selection:text-blue-900">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-30">
        <div className="max-w-6xl mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-2 rounded-xl shadow-md shadow-blue-200">
              <ClipboardList className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-slate-800 leading-none">Sistema Auditoría <span className="text-blue-600">5S</span></h1>
              <span className="text-[10px] text-gray-400 font-medium">Gestión Operativa</span>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
                onClick={() => setView('settings')}
                className={`p-2 rounded-lg transition-colors ${view === 'settings' ? 'bg-gray-100 text-gray-800' : 'text-gray-500 hover:bg-gray-50'}`}
                title="Configuración"
            >
                <Settings className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 py-8">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-lg border-t border-gray-200 shadow-[0_-5px_15px_-5px_rgba(0,0,0,0.05)] z-40 pb-safe">
        <div className="max-w-lg mx-auto flex justify-around items-center h-16 px-2">

          <NavButton 
            active={view === 'dashboard' || view === 'consolidated'} 
            onClick={() => setView('dashboard')}
            icon={<LayoutDashboard className="w-5 h-5" />}
            label="Inicio"
          />

          <NavButton 
            active={view === 'history'} 
            onClick={() => setView('history')}
            icon={<HistoryIcon className="w-5 h-5" />}
            label="Auditorías"
          />

          <button 
            onClick={() => { setEditingRecord(null); setView('form'); }}
            className="flex flex-col items-center justify-center -mt-8"
          >
            <div className={`p-4 rounded-full shadow-lg transition-transform hover:scale-105 active:scale-95 ${
                view === 'form' 
                ? 'bg-blue-600 text-white shadow-blue-300 ring-4 ring-blue-100' 
                : 'bg-white text-blue-600 border border-gray-100'
            }`}>
              {view === 'form' ? <ClipboardList className="w-6 h-6" /> : <PlusCircle className="w-6 h-6" />}
            </div>
            <span className={`text-[10px] font-medium mt-1 ${view === 'form' ? 'text-blue-600' : 'text-gray-500'}`}>
              Nuevo
            </span>
          </button>

           <NavButton 
            active={view === 'actions'} 
            onClick={() => setView('actions')}
            icon={<ListTodo className="w-5 h-5" />}
            label="Acciones"
            color="orange"
          />

           <NavButton 
            active={view === 'ai-editor'} 
            onClick={() => setView('ai-editor')}
            icon={<Camera className="w-5 h-5" />}
            label="IA Cam"
            color="purple"
          />
        </div>
      </nav>
    </div>
  );
};

interface NavButtonProps {
    active: boolean;
    onClick: () => void;
    icon: React.ReactNode;
    label: string;
    color?: 'blue' | 'purple' | 'orange';
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label, color = 'blue' }) => {
    let activeClass = 'text-blue-600';
    let bgClass = 'bg-blue-600';

    if (color === 'purple') { activeClass = 'text-purple-600'; bgClass = 'bg-purple-600'; }
    if (color === 'orange') { activeClass = 'text-orange-500'; bgClass = 'bg-orange-500'; }

    return (
        <button 
            onClick={onClick}
            className={`flex flex-col items-center justify-center w-16 h-full space-y-1 transition-colors ${
                active ? activeClass : 'text-gray-400 hover:text-gray-600'
            }`}
        >
            <div className={`transition-all duration-300 ${active ? '-translate-y-1' : ''}`}>
                {icon}
            </div>
            <span className={`text-[10px] font-medium transition-opacity ${active ? 'opacity-100' : 'opacity-70'}`}>
                {label}
            </span>
            {active && (
                <span className={`absolute bottom-0 w-8 h-1 rounded-t-full ${bgClass}`} />
            )}
        </button>
    );
};

