import React, { useState, useEffect } from 'react';
import { ViewState, AuditRecord, ActionItem, AppConfig } from './types';
import { QUESTIONS, AREA_MAPPING, AREAS } from './constants';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ConsolidatedView } from './components/ConsolidatedView';
import { ActionPlanView } from './components/ActionPlanView';
import { SettingsView } from './components/SettingsView';
import { ClipboardList, LayoutDashboard, History as HistoryIcon, Camera, PlusCircle, PieChart, Settings, ListTodo } from 'lucide-react';

// Initial default config based on constants
const DEFAULT_CONFIG: AppConfig = {
  questions: QUESTIONS,
  areas: AREAS,
  responsables: AREA_MAPPING.map(am => ({ name: am.responsable, area: am.area }))
};

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('dashboard');

  // State
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [actions, setActions] = useState<ActionItem[]>([]);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);

  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);

  // Load from local storage on mount
  useEffect(() => {
    const savedRecords = localStorage.getItem('audit_records');
    const savedActions = localStorage.getItem('audit_actions');
    const savedConfig = localStorage.getItem('audit_config');

    if (savedRecords) {
      try { setRecords(JSON.parse(savedRecords)); } catch (e) { console.error(e); }
    }
    if (savedActions) {
      try { setActions(JSON.parse(savedActions)); } catch (e) { console.error(e); }
    }
    if (savedConfig) {
      try { 
        const parsedConfig = JSON.parse(savedConfig);

        // Merge new questions from constants if they don't exist in saved config
        // This ensures updates to the app code are reflected in the user's config
        // while preserving their custom questions if any.
        const existingIds = new Set(parsedConfig.questions.map((q: any) => q.id));
        const questionsToAdd = QUESTIONS.filter(q => !existingIds.has(q.id));

        if (questionsToAdd.length > 0) {
            parsedConfig.questions = [...parsedConfig.questions, ...questionsToAdd];
        }

        setConfig(parsedConfig); 
      } catch (e) { console.error(e); }
    }
  }, []);

  // Save to local storage whenever state changes
  useEffect(() => {
    localStorage.setItem('audit_records', JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem('audit_actions', JSON.stringify(actions));
  }, [actions]);

  useEffect(() => {
    localStorage.setItem('audit_config', JSON.stringify(config));
  }, [config]);

  const handleSaveAudit = (record: AuditRecord, newActions: ActionItem[]) => {
    if (editingRecord) {
      setRecords(prev => prev.map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...prev]);
      // Add generated actions
      setActions(prev => [...newActions, ...prev]);
      if (newActions.length > 0) {
        alert(`Se han generado ${newActions.length} acciones correctivas automáticamente.`);
      }
    }
    setView('dashboard');
  };

  const handleUpdateAction = (updatedAction: ActionItem) => {
    setActions(prev => prev.map(a => a.id === updatedAction.id ? updatedAction : a));
  };

  const handleUpdateConfig = (newConfig: AppConfig) => {
    setConfig(newConfig);
  };

  const handleEdit = (record: AuditRecord) => {
    setEditingRecord(record);
    setView('form');
  };

  const handleDelete = (id: string) => {
    if (confirm("¿Está seguro de eliminar este registro? Esto NO eliminará las acciones generadas.")) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleCancelForm = () => {
    setEditingRecord(null);
    setView('dashboard');
  };

  const renderContent = () => {
    switch (view) {
      case 'form':
        return <AuditForm initialData={editingRecord} config={config} onSave={handleSaveAudit} onCancel={handleCancelForm} />;
      case 'dashboard':
        return <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} />;
      case 'history':
        return <History records={records} actions={actions} onEdit={handleEdit} onDelete={handleDelete} />;
      case 'ai-editor':
        return <AIEditor />;
      case 'consolidated':
        return <ConsolidatedView records={records} onBack={() => setView('dashboard')} />;
      case 'actions':
        return <ActionPlanView actions={actions} onUpdateAction={handleUpdateAction} />;
      case 'settings':
        return <SettingsView config={config} onUpdateConfig={handleUpdateConfig} />;
      default:
        return <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} />;
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 text-gray-900 font-sans selection:bg-blue-100 selection:text-blue-900">
      {/* Header */}
      <header className="bg-white border-b border-gray-200 sticky top-0 z-30">
        <div className="max-w-6xl mx-auto px-4 py-3 flex justify-between items-center">
          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-br from-blue-600 to-indigo-700 p-2 rounded-xl shadow-md shadow-blue-200">
              <ClipboardList className="w-5 h-5 text-white" />
            </div>
            <div>
              <h1 className="text-xl font-bold tracking-tight text-slate-800 leading-none">Sistema Auditoría <span className="text-blue-600">5S</span></h1>
              <span className="text-[10px] text-gray-400 font-medium">Gestión Operativa</span>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button
                onClick={() => setView('settings')}
                className={`p-2 rounded-lg transition-colors ${view === 'settings' ? 'bg-gray-100 text-gray-800' : 'text-gray-500 hover:bg-gray-50'}`}
                title="Configuración"
            >
                <Settings className="w-5 h-5" />
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-6xl mx-auto px-4 py-8">
        {renderContent()}
      </main>

      {/* Bottom Navigation */}
      <nav className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-lg border-t border-gray-200 shadow-[0_-5px_15px_-5px_rgba(0,0,0,0.05)] z-40 pb-safe">
        <div className="max-w-lg mx-auto flex justify-around items-center h-16 px-2">

          <NavButton 
            active={view === 'dashboard' || view === 'consolidated'} 
            onClick={() => setView('dashboard')}
            icon={<LayoutDashboard className="w-5 h-5" />}
            label="Inicio"
          />

          <NavButton 
            active={view === 'history'} 
            onClick={() => setView('history')}
            icon={<HistoryIcon className="w-5 h-5" />}
            label="Auditorías"
          />

          <button 
            onClick={() => { setEditingRecord(null); setView('form'); }}
            className="flex flex-col items-center justify-center -mt-8"
          >
            <div className={`p-4 rounded-full shadow-lg transition-transform hover:scale-105 active:scale-95 ${
                view === 'form' 
                ? 'bg-blue-600 text-white shadow-blue-300 ring-4 ring-blue-100' 
                : 'bg-white text-blue-600 border border-gray-100'
            }`}>
              {view === 'form' ? <ClipboardList className="w-6 h-6" /> : <PlusCircle className="w-6 h-6" />}
            </div>
            <span className={`text-[10px] font-medium mt-1 ${view === 'form' ? 'text-blue-600' : 'text-gray-500'}`}>
              Nuevo
            </span>
          </button>

           <NavButton 
            active={view === 'actions'} 
            onClick={() => setView('actions')}
            icon={<ListTodo className="w-5 h-5" />}
            label="Acciones"
            color="orange"
          />

           <NavButton 
            active={view === 'ai-editor'} 
            onClick={() => setView('ai-editor')}
            icon={<Camera className="w-5 h-5" />}
            label="IA Cam"
            color="purple"
          />
        </div>
      </nav>
    </div>
  );
};

interface NavButtonProps {
    active: boolean;
    onClick: () => void;
    icon: React.ReactNode;
    label: string;
    color?: 'blue' | 'purple' | 'orange';
}

const NavButton: React.FC<NavButtonProps> = ({ active, onClick, icon, label, color = 'blue' }) => {
    let activeClass = 'text-blue-600';
    let bgClass = 'bg-blue-600';

    if (color === 'purple') { activeClass = 'text-purple-600'; bgClass = 'bg-purple-600'; }
    if (color === 'orange') { activeClass = 'text-orange-500'; bgClass = 'bg-orange-500'; }

    return (
        <button 
            onClick={onClick}
            className={`flex flex-col items-center justify-center w-16 h-full space-y-1 transition-colors ${
                active ? activeClass : 'text-gray-400 hover:text-gray-600'
            }`}
        >
            <div className={`transition-all duration-300 ${active ? '-translate-y-1' : ''}`}>
                {icon}
            </div>
            <span className={`text-[10px] font-medium transition-opacity ${active ? 'opacity-100' : 'opacity-70'}`}>
                {label}
            </span>
            {active && (
                <span className={`absolute bottom-0 w-8 h-1 rounded-t-full ${bgClass}`} />
            )}
        </button>
    );
};

