                <div className={`${averageScore >= 90 ? 'bg-green-100' : 'bg-yellow-100'} p-1.5 rounded-lg`}>
                    <TrendingUp className={`w-4 h-4 ${averageScore >= 90 ? 'text-green-600' : 'text-yellow-600'}`} />
                </div>
            </div>
            <p className={`text-2xl font-bold mt-2 ${averageScore >= 90 ? 'text-green-600' : averageScore >= 70 ? 'text-yellow-600' : 'text-red-600'}`}>
              {averageScore}%
            </p>
        </div>

        <div 
            onClick={onViewActions}
            className="bg-white p-4 rounded-xl shadow-sm border border-red-100 flex flex-col justify-between cursor-pointer hover:shadow-md transition-all"
        >
            <div className="flex justify-between items-start">
                <p className="text-xs font-bold text-red-500 uppercase">Acciones Abiertas</p>
                <div className="bg-red-100 p-1.5 rounded-lg">
                    <AlertTriangle className="w-4 h-4 text-red-600" />
                </div>
            </div>
            <p className="text-2xl font-bold text-gray-800 mt-2">{openActions}</p>
