import React from 'react';
import { AuditRecord, Rating } from '../types';
import { QUESTIONS } from '../constants';
import { TrendingDown, TrendingUp, AlertOctagon, CheckCircle2, BarChart3, ArrowLeft, MapPin } from 'lucide-react';

interface ConsolidatedViewProps {
  records: AuditRecord[];
  onBack: () => void;
}

export const ConsolidatedView: React.FC<ConsolidatedViewProps> = ({ records, onBack }) => {
  // --- QUESTION STATISTICS ---
  const questionStats = QUESTIONS.map(q => {
    let totalPoints = 0;
    let maxPoints = 0;

    records.forEach(record => {
      const answer = record.answers.find(a => a.questionId === q.id);
      if (answer) {
        if (answer.rating === Rating.SI) {
          totalPoints += 1;
          maxPoints += 1;
        } else if (answer.rating === Rating.PARCIAL) {
          totalPoints += 0.5;
          maxPoints += 1;
        } else if (answer.rating === Rating.NO) {
          maxPoints += 1;
        }
        // N/A is ignored
      }
    });

    const percentage = maxPoints === 0 ? 0 : Math.round((totalPoints / maxPoints) * 100);
    return { ...q, percentage, count: maxPoints };
  });

  const activeQuestions = questionStats.filter(q => q.count > 0);
  const topLowestQuestions = [...activeQuestions].sort((a, b) => a.percentage - b.percentage).slice(0, 5);
  const topHighestQuestions = [...activeQuestions].sort((a, b) => b.percentage - a.percentage).slice(0, 5);

  // --- AREA STATISTICS ---
  const areaMap: Record<string, { totalScore: number; count: number }> = {};
  records.forEach(r => {
    if (!areaMap[r.area]) {
      areaMap[r.area] = { totalScore: 0, count: 0 };
    }
    areaMap[r.area].totalScore += r.score;
    areaMap[r.area].count += 1;
  });

  const areaStats = Object.entries(areaMap).map(([area, stats]) => ({
    name: area,
    average: Math.round(stats.totalScore / stats.count),
    count: stats.count
  }));

  // Sort by average ascending
  const sortedAreas = [...areaStats].sort((a, b) => a.average - b.average);

  // Split the list in half to ensure mutual exclusivity between "Worst" and "Best" lists
  const midPoint = Math.floor(sortedAreas.length / 2);

  const worstCandidates = sortedAreas.slice(0, midPoint);
  const bestCandidates = sortedAreas.slice(midPoint);

  // Take top 5 from respective halves
  const topLowestAreas = worstCandidates.slice(0, 5);
  // Reverse best candidates so the highest scores appear first
  const topHighestAreas = bestCandidates.reverse().slice(0, 5);

  return (
    <div className="space-y-8 mb-24 animate-fade-in">
      <div className="flex items-center gap-4 mb-6">
        <button 
          onClick={onBack}
          className="p-2 hover:bg-gray-100 rounded-full transition-colors"
        >
          <ArrowLeft className="w-6 h-6 text-gray-600" />
        </button>
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Análisis Consolidado</h2>
          <p className="text-sm text-gray-500">Desglose de cumplimiento por áreas y preguntas críticas.</p>
        </div>
      </div>

      {/* --- SECCION 1: ANÁLISIS POR ÁREAS --- */}
      <div>
        <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
            <MapPin className="w-5 h-5 text-blue-600" /> Rendimiento por Áreas
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Worst Areas */}
            <div className="bg-white rounded-xl shadow-md border border-red-100 overflow-hidden">
            <div className="p-4 border-b border-red-100 bg-red-50/50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                <TrendingDown className="w-5 h-5 text-red-600" />
                <h3 className="font-bold text-gray-800">Áreas Críticas (Top 5 Bajo)</h3>
                </div>
            </div>
            <div className="p-4 space-y-4">
                {topLowestAreas.length > 0 ? (
                topLowestAreas.map((item) => (
                    <div key={item.name} className="space-y-1">
                    <div className="flex justify-between text-sm">
                        <span className="font-medium text-gray-700">{item.name}</span>
                        <span className="font-bold text-red-600">{item.average}%</span>
                    </div>
                    <div className="w-full bg-red-100 rounded-full h-2">
                        <div 
                        className="bg-red-500 h-2 rounded-full transition-all duration-500" 
                        style={{ width: `${item.average}%` }}
                        ></div>
                    </div>
                    </div>
                ))
                ) : <p className="text-gray-400 text-sm">Sin datos suficientes para calcular áreas críticas.</p>}
            </div>
            </div>

            {/* Best Areas */}
            <div className="bg-white rounded-xl shadow-md border border-green-100 overflow-hidden">
            <div className="p-4 border-b border-green-100 bg-green-50/50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                <TrendingUp className="w-5 h-5 text-green-600" />
                <h3 className="font-bold text-gray-800">Áreas Destacadas (Top 5 Alto)</h3>
                </div>
            </div>
            <div className="p-4 space-y-4">
                {topHighestAreas.length > 0 ? (
                topHighestAreas.map((item) => (
                    <div key={item.name} className="space-y-1">
                    <div className="flex justify-between text-sm">
                        <span className="font-medium text-gray-700">{item.name}</span>
                        <span className="font-bold text-green-600">{item.average}%</span>
                    </div>
                    <div className="w-full bg-green-100 rounded-full h-2">
                        <div 
                        className="bg-green-500 h-2 rounded-full transition-all duration-500" 
                        style={{ width: `${item.average}%` }}
                        ></div>
                    </div>
                    </div>
                ))
                ) : <p className="text-gray-400 text-sm">Sin datos suficientes.</p>}
            </div>
            </div>
        </div>
      </div>

      {/* --- SECCION 2: ANÁLISIS POR PREGUNTAS --- */}
      <div>
        <h3 className="text-lg font-bold text-gray-800 mb-4 flex items-center gap-2">
            <AlertOctagon className="w-5 h-5 text-orange-600" /> Análisis de Hallazgos (Preguntas)
        </h3>
        <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Low Compliance Questions */}
            <div className="bg-white rounded-xl shadow-md border border-red-100 overflow-hidden">
            <div className="p-4 border-b border-red-100 bg-red-50/50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                <AlertOctagon className="w-5 h-5 text-red-600" />
                <h3 className="font-bold text-gray-800">Mayor Incumplimiento</h3>
                </div>
            </div>
            <div className="p-4 space-y-5">
                {topLowestQuestions.length > 0 ? (
                topLowestQuestions.map((item) => (
                    <div key={item.id} className="space-y-1">
                    <div className="flex justify-between text-sm">
                        {/* Removed truncate to wrap text */}
                        <span className="font-medium text-gray-700 flex-1 pr-4" title={item.text}>
                        {item.id}. {item.text}
                        </span>
                        <span className="font-bold text-red-600 flex-shrink-0">{item.percentage}%</span>
                    </div>
                    <div className="w-full bg-red-100 rounded-full h-2.5">
                        <div 
                        className="bg-red-500 h-2.5 rounded-full transition-all duration-500" 
                        style={{ width: `${item.percentage}%` }}
                        ></div>
                    </div>
                    <p className="text-[10px] text-gray-400 text-right">Base: {item.count} respuestas</p>
                    </div>
                ))
                ) : (
                <p className="text-center text-gray-400 py-4">No hay datos suficientes.</p>
                )}
            </div>
            </div>

            {/* High Compliance Questions */}
            <div className="bg-white rounded-xl shadow-md border border-green-100 overflow-hidden">
            <div className="p-4 border-b border-green-100 bg-green-50/50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                <CheckCircle2 className="w-5 h-5 text-green-600" />
                <h3 className="font-bold text-gray-800">Mayor Cumplimiento</h3>
                </div>
            </div>
            <div className="p-4 space-y-5">
                {topHighestQuestions.length > 0 ? (
                topHighestQuestions.map((item) => (
                    <div key={item.id} className="space-y-1">
                    <div className="flex justify-between text-sm">
                        {/* Removed truncate to wrap text */}
                        <span className="font-medium text-gray-700 flex-1 pr-4" title={item.text}>
                        {item.id}. {item.text}
                        </span>
                        <span className="font-bold text-green-600 flex-shrink-0">{item.percentage}%</span>
                    </div>
                    <div className="w-full bg-green-100 rounded-full h-2.5">
                        <div 
                        className="bg-green-500 h-2.5 rounded-full transition-all duration-500" 
                        style={{ width: `${item.percentage}%` }}
                        ></div>
                    </div>
                    <p className="text-[10px] text-gray-400 text-right">Base: {item.count} respuestas</p>
                    </div>
                ))
                ) : (
                <p className="text-center text-gray-400 py-4">No hay datos suficientes.</p>
                )}
            </div>
            </div>
        </div>
      </div>

      <div className="bg-blue-50 border border-blue-100 rounded-lg p-4 flex items-start gap-3">
        <BarChart3 className="w-5 h-5 text-blue-600 mt-0.5" />
        <div>
            <h4 className="font-semibold text-blue-800 text-sm">Resumen Ejecutivo</h4>
            <p className="text-sm text-blue-700 mt-1">
                Utilice el análisis de áreas para dirigir recursos de supervisión a los sectores con menor desempeño.
                Revise las preguntas con bajo cumplimiento para organizar capacitaciones o "charlas de 5 minutos" específicas sobre esos temas.
            </p>
        </div>
      </div>
    </div>
  );
};

export enum Rating {
  SI = 'SI',
  NO = 'NO',
  PARCIAL = 'PARCIAL',
  NA = 'N/A'
}

export interface Question {
  id: number;
  text: string;
}

export interface Answer {
  questionId: number;
  rating: Rating;
}

export interface AuditRecord {
  id: string;
  area: string;
  auditor: string;
  responsable?: string; // Person in charge of the area
  date: string; // ISO string
  answers: Answer[];
  score: number; // 0-100
}

export type ActionStatus = 'PENDING' | 'IN_PROGRESS' | 'CLOSED';

export interface ActionItem {
  id: string;
  auditId: string;
  area: string;
  questionId: number;
  questionText: string;
  issueType: 'NO' | 'PARCIAL'; // Why was it created?
  suggestedAction: string;
  responsable: string;
  dueDate: string; // ISO string
  status: ActionStatus;
  comments?: string;
  createdAt: string;
}

export interface AppConfig {
  areas: string[];
  responsables: { name: string; area?: string }[];
  questions: Question[];
}

export type ViewState = 'home' | 'form' | 'dashboard' | 'history' | 'ai-editor' | 'consolidated' | 'actions' | 'settings';

import React, { useState, useEffect } from 'react';
import { ViewState, AuditRecord, ActionItem, AppConfig } from './types';
import { QUESTIONS, AREA_MAPPING, AREAS } from './constants';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ConsolidatedView } from './components/ConsolidatedView';
import { ActionPlanView } from './components/ActionPlanView';
import { SettingsView } from './components/SettingsView';
import { 
  ClipboardList, 
  LayoutDashboard, 
  Plus, 
  FileText, 
  BarChart3, 
  Settings, 
  Home, 
  Camera 
} from 'lucide-react';

// Initial default config based on constants
const DEFAULT_CONFIG: AppConfig = {
  questions: QUESTIONS,
  areas: AREAS,
  responsables: AREA_MAPPING.map(am => ({ name: am.responsable, area: am.area }))
};

const App: React.FC = () => {
  // Default to 'home' as per new design requirement
  const [view, setView] = useState<ViewState>('home');

  // State
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [actions, setActions] = useState<ActionItem[]>([]);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);

  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);

  // Load from local storage on mount
  useEffect(() => {
    const savedRecords = localStorage.getItem('audit_records');
    const savedActions = localStorage.getItem('audit_actions');
    const savedConfig = localStorage.getItem('audit_config');

    if (savedRecords) {
      try { setRecords(JSON.parse(savedRecords)); } catch (e) { console.error(e); }
    }
    if (savedActions) {
      try { setActions(JSON.parse(savedActions)); } catch (e) { console.error(e); }
    }
    if (savedConfig) {
      try { 
        const parsedConfig = JSON.parse(savedConfig);
        const existingIds = new Set(parsedConfig.questions.map((q: any) => q.id));
        const questionsToAdd = QUESTIONS.filter(q => !existingIds.has(q.id));
        if (questionsToAdd.length > 0) {
            parsedConfig.questions = [...parsedConfig.questions, ...questionsToAdd];
        }
        setConfig(parsedConfig); 
      } catch (e) { console.error(e); }
    }
  }, []);

  // Save to local storage whenever state changes
  useEffect(() => {
    localStorage.setItem('audit_records', JSON.stringify(records));
  }, [records]);

  useEffect(() => {
    localStorage.setItem('audit_actions', JSON.stringify(actions));
  }, [actions]);

  useEffect(() => {
    localStorage.setItem('audit_config', JSON.stringify(config));
  }, [config]);

  const handleSaveAudit = (record: AuditRecord, newActions: ActionItem[]) => {
    if (editingRecord) {
      setRecords(prev => prev.map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...prev]);
      setActions(prev => [...newActions, ...prev]);
      if (newActions.length > 0) {
        alert(`Se han generado ${newActions.length} acciones correctivas automáticamente.`);
      }
    }
    setView('dashboard'); // Redirect to dashboard stats after save
  };

  const handleUpdateAction = (updatedAction: ActionItem) => {
    setActions(prev => prev.map(a => a.id === updatedAction.id ? updatedAction : a));
  };

  const handleUpdateConfig = (newConfig: AppConfig) => {
    setConfig(newConfig);
  };

  const handleEdit = (record: AuditRecord) => {
    setEditingRecord(record);
    setView('form');
  };

  const handleDelete = (id: string) => {
    if (confirm("¿Está seguro de eliminar este registro? Esto NO eliminará las acciones generadas.")) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const handleCancelForm = () => {
    setEditingRecord(null);
    setView('home');
  };

  const renderContent = () => {
    switch (view) {
      case 'home':
        return (
          <div className="flex flex-col items-center justify-center space-y-8 animate-fade-in py-8">
            <h2 className="text-4xl font-bold text-[#4285F4] text-center mb-8">
              Sistema de Auditoría 5S
            </h2>

            <div className="flex flex-col gap-6 w-full max-w-md px-4">
              {/* Button 1: Nueva Auditoría */}
              <button
                onClick={() => { setEditingRecord(null); setView('form'); }}
                className="group relative flex flex-col items-center justify-center bg-[#36C759] text-white p-6 rounded-2xl shadow-lg hover:shadow-xl transition-all transform hover:-translate-y-1 h-32 w-full"
              >
                <Plus className="w-10 h-10 mb-2" strokeWidth={2.5} />
                <span className="text-xl font-bold tracking-wide">Nueva Auditoría</span>
              </button>

              {/* Button 2: Ver Auditorías */}
              <button
                onClick={() => setView('history')}
                className="group relative flex flex-col items-center justify-center bg-[#4285F4] text-white p-6 rounded-2xl shadow-lg hover:shadow-xl transition-all transform hover:-translate-y-1 h-32 w-full"
              >
                <ClipboardList className="w-10 h-10 mb-2" strokeWidth={2.5} />
                <span className="text-xl font-bold tracking-wide">Ver Auditorías</span>
              </button>

              {/* Button 3: Dashboard */}
              <button
                onClick={() => setView('dashboard')}
                className="group relative flex flex-col items-center justify-center bg-[#8C47D8] text-white p-6 rounded-2xl shadow-lg hover:shadow-xl transition-all transform hover:-translate-y-1 h-32 w-full"
              >
                <BarChart3 className="w-10 h-10 mb-2" strokeWidth={2.5} />
                <span className="text-xl font-bold tracking-wide">Dashboard</span>
              </button>

              {/* Button 4: Consolidado */}
              <button
                onClick={() => setView('consolidated')}
                className="group relative flex flex-col items-center justify-center bg-[#F58137] text-white p-6 rounded-2xl shadow-lg hover:shadow-xl transition-all transform hover:-translate-y-1 h-32 w-full"
              >
                <FileText className="w-10 h-10 mb-2" strokeWidth={2.5} />
                <span className="text-xl font-bold tracking-wide">Consolidado</span>
              </button>
            </div>
          </div>
        );
      case 'form':
        return <AuditForm initialData={editingRecord} config={config} onSave={handleSaveAudit} onCancel={handleCancelForm} />;
      case 'dashboard':
        return <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} />;
      case 'history':
        return <History records={records} actions={actions} onEdit={handleEdit} onDelete={handleDelete} />;
      case 'ai-editor':
        return <AIEditor />;
      case 'consolidated':
        return <ConsolidatedView records={records} onBack={() => setView('home')} />;
      case 'actions':
        return <ActionPlanView actions={actions} onUpdateAction={handleUpdateAction} />;
      case 'settings':
        return <SettingsView config={config} onUpdateConfig={handleUpdateConfig} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-white font-sans text-gray-900 selection:bg-blue-100 selection:text-blue-900">
      {/* Custom Header - Dark Blue */}
      <header className="bg-[#0d1b2a] shadow-md sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 lg:px-6 h-16 flex items-center justify-between">

          {/* Title Left */}
          <div 
            className="flex items-center gap-3 cursor-pointer"
            onClick={() => setView('home')}
          >
            <div className="bg-white/10 p-2 rounded-lg backdrop-blur-sm">
               <ClipboardList className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-lg font-bold text-white tracking-wide hidden sm:block">
              Sistema Auditoría 5S
            </h1>
          </div>

          {/* Navigation Right */}
          <nav className="flex items-center gap-1 md:gap-4">
            <NavButton 
              label="Inicio" 
              active={view === 'home'} 
              onClick={() => setView('home')} 
              icon={<Home className="w-4 h-4" />} 
            />
            <NavButton 
              label="+ Nueva" 
              active={view === 'form'} 
              onClick={() => { setEditingRecord(null); setView('form'); }} 
              icon={<Plus className="w-4 h-4" />} 
            />
            <NavButton 
              label="Lista" 
              active={view === 'history'} 
              onClick={() => setView('history')} 
              icon={<ClipboardList className="w-4 h-4" />} 
            />
            <NavButton 
              label="Dashboard" 
              active={view === 'dashboard'} 
              onClick={() => setView('dashboard')} 
              icon={<BarChart3 className="w-4 h-4" />} 
            />
            <NavButton 
              label="Consolidado" 
              active={view === 'consolidated'} 
              onClick={() => setView('consolidated')} 
              icon={<FileText className="w-4 h-4" />} 
            />
             {/* Extra utils in header but less prominent */}
            <div className="h-6 w-px bg-white/20 mx-1"></div>
            <button 
                onClick={() => setView('settings')}
                className={`p-2 rounded-lg text-white/70 hover:text-white hover:bg-white/10 transition-colors ${view === 'settings' ? 'bg-white/10 text-white' : ''}`}
                title="Configuración"
            >
                <Settings className="w-5 h-5" />
            </button>
            <button 
                onClick={() => setView('ai-editor')}
                className={`p-2 rounded-lg text-white/70 hover:text-white hover:bg-white/10 transition-colors ${view === 'ai-editor' ? 'bg-white/10 text-white' : ''}`}
                title="Cámara IA"
            >
                <Camera className="w-5 h-5" />
            </button>
          </nav>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 lg:px-6 py-6 pb-20">
