                    <TrendingUp className={`w-4 h-4 ${averageScore >= 90 ? 'text-green-600' : 'text-yellow-600'}`} />
                </div>
            </div>
            <p className={`text-2xl font-bold mt-2 ${averageScore >= 90 ? 'text-green-600' : averageScore >= 70 ? 'text-yellow-600' : 'text-red-600'}`}>
