import React, { useState, useRef } from 'react';
import { editImageWithGemini } from '../services/geminiService';
import { Upload, Wand2, RefreshCw, Download, Image as ImageIcon } from 'lucide-react';

export const AIEditor: React.FC = () => {
  const [originalImage, setOriginalImage] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setOriginalImage(reader.result as string);
        setGeneratedImage(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!originalImage || !prompt.trim()) return;
    setIsLoading(true);
    try {
      const result = await editImageWithGemini(originalImage, prompt);
      setGeneratedImage(result);
    } catch (error) {
      alert("Error al procesar la imagen. Verifique su API Key.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="bg-[#1e293b] rounded-lg shadow-lg p-6 max-w-4xl mx-auto mb-20 border border-gray-800">
      <div className="flex items-center gap-3 mb-6 border-b border-gray-700 pb-4">
        <div className="bg-purple-900/30 p-2 rounded-lg">
          <Wand2 className="w-6 h-6 text-purple-400" />
        </div>
        <div>
          <h2 className="text-2xl font-bold text-gray-100">Editor de Evidencia con IA</h2>
          <p className="text-sm text-gray-400">Sube una foto de la auditoría y usa Gemini para resaltar fallos.</p>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <div className="space-y-4">
          <div 
            className={`border-2 border-dashed rounded-xl h-64 flex flex-col items-center justify-center cursor-pointer transition-colors ${
              originalImage ? 'border-blue-500/50 bg-blue-900/10' : 'border-gray-600 hover:border-purple-500/50 hover:bg-purple-900/10'
            }`}
            onClick={() => fileInputRef.current?.click()}
          >
            {originalImage ? (
              <img src={originalImage} alt="Original" className="h-full w-full object-contain rounded-lg" />
            ) : (
              <div className="text-center p-4">
                <Upload className="w-10 h-10 text-gray-500 mx-auto mb-2" />
                <p className="text-sm text-gray-400">Clic para subir imagen</p>
                <p className="text-xs text-gray-600 mt-1">Soporta JPG, PNG</p>
              </div>
            )}
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept="image/*" className="hidden" />
          </div>

          <div className="flex gap-2">
            <input
              type="text"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
              placeholder="Ej: 'Resalta con rojo la caja en el suelo'"
              className="flex-1 bg-[#0f172a] border border-gray-600 rounded-md p-2 text-white focus:ring-purple-500 focus:border-purple-500"
            />
            <button
              onClick={handleGenerate}
              disabled={!originalImage || !prompt || isLoading}
              className={`px-4 py-2 rounded-md text-white font-medium flex items-center ${
                !originalImage || !prompt || isLoading ? 'bg-gray-700 cursor-not-allowed' : 'bg-purple-600 hover:bg-purple-700'
              }`}
            >
              {isLoading ? <RefreshCw className="w-4 h-4 animate-spin" /> : <Wand2 className="w-4 h-4" />}
            </button>
          </div>
        </div>

        <div className="border border-gray-700 rounded-xl h-64 md:h-auto flex items-center justify-center bg-[#0f172a] relative overflow-hidden">
          {isLoading ? (
            <div className="text-center">
              <RefreshCw className="w-10 h-10 text-purple-500 animate-spin mx-auto mb-2" />
              <p className="text-sm text-purple-400 font-medium">Gemini está pensando...</p>
            </div>
          ) : generatedImage ? (
            <div className="relative w-full h-full group">
              <img src={generatedImage} alt="Generada por IA" className="w-full h-full object-contain" />
              <a href={generatedImage} download="evidencia_editada.png" className="absolute top-2 right-2 p-2 bg-black/50 rounded-full shadow-sm opacity-0 group-hover:opacity-100 transition-opacity text-white hover:bg-purple-600">
                <Download className="w-5 h-5" />
              </a>
            </div>
          ) : (
            <div className="text-center text-gray-600 p-4">
              <ImageIcon className="w-10 h-10 mx-auto mb-2 opacity-30" />
              <p className="text-sm">La imagen editada aparecerá aquí</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { AppConfig } from '../types';
import { Plus, Trash2, Settings as SettingsIcon, Users, MapPin, HelpCircle } from 'lucide-react';

interface SettingsViewProps {
  config: AppConfig;
  onUpdateConfig: (newConfig: AppConfig) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({ config, onUpdateConfig }) => {
  const [activeTab, setActiveTab] = useState<'areas' | 'responsables' | 'questions'>('areas');
  const [newArea, setNewArea] = useState('');
  const [newResponsable, setNewResponsable] = useState('');
  const [newQuestion, setNewQuestion] = useState('');

  const handleAddArea = () => {
    if (newArea.trim()) {
      onUpdateConfig({ ...config, areas: [...config.areas, newArea.trim().toUpperCase()] });
      setNewArea('');
    }
  };

  const handleDeleteArea = (area: string) => {
    if (confirm(`¿Eliminar área ${area}?`)) {
      onUpdateConfig({ ...config, areas: config.areas.filter(a => a !== area) });
    }
  };

  const handleAddResponsable = () => {
    if (newResponsable.trim()) {
      onUpdateConfig({ ...config, responsables: [...config.responsables, { name: newResponsable.trim().toUpperCase() }] });
      setNewResponsable('');
    }
  };

  const handleDeleteResponsable = (name: string) => {
    if (confirm(`¿Eliminar responsable ${name}?`)) {
      onUpdateConfig({ ...config, responsables: config.responsables.filter(r => r.name !== name) });
    }
  };

  const handleAddQuestion = () => {
    if (newQuestion.trim()) {
      const nextId = config.questions.length > 0 ? Math.max(...config.questions.map(q => q.id)) + 1 : 1;
      onUpdateConfig({ ...config, questions: [...config.questions, { id: nextId, text: newQuestion.trim() }] });
      setNewQuestion('');
    }
  };

  const handleDeleteQuestion = (id: number) => {
    if (confirm(`¿Eliminar pregunta ID ${id}?`)) {
      onUpdateConfig({ ...config, questions: config.questions.filter(q => q.id !== id) });
    }
  };

  return (
    <div className="bg-[#1e293b] rounded-xl shadow-lg border border-gray-800 mb-24 overflow-hidden">
      <div className="p-6 border-b border-gray-800 bg-[#0f172a] flex items-center gap-3">
        <div className="bg-gray-800 p-2 rounded-lg">
            <SettingsIcon className="w-6 h-6 text-gray-300" />
        </div>
        <div>
            <h2 className="text-xl font-bold text-gray-100">Configuración</h2>
            <p className="text-sm text-gray-400">Parámetros globales.</p>
        </div>
      </div>

      <div className="flex border-b border-gray-800">
        <button onClick={() => setActiveTab('areas')} className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${activeTab === 'areas' ? 'border-blue-500 text-blue-400 bg-blue-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}><MapPin className="w-4 h-4" /> Áreas</button>
        <button onClick={() => setActiveTab('responsables')} className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${activeTab === 'responsables' ? 'border-blue-500 text-blue-400 bg-blue-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}><Users className="w-4 h-4" /> Responsables</button>
        <button onClick={() => setActiveTab('questions')} className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${activeTab === 'questions' ? 'border-blue-500 text-blue-400 bg-blue-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}><HelpCircle className="w-4 h-4" /> Preguntas</button>
      </div>

      <div className="p-6">
        {activeTab === 'areas' && (
          <div className="space-y-4">
            <div className="flex gap-2">
              <input type="text" value={newArea} onChange={(e) => setNewArea(e.target.value)} placeholder="Nueva área..." className="flex-1 bg-[#0f172a] border border-gray-600 rounded-lg p-2 text-white focus:ring-blue-500 focus:border-blue-500" />
              <button onClick={handleAddArea} className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2"><Plus className="w-4 h-4" /> Agregar</button>
            </div>
            <ul className="divide-y divide-gray-800 border border-gray-700 rounded-lg overflow-hidden">
              {config.areas.map((area) => (
                <li key={area} className="p-3 hover:bg-[#0f172a] flex justify-between items-center group">
                  <span className="font-medium text-gray-300">{area}</span>
                  <button onClick={() => handleDeleteArea(area)} className="text-gray-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-4 h-4" /></button>
                </li>
              ))}
            </ul>
          </div>
        )}
        {activeTab === 'responsables' && (
          <div className="space-y-4">
             <div className="flex gap-2">
              <input type="text" value={newResponsable} onChange={(e) => setNewResponsable(e.target.value)} placeholder="Nuevo responsable..." className="flex-1 bg-[#0f172a] border border-gray-600 rounded-lg p-2 text-white focus:ring-blue-500 focus:border-blue-500" />
              <button onClick={handleAddResponsable} className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2"><Plus className="w-4 h-4" /> Agregar</button>
            </div>
            <ul className="divide-y divide-gray-800 border border-gray-700 rounded-lg overflow-hidden">
              {config.responsables.map((resp) => (
                <li key={resp.name} className="p-3 hover:bg-[#0f172a] flex justify-between items-center group">
                  <span className="font-medium text-gray-300">{resp.name}</span>
                  <button onClick={() => handleDeleteResponsable(resp.name)} className="text-gray-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-4 h-4" /></button>
                </li>
              ))}
            </ul>
          </div>
        )}
        {activeTab === 'questions' && (
          <div className="space-y-4">
             <div className="flex gap-2">
              <input type="text" value={newQuestion} onChange={(e) => setNewQuestion(e.target.value)} placeholder="Nueva pregunta..." className="flex-1 bg-[#0f172a] border border-gray-600 rounded-lg p-2 text-white focus:ring-blue-500 focus:border-blue-500" />
              <button onClick={handleAddQuestion} className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2"><Plus className="w-4 h-4" /> Agregar</button>
            </div>
            <ul className="divide-y divide-gray-800 border border-gray-700 rounded-lg overflow-hidden">
              {config.questions.map((q) => (
                <li key={q.id} className="p-3 hover:bg-[#0f172a] flex justify-between items-center group">
                  <div className="flex items-center gap-3">
                    <span className="w-6 h-6 bg-blue-900/50 text-blue-300 rounded-full flex items-center justify-center text-xs font-bold border border-blue-800">{q.id}</span>
                    <span className="text-gray-300 text-sm">{q.text}</span>
                  </div>
                  <button onClick={() => handleDeleteQuestion(q.id)} className="text-gray-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-4 h-4" /></button>
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </div>
  );
};

import React from 'react';
import { AuditRecord, ActionItem } from '../types';
import * as XLSX from 'xlsx';
import { Edit2, Trash2, FileSpreadsheet, Calendar, Share } from 'lucide-react';

interface HistoryProps {
  records: AuditRecord[];
  actions: ActionItem[];
  onEdit: (record: AuditRecord) => void;
  onDelete: (id: string) => void;
}

export const History: React.FC<HistoryProps> = ({ records, actions, onEdit, onDelete }) => {

  const handleExportExcel = () => {
    // Format data specifically for SharePoint List Import
    const auditData = records.map(r => {
      const row: any = {
        'ID_Unico': r.id,
        'Fecha_Auditoria': new Date(r.date).toLocaleDateString(),
        'Area': r.area,
        'Responsable': r.responsable || 'N/A',
        'Auditor': r.auditor,
        'Puntaje_Total': r.score
      };
      // Flatten questions for Excel columns
      r.answers.forEach(a => { row[`P${a.questionId}_Respuesta`] = a.rating; });
      return row;
    });

    const actionData = actions.map(a => ({
        'ID_Accion': a.id,
        'ID_Auditoria_Ref': a.auditId,
        'Fecha_Creacion': new Date(a.createdAt).toLocaleDateString(),
        'Area': a.area,
        'Hallazgo': a.questionText,
        'Tipo_Hallazgo': a.issueType,
        'Accion_Sugerida': a.suggestedAction,
        'Responsable_Accion': a.responsable,
        'Fecha_Compromiso': new Date(a.dueDate).toLocaleDateString(),
        'Estado_Actual': a.status === 'PENDING' ? 'Pendiente' : a.status === 'IN_PROGRESS' ? 'En Proceso' : 'Cerrado',
    }));

    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(auditData), "Datos_Para_SharePoint");
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(actionData), "Planes_De_Accion");

    // Save file
    XLSX.writeFile(wb, `Auditoria_5S_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const getScoreBadge = (score: number) => {
    let colorClass = '';
    if (score >= 90) colorClass = 'bg-green-900/30 text-green-400 border-green-500/30';
    else if (score >= 70) colorClass = 'bg-yellow-900/30 text-yellow-400 border-yellow-500/30';
    else colorClass = 'bg-red-900/30 text-red-400 border-red-500/30';

    return (
      <span className={`px-2.5 py-0.5 inline-flex text-xs leading-5 font-bold rounded-full border ${colorClass}`}>
        {score}%
      </span>
    );
  };

  return (
    <div className="space-y-6 mb-24 animate-fade-in">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-[#1e293b] p-5 rounded-xl shadow-lg border border-gray-700">
        <div>
          <h2 className="text-2xl font-bold text-gray-100">Historial de Registros</h2>
          <p className="text-sm text-gray-400">{records.length} auditorías en base de datos local</p>
        </div>
        <button 
          onClick={handleExportExcel}
          className="w-full sm:w-auto flex items-center justify-center px-6 py-3 bg-[#107c41] text-white rounded-lg hover:bg-[#0b5c30] transition-all shadow-lg hover:shadow-green-500/20 font-medium border border-green-600"
        >
          <FileSpreadsheet className="w-5 h-5 mr-2" />
          Descargar para SharePoint
        </button>
      </div>

      <div className="bg-blue-900/20 border border-blue-500/30 p-4 rounded-lg flex items-start gap-3">
        <Share className="w-5 h-5 text-blue-400 mt-0.5" />
        <div className="text-sm text-gray-300">
            <span className="font-bold text-blue-300">Nota sobre SharePoint:</span> Dado que esta es una aplicación web segura sin servidor, no guarda directamente en su nube corporativa. 
            <br/>1. Presione el botón verde de arriba para descargar el Excel.
            <br/>2. Arrastre el archivo descargado a su carpeta de SharePoint o Teams.
        </div>
      </div>

      {records.length === 0 ? (
        <div className="bg-[#1e293b] rounded-xl shadow-sm border border-gray-800 p-12 text-center">
            <div className="w-16 h-16 bg-[#0f172a] rounded-full flex items-center justify-center mx-auto mb-4 border border-gray-700">
                <FileSpreadsheet className="w-8 h-8 text-gray-500" />
            </div>
            <h3 className="text-lg font-medium text-gray-200">No hay registros</h3>
            <p className="text-gray-500 mt-1">Comience una nueva auditoría para ver los datos aquí.</p>
        </div>
      ) : (
        <>
          <div className="hidden sm:block bg-[#1e293b] rounded-xl shadow-lg border border-gray-700 overflow-hidden">
            <table className="min-w-full divide-y divide-gray-800">
