            >
              <Save className="w-4 h-4 mr-2" />
              Guardar Auditoría
            </button>
          </div>
        </div>
      </form>
    </div>
  );
};

import React, { useState } from 'react';
import { AppConfig } from '../types';
import { Plus, Trash2, Settings as SettingsIcon, Users, MapPin, HelpCircle } from 'lucide-react';

interface SettingsViewProps {
  config: AppConfig;
  onUpdateConfig: (newConfig: AppConfig) => void;
}

export const SettingsView: React.FC<SettingsViewProps> = ({ config, onUpdateConfig }) => {
  const [activeTab, setActiveTab] = useState<'areas' | 'questions'>('areas');
  const [newArea, setNewArea] = useState('');
  const [newResponsableForArea, setNewResponsableForArea] = useState('');
  const [newQuestion, setNewQuestion] = useState('');

  const handleAddAreaAndResponsable = () => {
    if (newArea.trim() && newResponsableForArea.trim()) {
      const areaName = newArea.trim().toUpperCase();
      const responsableName = newResponsableForArea.trim().toUpperCase();

      onUpdateConfig({ 
        ...config, 
        areas: [...config.areas, areaName],
        responsables: [...config.responsables, { name: responsableName, area: areaName }]
      });
      setNewArea('');
      setNewResponsableForArea('');
    } else {
        alert("Debe ingresar tanto el nombre del Área como el Responsable.");
    }
  };

  const handleDeleteArea = (area: string) => {
    if (confirm(`¿Eliminar área ${area} y su responsable asignado?`)) {
      onUpdateConfig({ 
          ...config, 
          areas: config.areas.filter(a => a !== area),
          responsables: config.responsables.filter(r => r.area !== area)
      });
    }
  };

  const handleAddQuestion = () => {
    if (newQuestion.trim()) {
      const nextId = config.questions.length > 0 ? Math.max(...config.questions.map(q => q.id)) + 1 : 1;
      onUpdateConfig({ ...config, questions: [...config.questions, { id: nextId, text: newQuestion.trim() }] });
      setNewQuestion('');
    }
  };

  const handleDeleteQuestion = (id: number) => {
    if (confirm(`¿Eliminar pregunta ID ${id}?`)) {
      onUpdateConfig({ ...config, questions: config.questions.filter(q => q.id !== id) });
    }
  };

  return (
    <div className="bg-[#1e293b] rounded-xl shadow-lg border border-gray-800 mb-24 overflow-hidden">
      <div className="p-6 border-b border-gray-800 bg-[#0f172a] flex items-center gap-3">
        <div className="bg-gray-800 p-2 rounded-lg">
            <SettingsIcon className="w-6 h-6 text-gray-300" />
        </div>
        <div>
            <h2 className="text-xl font-bold text-gray-100">Configuración</h2>
            <p className="text-sm text-gray-400">Gestione áreas, responsables y preguntas.</p>
        </div>
      </div>

      <div className="flex border-b border-gray-800">
        <button onClick={() => setActiveTab('areas')} className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${activeTab === 'areas' ? 'border-blue-500 text-blue-400 bg-blue-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}><MapPin className="w-4 h-4" /> Áreas y Responsables</button>
        <button onClick={() => setActiveTab('questions')} className={`flex-1 py-4 text-sm font-medium flex items-center justify-center gap-2 border-b-2 transition-colors ${activeTab === 'questions' ? 'border-blue-500 text-blue-400 bg-blue-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}><HelpCircle className="w-4 h-4" /> Preguntas</button>
      </div>

      <div className="p-6">
        {activeTab === 'areas' && (
          <div className="space-y-6">
            <div className="bg-blue-900/10 border border-blue-500/20 p-4 rounded-lg space-y-3">
                <h3 className="text-sm font-bold text-blue-300">Agregar Nueva Área</h3>
                <div className="flex flex-col md:flex-row gap-3">
                    <input type="text" value={newArea} onChange={(e) => setNewArea(e.target.value)} placeholder="Nombre del Área" className="flex-1 bg-[#0f172a] border border-gray-600 rounded-lg p-2.5 text-white focus:ring-blue-500 focus:border-blue-500 text-sm" />
                    <input type="text" value={newResponsableForArea} onChange={(e) => setNewResponsableForArea(e.target.value)} placeholder="Nombre del Responsable" className="flex-1 bg-[#0f172a] border border-gray-600 rounded-lg p-2.5 text-white focus:ring-blue-500 focus:border-blue-500 text-sm" />
                    <button onClick={handleAddAreaAndResponsable} className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center justify-center gap-2 text-sm font-medium"><Plus className="w-4 h-4" /> Agregar</button>
                </div>
            </div>

            <div className="space-y-2">
                <h3 className="text-sm font-bold text-gray-400 uppercase tracking-wider">Áreas Existentes</h3>
                <ul className="divide-y divide-gray-800 border border-gray-700 rounded-lg overflow-hidden bg-[#0f172a]/50">
                {config.areas.map((area) => {
                    const resp = config.responsables.find(r => r.area === area);
                    return (
                        <li key={area} className="p-4 hover:bg-[#0f172a] flex justify-between items-center group transition-colors">
                            <div>
                                <div className="font-bold text-gray-200 flex items-center gap-2">
                                    <MapPin className="w-4 h-4 text-blue-500" /> {area}
                                </div>
                                <div className="text-sm text-gray-500 mt-1 flex items-center gap-2 ml-6">
                                    <Users className="w-3 h-3" /> Responsable: <span className="text-gray-400">{resp?.name || 'No asignado'}</span>
                                </div>
                            </div>
                            <button onClick={() => handleDeleteArea(area)} className="p-2 text-gray-500 hover:text-red-400 hover:bg-red-900/20 rounded-full transition-all" title="Eliminar Área"><Trash2 className="w-4 h-4" /></button>
                        </li>
                    );
                })}
                </ul>
            </div>
          </div>
        )}

        {activeTab === 'questions' && (
          <div className="space-y-4">
             <div className="flex gap-2">
              <input type="text" value={newQuestion} onChange={(e) => setNewQuestion(e.target.value)} placeholder="Nueva pregunta..." className="flex-1 bg-[#0f172a] border border-gray-600 rounded-lg p-2 text-white focus:ring-blue-500 focus:border-blue-500" />
              <button onClick={handleAddQuestion} className="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700 flex items-center gap-2"><Plus className="w-4 h-4" /> Agregar</button>
            </div>
            <ul className="divide-y divide-gray-800 border border-gray-700 rounded-lg overflow-hidden">
              {config.questions.map((q) => (
                <li key={q.id} className="p-3 hover:bg-[#0f172a] flex justify-between items-center group">
                  <div className="flex items-center gap-3">
                    <span className="w-6 h-6 bg-blue-900/50 text-blue-300 rounded-full flex items-center justify-center text-xs font-bold border border-blue-800">{q.id}</span>
                    <span className="text-gray-300 text-sm">{q.text}</span>
                  </div>
                  <button onClick={() => handleDeleteQuestion(q.id)} className="text-gray-500 hover:text-red-400 opacity-0 group-hover:opacity-100 transition-opacity"><Trash2 className="w-4 h-4" /></button>
                </li>
              ))}
            </ul>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useRef } from 'react';
import { AuditRecord, ActionItem } from '../types';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LabelList, PieChart, Pie, Legend } from 'recharts';
import { Trophy, TrendingUp, AlertTriangle, CheckCircle, PieChart as PieChartIcon, ClipboardList, Activity, Camera } from 'lucide-react';
import html2canvas from 'html2canvas';

interface DashboardProps {
  records: AuditRecord[];
  actions: ActionItem[];
  onViewConsolidated: () => void;
  onViewActions: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ records, actions, onViewConsolidated, onViewActions }) => {
  const dashboardRef = useRef<HTMLDivElement>(null);

  const handleCaptureScreenshot = async () => {
    if (dashboardRef.current) {
        try {
            const canvas = await html2canvas(dashboardRef.current, {
                backgroundColor: '#121212',
                scale: 2 // High resolution
            });
            const link = document.createElement('a');
            link.download = `Dashboard_Status_${new Date().toISOString().split('T')[0]}.png`;
            link.href = canvas.toDataURL('image/png');
            link.click();
        } catch (error) {
            console.error("Error capturing screenshot:", error);
            alert("Error al capturar la imagen. Intente nuevamente.");
        }
    }
  };

  // Aggregate average score by Area
  const areaStats: Record<string, { totalScore: number; count: number }> = {};

  records.forEach(r => {
    if (!areaStats[r.area]) {
      areaStats[r.area] = { totalScore: 0, count: 0 };
    }
    areaStats[r.area].totalScore += r.score;
    areaStats[r.area].count += 1;
  });

  const chartData = Object.entries(areaStats)
    .map(([area, stats]) => ({
      name: area,
      score: Math.round(stats.totalScore / stats.count),
      audits: stats.count
    }))
    .sort((a, b) => b.score - a.score); // Sort by score descending

  // Color logic
  const getScoreColor = (score: number) => {
    if (score >= 90) return 'text-green-400 bg-green-900/30 border-green-500/30';
    if (score >= 70) return 'text-yellow-400 bg-yellow-900/30 border-yellow-500/30';
    return 'text-red-400 bg-red-900/30 border-red-500/30';
  };

  const getBarColor = (score: number) => {
    if (score >= 90) return '#22c55e'; // Green-500
    if (score >= 70) return '#eab308'; // Yellow-500
    return '#ef4444'; // Red-500
  };

  const averageScore = records.length > 0
    ? Math.round(records.reduce((acc, r) => acc + r.score, 0) / records.length)
    : 0;

  const openActions = actions.filter(a => a.status !== 'CLOSED').length;
  const closedActions = actions.filter(a => a.status === 'CLOSED').length;

  // Calculate dynamic height for the chart to fit all areas
  const chartHeight = Math.max(300, chartData.length * 60);

  // Pie Chart Data
  const pieData = [
    { name: 'Cumplimiento', value: averageScore },
    { name: 'Brecha', value: 100 - averageScore }
  ];
  const pieColors = [getBarColor(averageScore), '#334155']; // Use dark slate for gap

  return (
    <div className="space-y-8 mb-24 animate-fade-in" ref={dashboardRef}>

      <div className="flex justify-between items-center">
          <h2 className="text-xl font-bold text-gray-100 hidden sm:block">Dashboard Operativo</h2>
          <button 
            onClick={handleCaptureScreenshot}
            className="flex items-center gap-2 bg-[#1e293b] border border-gray-700 text-gray-300 px-4 py-2 rounded-lg hover:bg-[#0f172a] hover:text-white transition-all text-sm ml-auto"
          >
            <Camera className="w-4 h-4" /> Capturar Pantalla
          </button>
      </div>

      {/* --- NEON DESIGN KPI CARDS --- */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">

        {/* CARD 1: AUDITORÍAS (Cyan) */}
        <div className="bg-[#0f172a] rounded-[24px] border border-cyan-500/30 p-6 flex flex-col justify-between h-48 relative shadow-[0_0_15px_rgba(34,211,238,0.1)] transition-transform hover:-translate-y-1">
            <div className="flex justify-between items-start">
                <p className="text-gray-400 font-bold text-xs tracking-wider">AUDITORÍAS</p>
                <div className="relative group">
                    <div className="absolute inset-0 bg-cyan-400 blur-sm opacity-20 rounded-full"></div>
                    <div className="relative border border-cyan-500/50 rounded-full p-1.5 bg-[#0f172a]">
                        <CheckCircle className="w-5 h-5 text-cyan-400" />
                    </div>
                </div>
            </div>
            <div className="flex-1 flex items-center justify-center">
                <p className="text-5xl font-bold text-white drop-shadow-[0_0_8px_rgba(34,211,238,0.5)]">
                    {records.length}
                </p>
            </div>
            <div className="h-4"></div>
        </div>

        {/* CARD 2: PROMEDIO (Green) */}
        <div className="bg-[#0f172a] rounded-[24px] border border-green-500/30 p-6 flex flex-col justify-between h-48 relative shadow-[0_0_15px_rgba(74,222,128,0.1)] transition-transform hover:-translate-y-1">
            <div className="flex justify-between items-start">
                <p className="text-gray-400 font-bold text-xs tracking-wider">PROMEDIO</p>
                <div className="relative group">
                    <div className="absolute inset-0 bg-green-500 blur-sm opacity-20 rounded-full"></div>
                    <div className="relative border border-green-500/50 rounded-full p-1.5 bg-[#0f172a]">
                        <TrendingUp className="w-5 h-5 text-green-400" />
                    </div>
                </div>
            </div>
            <div className="flex-1 flex items-center justify-center">
                <p className={`text-5xl font-bold drop-shadow-[0_0_8px_rgba(74,222,128,0.5)] ${
                    averageScore >= 90 ? 'text-green-400' : averageScore >= 70 ? 'text-yellow-400' : 'text-red-400'
                }`}>
                    {averageScore}%
                </p>
            </div>
            <div className="h-4"></div>
        </div>

        {/* CARD 3: ACCIONES ABIERTAS (Orange) */}
        <div 
            onClick={onViewActions}
            className="bg-[#0f172a] rounded-[24px] border border-orange-500/30 p-6 flex flex-col justify-between h-48 relative shadow-[0_0_15px_rgba(251,146,60,0.1)] cursor-pointer hover:shadow-[0_0_25px_rgba(251,146,60,0.2)] transition-all hover:-translate-y-1 group"
        >
            <div className="flex justify-between items-start">
                <div className="flex flex-col">
                    <p className="text-gray-400 font-bold text-xs tracking-wider">ACCIONES</p>
                    <p className="text-orange-400 font-bold text-xs tracking-wider">PENDIENTES</p>
                </div>
                <div className="relative">
                    <div className="absolute inset-0 bg-orange-500 blur-sm opacity-20 rounded-full"></div>
                    <div className="relative border border-orange-500/50 rounded-full p-1.5 bg-[#0f172a]">
                        <AlertTriangle className="w-5 h-5 text-orange-400" />
                    </div>
                </div>
            </div>
            <div className="flex-1 flex items-center justify-center">
                <p className="text-5xl font-bold text-white drop-shadow-[0_0_8px_rgba(251,146,60,0.5)]">
                    {openActions}
                </p>
            </div>
            <p className="text-center text-orange-400/80 text-xs font-medium mt-auto group-hover:text-orange-300 transition-colors">Click para gestionar</p>
        </div>

        {/* CARD 4: CERRADAS (Purple) */}
        <div className="bg-[#0f172a] rounded-[24px] border border-purple-500/30 p-6 flex flex-col justify-between h-48 relative shadow-[0_0_15px_rgba(192,132,252,0.1)] transition-transform hover:-translate-y-1">
            <div className="flex justify-between items-start">
                <p className="text-gray-400 font-bold text-xs tracking-wider">CERRADAS</p>
                <div className="relative group">
                    <div className="absolute inset-0 bg-purple-500 blur-sm opacity-20 rounded-full"></div>
                    <div className="relative border border-purple-500/50 rounded-full p-1.5 bg-[#0f172a]">
                        <CheckCircle className="w-5 h-5 text-purple-400" />
                    </div>
                </div>
            </div>
            <div className="flex-1 flex items-center justify-center">
                <p className="text-5xl font-bold text-white drop-shadow-[0_0_8px_rgba(192,132,252,0.5)]">
                    {closedActions}
                </p>
            </div>
            <div className="h-4"></div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        {/* Action Button for Analysis */}
        <button 
            onClick={onViewConsolidated}
            className="w-full py-4 px-6 bg-[#1e293b] hover:bg-[#0f172a] text-gray-200 border border-gray-700 rounded-xl shadow-lg transition-all flex items-center justify-center gap-3 font-bold text-lg group"
        >
            <div className="bg-orange-900/30 p-2 rounded-full border border-orange-500/30 group-hover:border-orange-500/60 transition-colors">
                <PieChartIcon className="w-6 h-6 text-orange-400" />
            </div>
            Análisis Consolidado
        </button>

        {/* Action Button for Plans */}
        <button 
            onClick={onViewActions}
            className="w-full py-4 px-6 bg-[#1e293b] hover:bg-[#0f172a] text-gray-200 border border-gray-700 rounded-xl shadow-lg transition-all flex items-center justify-center gap-3 font-bold text-lg group"
        >
            <div className="bg-blue-900/30 p-2 rounded-full border border-blue-500/30 group-hover:border-blue-500/60 transition-colors">
                <ClipboardList className="w-6 h-6 text-blue-400" />
            </div>
            Ver Planes de Acción
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">

        {/* Global Compliance Pie Chart */}
        <div className="bg-[#1e293b] rounded-xl shadow-lg border border-gray-800 p-5 flex flex-col">
          <h3 className="text-lg font-bold text-gray-100 mb-2">Cumplimiento Global</h3>
          <div className="flex-1 min-h-[300px] flex items-center justify-center relative">
              <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                      <Pie
                          data={pieData}
                          cx="50%"
                          cy="50%"
                          innerRadius={60}
                          outerRadius={80}
                          paddingAngle={5}
                          dataKey="value"
                          startAngle={90}
                          endAngle={-270}
                          stroke="none"
                      >
                          <Cell fill={pieColors[0]} />
                          <Cell fill={pieColors[1]} />
                      </Pie>
                      <Tooltip 
                        contentStyle={{ borderRadius: '8px', border: '1px solid #374151', backgroundColor: '#0f172a', color: '#f3f4f6' }}
                        itemStyle={{ color: '#e2e8f0' }}
                      />
                      <Legend verticalAlign="bottom" height={36} formatter={(value) => <span style={{ color: '#9ca3af' }}>{value}</span>} />
                  </PieChart>
              </ResponsiveContainer>
              <div className="absolute inset-0 flex items-center justify-center flex-col pointer-events-none pb-8">
                  <span className={`text-3xl font-bold ${
                      averageScore >= 90 ? 'text-green-400' : averageScore >= 70 ? 'text-yellow-400' : 'text-red-400'
                  }`}>
                    {averageScore}%
                  </span>
                  <span className="text-xs text-gray-400 font-medium uppercase">Promedio</span>
              </div>
          </div>
        </div>

        {/* Ranking List */}
        <div className="lg:col-span-2 bg-[#1e293b] rounded-xl shadow-lg border border-gray-800 overflow-hidden">
          <div className="p-5 border-b border-gray-800 flex items-center gap-2 bg-[#0f172a]">
            <Trophy className="w-5 h-5 text-yellow-500" />
            <h3 className="text-lg font-bold text-gray-100">Ranking de Cumplimiento</h3>
          </div>
          <div className="p-0">
            {chartData.length > 0 ? (
