import React, { useState, useEffect, useRef } from 'react';
import { ViewState, AuditRecord, ActionItem, AppConfig, Rating } from './types';
import { QUESTIONS, AREA_MAPPING, AREAS } from './constants';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ConsolidatedView } from './components/ConsolidatedView';
import { ActionPlanView } from './components/ActionPlanView';
import { SettingsView } from './components/SettingsView';
import { 
  ClipboardList, 
  Plus, 
  FileText, 
  BarChart, 
  Settings, 
  Home, 
  Camera 
} from 'lucide-react';

const DEFAULT_CONFIG: AppConfig = {
  questions: QUESTIONS,
  areas: AREAS,
  responsables: AREA_MAPPING.map(am => ({ name: am.responsable, area: am.area }))
};

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('home');
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [actions, setActions] = useState<ActionItem[]>([]);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);
  const isInitialLoad = useRef(true);

  // Carga inicial
  useEffect(() => {
    const savedRecords = localStorage.getItem('audit_records');
    const savedActions = localStorage.getItem('audit_actions');
    const savedConfig = localStorage.getItem('audit_config');

    if (savedRecords) try { setRecords(JSON.parse(savedRecords)); } catch (e) { console.error(e); }
    if (savedActions) try { setActions(JSON.parse(savedActions)); } catch (e) { console.error(e); }
    if (savedConfig) {
      try { 
        const parsedConfig = JSON.parse(savedConfig);
        // Mezclar con nuevas preguntas si existen
        const existingIds = new Set(parsedConfig.questions.map((q: any) => q.id));
        const questionsToAdd = QUESTIONS.filter(q => !existingIds.has(q.id));
        parsedConfig.questions = [...parsedConfig.questions, ...questionsToAdd];
        setConfig(parsedConfig); 
      } catch (e) { console.error(e); }
    }
    isInitialLoad.current = false;
  }, []);

  // Guardado persistente (solo después de la carga inicial)
  useEffect(() => {
    if (!isInitialLoad.current) {
      localStorage.setItem('audit_records', JSON.stringify(records));
    }
  }, [records]);

  useEffect(() => {
    if (!isInitialLoad.current) {
      localStorage.setItem('audit_actions', JSON.stringify(actions));
    }
  }, [actions]);

  useEffect(() => {
    if (!isInitialLoad.current) {
      localStorage.setItem('audit_config', JSON.stringify(config));
    }
  }, [config]);

  const handleSaveAudit = (record: AuditRecord, newActions: ActionItem[]) => {
    if (editingRecord) {
      setRecords(prev => prev.map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...prev]);
      setActions(prev => [...newActions, ...prev]);
    }
    setView('dashboard');
  };

  const loadDemoData = () => {
    const demoRecords: AuditRecord[] = config.areas.slice(0, 5).map((area, idx) => ({
        id: `demo-${idx}`,
        area,
        auditor: 'Demo Auditor',
        responsable: config.responsables.find(r => r.area === area)?.name || 'Admin',
        date: new Date().toISOString(),
        score: 70 + Math.floor(Math.random() * 30),
        answers: config.questions.map(q => ({ questionId: q.id, rating: Rating.SI }))
    }));
    setRecords(demoRecords);
    alert("Datos de prueba cargados correctamente.");
  };

  const handleUpdateAction = (updatedAction: ActionItem) => {
    setActions(prev => prev.map(a => a.id === updatedAction.id ? updatedAction : a));
  };

  const handleUpdateConfig = (newConfig: AppConfig) => {
    setConfig(newConfig);
  };

  const handleEdit = (record: AuditRecord) => {
    setEditingRecord(record);
    setView('form');
  };

  const handleDelete = (id: string) => {
    if (confirm("¿Eliminar este registro?")) {
      setRecords(prev => prev.filter(r => r.id !== id));
    }
  };

  const renderContent = () => {
    switch (view) {
      case 'home':
        return (
          <div className="flex flex-col items-center justify-center space-y-8 animate-fade-in py-8 text-center">
            <h2 className="text-4xl font-bold text-blue-400 mb-8 drop-shadow-lg">
              Sistema de Auditoría 5S
            </h2>
            <div className="flex flex-col gap-6 w-full max-w-md px-4">
              <MenuButton label="Nueva Auditoría" onClick={() => { setEditingRecord(null); setView('form'); }} color="green" icon={<Plus className="w-8 h-8" />} />
              <MenuButton label="Lista de Registros" onClick={() => setView('history')} color="blue" icon={<ClipboardList className="w-8 h-8" />} />
              <MenuButton label="Dashboard" onClick={() => setView('dashboard')} color="purple" icon={<BarChart className="w-8 h-8" />} />
              <MenuButton label="Análisis Consolidado" onClick={() => setView('consolidated')} color="orange" icon={<FileText className="w-8 h-8" />} />
            </div>
          </div>
        );
      case 'form':
        return <AuditForm initialData={editingRecord} config={config} onSave={handleSaveAudit} onCancel={() => setView('home')} />;
      case 'dashboard':
        return <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} onGenerateDemo={loadDemoData} />;
      case 'history':
        return <History records={records} actions={actions} onEdit={handleEdit} onDelete={handleDelete} />;
      case 'ai-editor':
        return <AIEditor />;
      case 'consolidated':
        return <ConsolidatedView records={records} onBack={() => setView('home')} />;
      case 'actions':
        return <ActionPlanView actions={actions} onUpdateAction={handleUpdateAction} />;
      case 'settings':
        return <SettingsView config={config} onUpdateConfig={handleUpdateConfig} />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-[#121212] font-sans text-gray-100">
      <header className="bg-[#0f172a] border-b border-gray-800 shadow-lg sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('home')}>
            <ClipboardList className="w-6 h-6 text-blue-400" />
            <h1 className="text-lg font-bold hidden sm:block">AuditCheck Pro</h1>
          </div>
          <nav className="flex items-center gap-2">
            <NavIcon active={view === 'home'} onClick={() => setView('home')} icon={<Home className="w-5 h-5" />} title="Inicio" />
            <NavIcon active={view === 'form'} onClick={() => { setEditingRecord(null); setView('form'); }} icon={<Plus className="w-5 h-5" />} title="Nueva" />
            <NavIcon active={view === 'dashboard'} onClick={() => setView('dashboard')} icon={<BarChart className="w-5 h-5" />} title="Dashboard" />
            <NavIcon active={view === 'settings'} onClick={() => setView('settings')} icon={<Settings className="w-5 h-5" />} title="Ajustes" />
            <NavIcon active={view === 'ai-editor'} onClick={() => setView('ai-editor')} icon={<Camera className="w-5 h-5" />} title="IA" />
          </nav>
        </div>
      </header>
      <main className="max-w-7xl mx-auto px-4 py-6">{renderContent()}</main>
    </div>
  );
};

const MenuButton: React.FC<{label: string, onClick: () => void, color: string, icon: React.ReactNode}> = ({label, onClick, color, icon}) => {
    const colors: any = {
        green: 'border-green-500/30 text-green-400 shadow-green-500/10',
        blue: 'border-blue-500/30 text-blue-400 shadow-blue-500/10',
        purple: 'border-purple-500/30 text-purple-400 shadow-purple-500/10',
        orange: 'border-orange-500/30 text-orange-400 shadow-orange-500/10'
    };
    return (
        <button onClick={onClick} className={`flex flex-col items-center justify-center bg-[#1e293b] border p-6 rounded-2xl shadow-xl hover:bg-[#0f172a] transition-all transform hover:-translate-y-1 ${colors[color]}`}>
            {icon}
            <span className="text-lg font-bold mt-2">{label}</span>
        </button>
    );
};

const NavIcon: React.FC<{active: boolean, onClick: () => void, icon: React.ReactNode, title: string}> = ({active, onClick, icon, title}) => (
    <button onClick={onClick} title={title} className={`p-2 rounded-lg transition-colors ${active ? 'bg-blue-600/20 text-blue-400' : 'text-gray-400 hover:bg-gray-800'}`}>
        {icon}
    </button>
);

export default App;

import React, { useRef } from 'react';
import { AuditRecord, ActionItem } from '../types';
import { 
  BarChart as ReBarChart, 
  Bar, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer, 
  Cell, 
  LabelList, 
  PieChart, 
  Pie 
} from 'recharts';
import { 
  Trophy, 
  PieChart as PieChartIcon, 
  ClipboardList, 
  Camera, 
  BarChart,
  Database
} from 'lucide-react';
import html2canvas from 'html2canvas';

interface DashboardProps {
  records: AuditRecord[];
  actions: ActionItem[];
  onViewConsolidated: () => void;
  onViewActions: () => void;
  onGenerateDemo?: () => void;
}

export const Dashboard: React.FC<DashboardProps> = ({ records, actions, onViewConsolidated, onViewActions, onGenerateDemo }) => {
  const dashboardRef = useRef<HTMLDivElement>(null);

  if (!records || records.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-6 animate-fade-in bg-[#1e293b] rounded-3xl border border-gray-800 p-10">
        <div className="bg-[#0f172a] p-8 rounded-full border border-gray-700 shadow-2xl">
          <BarChart className="w-16 h-16 text-gray-500" />
        </div>
        <div className="max-w-md">
          <h2 className="text-2xl font-bold text-gray-100 mb-2">Dashboard sin datos</h2>
          <p className="text-gray-400 mb-6">Aún no se han realizado auditorías. Realiza una inspección o usa el botón de abajo para ver cómo se vería el panel.</p>
          <button 
            onClick={onGenerateDemo}
            className="flex items-center gap-2 mx-auto bg-gray-700 hover:bg-gray-600 text-white px-6 py-3 rounded-xl transition-all font-bold"
          >
            <Database className="w-5 h-5" /> Cargar Datos de Ejemplo
          </button>
        </div>
      </div>
    );
  }

  const areaStats: Record<string, { totalScore: number; count: number }> = {};
  records.forEach(r => {
    if (!areaStats[r.area]) areaStats[r.area] = { totalScore: 0, count: 0 };
    areaStats[r.area].totalScore += (r.score || 0);
    areaStats[r.area].count += 1;
  });

  const chartData = Object.entries(areaStats)
    .map(([area, stats]) => ({
      name: area,
      score: Math.round(stats.totalScore / stats.count),
      audits: stats.count
    }))
    .sort((a, b) => b.score - a.score);

  const averageScore = Math.round(records.reduce((acc, r) => acc + (r.score || 0), 0) / records.length);
  const openActions = actions.filter(a => a.status !== 'CLOSED').length;
  const closedActions = actions.filter(a => a.status === 'CLOSED').length;

  const chartHeight = Math.max(300, chartData.length * 40);
  const pieData = [
    { name: 'Cumplimiento', value: averageScore },
    { name: 'Faltante', value: Math.max(0, 100 - averageScore) }
  ];

  const handleCaptureScreenshot = async () => {
    if (dashboardRef.current) {
        try {
            window.scrollTo(0, 0);
            const canvas = await html2canvas(dashboardRef.current, {
                backgroundColor: '#121212',
                scale: 2,
                logging: false,
                useCORS: true
            });
            const link = document.createElement('a');
            link.download = `Dashboard_5S_${new Date().toLocaleDateString()}.png`;
            link.href = canvas.toDataURL('image/png');
            link.click();
        } catch (error) {
            console.error(error);
            alert("Error al generar imagen.");
        }
    }
  };

  const getBarColor = (score: number) => {
    if (score >= 90) return '#22c55e';
    if (score >= 70) return '#eab308';
    return '#ef4444';
  };

  return (
    <div className="space-y-6 pb-20 animate-fade-in" ref={dashboardRef}>
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div>
            <h2 className="text-2xl font-bold text-white tracking-tight">Panel de Indicadores</h2>
            <p className="text-sm text-gray-500">Resumen operativo 5S</p>
          </div>
          <button 
            onClick={handleCaptureScreenshot}
            className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl transition-all font-bold"
          >
            <Camera className="w-4 h-4" /> Exportar Imagen
          </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatItem label="Auditorías" value={records.length} color="text-white" />
        <StatItem label="Promedio" value={`${averageScore}%`} color={averageScore >= 80 ? 'text-green-400' : 'text-yellow-400'} />
        <StatItem label="Abiertas" value={openActions} color="text-red-400" />
        <StatItem label="Cerradas" value={closedActions} color="text-purple-400" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <button onClick={onViewConsolidated} className="p-6 bg-[#1e293b] border border-orange-500/20 rounded-2xl hover:border-orange-500/50 transition-all flex justify-between items-center group">
            <div className="text-left">
                <p className="text-orange-400 font-bold text-lg">Ver Hallazgos Críticos</p>
                <p className="text-xs text-gray-500">Preguntas con más fallos</p>
            </div>
            <PieChartIcon className="w-8 h-8 text-orange-500/40 group-hover:text-orange-500 transition-colors" />
        </button>
        <button onClick={onViewActions} className="p-6 bg-[#1e293b] border border-blue-500/20 rounded-2xl hover:border-blue-500/50 transition-all flex justify-between items-center group">
            <div className="text-left">
                <p className="text-blue-400 font-bold text-lg">Planes de Acción</p>
                <p className="text-xs text-gray-500">Seguimiento de tareas</p>
            </div>
            <ClipboardList className="w-8 h-8 text-blue-500/40 group-hover:text-blue-500 transition-colors" />
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="bg-[#1e293b] rounded-2xl border border-gray-800 p-6 flex flex-col items-center justify-center min-h-[350px]">
          <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-4">Cumplimiento Global</h3>
          <div className="relative w-full h-64">
              <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                      <Pie data={pieData} cx="50%" cy="50%" innerRadius={60} outerRadius={80} dataKey="value" stroke="none">
                          <Cell fill={getBarColor(averageScore)} />
                          <Cell fill="#0f172a" />
                      </Pie>
                  </PieChart>
              </ResponsiveContainer>
              <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <span className="text-4xl font-black text-white">{averageScore}%</span>
              </div>
          </div>
        </div>

        <div className="lg:col-span-2 bg-[#1e293b] rounded-2xl border border-gray-800 overflow-hidden">
          <div className="p-4 border-b border-gray-800 bg-[#0f172a]/30 flex items-center gap-2">
              <Trophy className="w-5 h-5 text-yellow-500" />
              <h3 className="text-sm font-bold text-white uppercase tracking-widest">Top Áreas</h3>
          </div>
          <div className="p-2 overflow-y-auto max-h-[300px]">
            {chartData.map((item, index) => (
              <div key={item.name} className="p-3 flex items-center justify-between hover:bg-white/5 rounded-lg">
                <div className="flex items-center gap-3">
                  <span className="text-xs font-bold text-gray-500 w-4">{index + 1}</span>
                  <span className="font-bold text-sm text-gray-200">{item.name}</span>
                </div>
                <span className={`px-2 py-1 rounded-md text-[10px] font-bold border ${item.score >= 90 ? 'text-green-400 border-green-900' : 'text-yellow-400 border-yellow-900'}`}>
                    {item.score}%
                </span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="bg-[#1e293b] rounded-2xl border border-gray-800 p-6">
        <h3 className="text-sm font-bold text-white uppercase tracking-widest mb-6 flex items-center gap-2">
            <BarChart className="w-4 h-4 text-blue-400" /> Rendimiento Detallado (%)
        </h3>
        <div className="w-full" style={{ height: `${chartHeight}px` }}>
          <ResponsiveContainer width="100%" height="100%">
            <ReBarChart data={chartData} layout="vertical">
              <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#334155" opacity={0.2} />
