import React, { useState, useEffect, useRef } from 'react';
import { ViewState, AuditRecord, ActionItem, AppConfig, Rating } from './types';
import { QUESTIONS, AREA_MAPPING, AREAS } from './constants';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ConsolidatedView } from './components/ConsolidatedView';
import { ActionPlanView } from './components/ActionPlanView';
import { SettingsView } from './components/SettingsView';
import { 
  ClipboardList, 
  Plus, 
  FileText, 
  BarChart, 
  Settings, 
  Home, 
  Camera 
} from 'lucide-react';

const DEFAULT_CONFIG: AppConfig = {
  questions: QUESTIONS,
  areas: AREAS,
  responsables: AREA_MAPPING.map(am => ({ name: am.responsable, area: am.area }))
};

const MenuButton = ({label, onClick, color, icon}: any) => {
    const colors: any = {
        green: 'border-green-500/30 text-green-400 shadow-green-500/10',
        blue: 'border-blue-500/30 text-blue-400 shadow-blue-500/10',
        purple: 'border-purple-500/30 text-purple-400 shadow-purple-500/10',
        orange: 'border-orange-500/30 text-orange-400 shadow-orange-500/10'
    };
    return (
        <button onClick={onClick} className={`flex flex-col items-center justify-center bg-[#1e293b] border p-6 rounded-2xl shadow-xl hover:bg-[#0f172a] transition-all transform hover:-translate-y-1 ${colors[color]}`}>
            {icon}
            <span className="text-lg font-bold mt-2">{label}</span>
        </button>
    );
};

const NavIcon = ({active, onClick, icon, title}: any) => (
    <button onClick={onClick} title={title} className={`p-2 rounded-lg transition-colors ${active ? 'bg-blue-600/20 text-blue-400' : 'text-gray-400 hover:bg-gray-800'}`}>
        {icon}
    </button>
);

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('home');
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [actions, setActions] = useState<ActionItem[]>([]);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);
  const isInitialLoad = useRef(true);

  useEffect(() => {
    const savedRecords = localStorage.getItem('audit_records');
    const savedActions = localStorage.getItem('audit_actions');
    const savedConfig = localStorage.getItem('audit_config');

    if (savedRecords) try { setRecords(JSON.parse(savedRecords) || []); } catch (e) { console.error(e); setRecords([]); }
    if (savedActions) try { setActions(JSON.parse(savedActions) || []); } catch (e) { console.error(e); setActions([]); }
    if (savedConfig) try { setConfig(JSON.parse(savedConfig) || DEFAULT_CONFIG); } catch (e) { console.error(e); setConfig(DEFAULT_CONFIG); }

    isInitialLoad.current = false;
  }, []);

  useEffect(() => {
    if (!isInitialLoad.current) {
      localStorage.setItem('audit_records', JSON.stringify(records));
      localStorage.setItem('audit_actions', JSON.stringify(actions));
      localStorage.setItem('audit_config', JSON.stringify(config));
    }
  }, [records, actions, config]);

  const handleSaveAudit = (record: AuditRecord, newActions: ActionItem[]) => {
    if (editingRecord) {
      setRecords(prev => (prev || []).map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...(prev || [])]);
      if (newActions && newActions.length > 0) {
        setActions(prev => [...newActions, ...(prev || [])]);
      }
    }
    // Pequeño delay para asegurar que el estado se actualizó antes del render del Dashboard
    setTimeout(() => setView('dashboard'), 10);
  };

  const loadDemoData = () => {
    const demoRecords: AuditRecord[] = config.areas.slice(0, 5).map((area, idx) => ({
        id: `demo-${idx}-${Date.now()}`,
        area,
        auditor: 'Demo Auditor',
        responsable: config.responsables.find(r => r.area === area)?.name || 'Admin',
        date: new Date().toISOString(),
        score: 65 + Math.floor(Math.random() * 30),
        answers: config.questions.map(q => ({ questionId: q.id, rating: Rating.SI }))
    }));
    setRecords(prev => [...demoRecords, ...(prev || [])]);
  };

  const renderContent = () => {
    switch (view) {
      case 'home':
        return (
          <div className="flex flex-col items-center justify-center space-y-8 animate-fade-in py-8 text-center">
            <h2 className="text-4xl font-black text-white mb-8 drop-shadow-lg tracking-tight">
              AuditCheck <span className="text-blue-500">Pro</span>
            </h2>
            <div className="flex flex-col gap-6 w-full max-w-md px-4">
              <MenuButton label="Nueva Auditoría" onClick={() => { setEditingRecord(null); setView('form'); }} color="green" icon={<Plus className="w-8 h-8" />} />
              <MenuButton label="Historial" onClick={() => setView('history')} color="blue" icon={<ClipboardList className="w-8 h-8" />} />
              <MenuButton label="Indicadores" onClick={() => setView('dashboard')} color="purple" icon={<BarChart className="w-8 h-8" />} />
              <MenuButton label="Consolidado" onClick={() => setView('consolidated')} color="orange" icon={<FileText className="w-8 h-8" />} />
            </div>
          </div>
        );
      case 'form':
        return <AuditForm initialData={editingRecord} config={config} onSave={handleSaveAudit} onCancel={() => setView('home')} />;
      case 'dashboard':
        return <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} onGenerateDemo={loadDemoData} />;
      case 'history':
        return <History records={records} actions={actions} onEdit={(r) => { setEditingRecord(r); setView('form'); }} onDelete={(id) => setRecords(prev => prev.filter(r => r.id !== id))} />;
      case 'consolidated':
        return <ConsolidatedView records={records} onBack={() => setView('home')} />;
      case 'actions':
        return <ActionPlanView actions={actions} onUpdateAction={(ua) => setActions(prev => prev.map(a => a.id === ua.id ? ua : a))} />;
      case 'settings':
        return <SettingsView config={config} onUpdateConfig={setConfig} />;
      case 'ai-editor':
        return <AIEditor />;
      default:
        return null;
    }
  };

  return (
    <div className="min-h-screen bg-[#0f172a] font-sans text-gray-100">
      <header className="bg-[#1e293b]/80 backdrop-blur-md border-b border-gray-800 shadow-xl sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={() => setView('home')}>
            <ClipboardList className="w-6 h-6 text-blue-500" />
            <h1 className="text-lg font-black tracking-tighter">AuditCheck</h1>
          </div>
          <nav className="flex items-center gap-1">
            <NavIcon active={view === 'home'} onClick={() => setView('home')} icon={<Home className="w-5 h-5" />} title="Inicio" />
            <NavIcon active={view === 'form'} onClick={() => { setEditingRecord(null); setView('form'); }} icon={<Plus className="w-5 h-5" />} title="Nueva" />
            <NavIcon active={view === 'dashboard'} onClick={() => setView('dashboard')} icon={<BarChart className="w-5 h-5" />} title="Dashboard" />
            <NavIcon active={view === 'settings'} onClick={() => setView('settings')} icon={<Settings className="w-5 h-5" />} title="Ajustes" />
            <NavIcon active={view === 'ai-editor'} onClick={() => setView('ai-editor')} icon={<Camera className="w-5 h-5" />} title="IA" />
          </nav>
        </div>
      </header>
      <main className="max-w-7xl mx-auto px-4 py-6">{renderContent()}</main>
    </div>
  );
};

export default App;

import React, { useRef, useMemo } from 'react';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Cell, LabelList,
  PieChart, Pie
} from 'recharts';
import { AuditRecord, ActionItem } from '../types';
import { 
  Trophy, 
  PieChart as PieIcon, 
  ClipboardList, 
  Camera, 
  BarChart as LucideBarChart,
  Database,
  TrendingUp
} from 'lucide-react';
import html2canvas from 'html2canvas';

interface DashboardProps {
  records: AuditRecord[];
  actions: ActionItem[];
  onViewConsolidated: () => void;
  onViewActions: () => void;
  onGenerateDemo?: () => void;
}

const StatCard = ({ label, value, color }: { label: string, value: string | number, color: string }) => (
    <div className="bg-[#1e293b] p-4 rounded-2xl border border-gray-800 shadow-sm">
        <p className="text-[10px] font-bold text-gray-500 uppercase tracking-wider mb-1">{label}</p>
        <p className={`text-2xl font-black ${color}`}>{value}</p>
    </div>
);

export const Dashboard: React.FC<DashboardProps> = ({ records = [], actions = [], onViewConsolidated, onViewActions, onGenerateDemo }) => {
  const dashboardRef = useRef<HTMLDivElement>(null);

  // Memoización de datos para evitar re-cálculos costosos y crashes
  const { chartData, averageScore, openActions, closedActions, pieData } = useMemo(() => {
    const safeRecords = Array.isArray(records) ? records : [];
    const safeActions = Array.isArray(actions) ? actions : [];

    const areaStats: Record<string, { totalScore: number; count: number }> = {};
    safeRecords.forEach(r => {
      const area = r.area || 'General';
      if (!areaStats[area]) areaStats[area] = { totalScore: 0, count: 0 };
      areaStats[area].totalScore += (Number(r.score) || 0);
      areaStats[area].count += 1;
    });

    const calculatedChartData = Object.entries(areaStats)
      .map(([area, stats]) => ({
        name: area,
        score: stats.count > 0 ? Math.round(stats.totalScore / stats.count) : 0,
        audits: stats.count
      }))
      .sort((a, b) => b.score - a.score);

    const totalScoreSum = safeRecords.reduce((acc, r) => acc + (Number(r.score) || 0), 0);
    const avg = safeRecords.length > 0 ? Math.round(totalScoreSum / safeRecords.length) : 0;

    return {
      chartData: calculatedChartData,
      averageScore: avg,
      openActions: safeActions.filter(a => a && a.status !== 'CLOSED').length,
      closedActions: safeActions.filter(a => a && a.status === 'CLOSED').length,
      pieData: [
        { name: 'Cumplimiento', value: avg },
        { name: 'Restante', value: Math.max(0, 100 - avg) }
      ]
    };
  }, [records, actions]);

  if (!records || records.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-6 animate-fade-in bg-[#1e293b] rounded-3xl border border-gray-800 p-10">
        <div className="bg-[#0f172a] p-8 rounded-full border border-gray-700 shadow-2xl">
          <LucideBarChart className="w-16 h-16 text-gray-500" />
        </div>
        <div className="max-w-md">
          <h2 className="text-2xl font-bold text-gray-100 mb-2">Dashboard sin datos</h2>
          <p className="text-gray-400 mb-6">Aún no se han realizado auditorías. Use el botón de abajo para cargar una demostración visual.</p>
          <button 
            onClick={onGenerateDemo}
            className="flex items-center gap-2 mx-auto bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-xl transition-all font-bold shadow-lg shadow-blue-500/20"
          >
            <Database className="w-5 h-5" /> Cargar Datos de Ejemplo
          </button>
        </div>
      </div>
    );
  }

  const getBarColor = (score: number) => {
    if (score >= 90) return '#22c55e';
    if (score >= 70) return '#eab308';
    return '#ef4444';
  };

  const handleCaptureScreenshot = async () => {
    if (!dashboardRef.current) return;
    try {
        const canvas = await html2canvas(dashboardRef.current, { backgroundColor: '#0f172a', scale: 2 });
        const link = document.createElement('a');
        link.download = `AuditCheck_Reporte_${new Date().toLocaleDateString()}.png`;
        link.href = canvas.toDataURL('image/png');
        link.click();
    } catch (e) { console.error(e); }
  };

  const chartHeight = Math.max(300, chartData.length * 45);

  return (
    <div className="space-y-6 pb-20 animate-fade-in" ref={dashboardRef}>
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
          <div>
            <h2 className="text-2xl font-bold text-white tracking-tight flex items-center gap-2">
                <TrendingUp className="text-blue-400" /> Panel de Indicadores
            </h2>
            <p className="text-sm text-gray-500">Estado actual del programa 5S</p>
          </div>
          <button 
            onClick={handleCaptureScreenshot}
            className="flex items-center gap-2 bg-[#1e293b] border border-gray-700 hover:bg-gray-800 text-white px-4 py-2 rounded-xl transition-all font-bold text-sm"
          >
            <Camera className="w-4 h-4" /> Capturar Vista
          </button>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
        <StatCard label="Auditorías" value={records.length} color="text-blue-400" />
        <StatCard label="Puntaje Global" value={`${averageScore}%`} color={averageScore >= 80 ? 'text-green-400' : 'text-yellow-400'} />
        <StatCard label="Pendientes" value={openActions} color="text-red-400" />
        <StatCard label="Cerradas" value={closedActions} color="text-purple-400" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <button onClick={onViewConsolidated} className="p-5 bg-[#1e293b] border border-orange-500/20 rounded-2xl hover:border-orange-500/50 transition-all flex justify-between items-center group text-left">
            <div>
                <p className="text-orange-400 font-bold text-lg">Debilidades Críticas</p>
                <p className="text-xs text-gray-500">Hallazgos recurrentes por pregunta</p>
            </div>
            <PieIcon className="w-8 h-8 text-orange-500/30 group-hover:text-orange-500 transition-colors" />
        </button>
        <button onClick={onViewActions} className="p-5 bg-[#1e293b] border border-blue-500/20 rounded-2xl hover:border-blue-500/50 transition-all flex justify-between items-center group text-left">
            <div>
                <p className="text-blue-400 font-bold text-lg">Planes de Mejora</p>
                <p className="text-xs text-gray-500">Seguimiento de acciones correctivas</p>
            </div>
            <ClipboardList className="w-8 h-8 text-blue-500/30 group-hover:text-blue-500 transition-colors" />
        </button>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Gráfico Cumplimiento */}
        <div className="bg-[#1e293b] rounded-2xl border border-gray-800 p-6 flex flex-col items-center justify-center min-h-[350px]">
          <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-4">Cumplimiento Global</h3>
          <div className="relative w-full h-64">
              <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                      <Pie data={pieData} cx="50%" cy="50%" innerRadius={60} outerRadius={85} dataKey="value" stroke="none" startAngle={90} endAngle={-270}>
                          <Cell fill={getBarColor(averageScore)} />
                          <Cell fill="#0f172a" />
                      </Pie>
                  </PieChart>
              </ResponsiveContainer>
              <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <span className="text-5xl font-black text-white">{averageScore}%</span>
                  <span className="text-[10px] text-gray-500 font-bold uppercase">Meta 95%</span>
              </div>
          </div>
        </div>

        {/* Ranking */}
        <div className="lg:col-span-2 bg-[#1e293b] rounded-2xl border border-gray-800 overflow-hidden">
          <div className="p-4 border-b border-gray-800 bg-[#0f172a]/30 flex items-center gap-2">
              <Trophy className="w-5 h-5 text-yellow-500" />
              <h3 className="text-sm font-bold text-white uppercase tracking-widest">Desempeño por Áreas</h3>
          </div>
          <div className="p-2 overflow-y-auto max-h-[300px] divide-y divide-gray-800/50">
            {chartData.map((item, index) => (
              <div key={item.name} className="p-4 flex items-center justify-between hover:bg-white/5 transition-colors">
                <div className="flex items-center gap-4">
                  <span className={`w-6 h-6 rounded flex items-center justify-center text-xs font-bold ${index < 3 ? 'bg-yellow-500/20 text-yellow-500' : 'bg-gray-800 text-gray-500'}`}>
                    {index + 1}
                  </span>
                  <span className="font-bold text-sm text-gray-100">{item.name}</span>
                </div>
                <div className="flex items-center gap-3">
                    <span className={`px-2 py-1 rounded-md text-[10px] font-bold border ${item.score >= 85 ? 'text-green-400 border-green-900/50 bg-green-900/10' : 'text-yellow-400 border-yellow-900/50 bg-yellow-900/10'}`}>
                        {item.score}%
                    </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Gráfico Detallado */}
      <div className="bg-[#1e293b] rounded-2xl border border-gray-800 p-6">
        <h3 className="text-sm font-bold text-white uppercase tracking-widest mb-6">Comparativa Detallada (%)</h3>
        <div className="w-full" style={{ height: `${chartHeight}px` }}>
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} layout="vertical" margin={{ left: 10, right: 40, top: 0, bottom: 0 }}>
              <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#334155" opacity={0.2} />
              <XAxis type="number" domain={[0, 100]} hide />
              <YAxis dataKey="name" type="category" width={110} tick={{fontSize: 10, fill: '#94a3b8', fontWeight: 'bold'}} axisLine={false} tickLine={false} />
              <Tooltip cursor={{fill: 'rgba(255,255,255,0.05)'}} contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #374151', borderRadius: '8px', color: '#fff' }} />
              <Bar dataKey="score" radius={[0, 4, 4, 0]} barSize={20}>
                  {chartData.map((entry, index) => <Cell key={index} fill={getBarColor(entry.score)} />)}
                  <LabelList dataKey="score" position="right" formatter={(v: any) => `${v}%`} style={{ fontSize: '10px', fill: '#cbd5e1', fontWeight: 'bold' }} offset={10} />
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

