export const Dashboard: React.FC<DashboardProps> = ({ records = [], actions = [], onViewConsolidated, onViewActions, onGenerateDemo }) => {
  const [isReady, setIsReady] = useState(false);
  const dashboardRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const timer = setTimeout(() => setIsReady(true), 200);
    return () => clearTimeout(timer);
  }, [records.length]);

  const handleCaptureScreenshot = async () => {
    if (dashboardRef.current) {
        try {
            const canvas = await html2canvas(dashboardRef.current, {
                backgroundColor: '#0f172a',
                scale: 2,
                logging: false,
                useCORS: true
            });
            const link = document.createElement('a');
            link.download = `Dashboard_Planta_${new Date().toISOString().split('T')[0]}.png`;
            link.href = canvas.toDataURL('image/png');
            link.click();
        } catch (error) {
            console.error("Error capturando dashboard:", error);
            alert("Error al capturar la imagen. Intente nuevamente.");
        }
    }
  };

  const safeRecords = useMemo(() => Array.isArray(records) ? records : [], [records]);
  const safeActions = useMemo(() => Array.isArray(actions) ? actions : [], [actions]);

  const stats = useMemo(() => {
    if (safeRecords.length === 0) return null;

    try {
      const areaMap: Record<string, { total: number; count: number }> = {};

      safeRecords.forEach(r => {
        if (!r) return;
        const areaName = r.area || 'Sin Área';
        if (!areaMap[areaName]) areaMap[areaName] = { total: 0, count: 0 };

        const scoreVal = parseFloat(String(r.score || 0));
        areaMap[areaName].total += isNaN(scoreVal) ? 0 : scoreVal;
        areaMap[areaName].count += 1;
      });

      const calculatedChartData = Object.entries(areaMap)
        .map(([name, s]) => ({
          name,
          score: s.count > 0 ? Math.round(s.total / s.count) : 0,
          audits: s.count
        }))
        .sort((a, b) => b.score - a.score);

      const totalSum = safeRecords.reduce((acc, r) => {
        const val = parseFloat(String(r?.score || 0));
        return acc + (isNaN(val) ? 0 : val);
      }, 0);

      const finalAvg = safeRecords.length > 0 ? Math.round(totalSum / safeRecords.length) : 0;

      return {
        chartData: calculatedChartData,
        averageScore: finalAvg,
        openActions: safeActions.filter(a => a && a.status !== 'CLOSED').length,
        closedActions: safeActions.filter(a => a && a.status === 'CLOSED').length,
        pieData: [
          { name: 'Cumplimiento', value: finalAvg },
          { name: 'Brecha', value: Math.max(0, 100 - finalAvg) }
        ]
      };
    } catch (e) {
      console.error("Dashboard calculation error:", e);
      return null;
    }
  }, [safeRecords, safeActions]);

  if (!stats || !isReady || stats.chartData.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center min-h-[60vh] text-center space-y-6 animate-fade-in bg-[#1e293b]/50 rounded-3xl border border-gray-800 p-12">
        <div className="bg-[#0f172a] p-10 rounded-full border border-gray-700 shadow-2xl">
          <LucideBarChart className="w-20 h-20 text-blue-500/50" />
        </div>
        <div className="max-w-md">
          <h2 className="text-2xl font-bold text-white mb-2">Esperando Auditorías...</h2>
          <p className="text-gray-400 mb-8 text-sm">Realice su primera inspección o cargue datos de prueba para visualizar el desempeño de planta.</p>
          <button 
            onClick={onGenerateDemo}
            className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-8 py-4 rounded-2xl transition-all font-bold shadow-lg shadow-blue-600/20"
          >
            <Database className="w-5 h-5" /> Generar Datos de Ejemplo
          </button>
        </div>
      </div>
    );
  }

  const { chartData, averageScore, openActions, closedActions, pieData } = stats;

  const getBarColor = (score: number) => {
    if (score >= 90) return '#22c55e';
    if (score >= 75) return '#eab308';
    return '#ef4444';
  };

  return (
    <div className="space-y-6 pb-24 animate-fade-in" ref={dashboardRef}>
      <div className="flex flex-col lg:flex-row lg:items-center justify-between gap-4">
        <h2 className="text-3xl font-black text-white flex items-center gap-3 tracking-tighter">
            <TrendingUp className="text-blue-500" /> DASHBOARD DE PLANTA
        </h2>
        <div className="flex flex-wrap items-center gap-2">
            <button 
              onClick={handleCaptureScreenshot}
              className="flex items-center gap-2 bg-purple-600/10 text-purple-400 border border-purple-500/30 px-4 py-2 rounded-xl text-xs font-bold hover:bg-purple-600 hover:text-white transition-all"
              title="Descargar imagen del dashboard"
            >
                <Camera className="w-4 h-4" /> Capturar
            </button>
            <button 
              onClick={onViewConsolidated}
              className="flex items-center gap-2 bg-blue-600/10 text-blue-400 border border-blue-500/30 px-4 py-2 rounded-xl text-xs font-bold hover:bg-blue-600 hover:text-white transition-all"
            >
                <SearchCode className="w-4 h-4" /> Análisis Consolidado
            </button>
            <button 
              onClick={onViewActions}
              className="flex items-center gap-2 bg-amber-600/10 text-amber-400 border border-amber-500/30 px-4 py-2 rounded-xl text-xs font-bold hover:bg-amber-600 hover:text-white transition-all"
            >
                <ListChecks className="w-4 h-4" /> Plan de Acción
            </button>
        </div>
      </div>

      <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
        <StatCard label="Auditorías" value={safeRecords.length} color="text-blue-400" icon={ClipboardList} />
        <StatCard label="Global" value={`${averageScore}%`} color={averageScore >= 80 ? 'text-green-400' : 'text-yellow-400'} icon={Target} />
        <StatCard 
          label="Hallazgos Pendientes" 
          value={openActions} 
          color="text-red-400" 
          icon={AlertTriangle} 
          onClick={onViewActions}
        />
        <StatCard label="Cerrados" value={closedActions} color="text-purple-400" icon={Trophy} />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="bg-[#1e293b] rounded-2xl border border-gray-800 p-8 flex flex-col items-center justify-center min-h-[400px]">
          <h3 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-8">Nivel de Calidad</h3>
          <div className="relative w-full h-72">
              <Recharts.ResponsiveContainer width="100%" height="100%">
                  <Recharts.PieChart>
                      <Recharts.Pie 
                        data={pieData} 
                        cx="50%" cy="50%" 
                        innerRadius={80} outerRadius={110} 
                        dataKey="value" stroke="none" 
                        startAngle={90} endAngle={-270}
                      >
                          <Recharts.Cell fill={getBarColor(averageScore)} />
                          <Recharts.Cell fill="#0f172a" />
                      </Recharts.Pie>
                  </Recharts.PieChart>
              </Recharts.ResponsiveContainer>
              <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none">
                  <span className="text-6xl font-black text-white leading-none">{averageScore}%</span>
                  <span className="text-[10px] text-gray-500 font-bold uppercase tracking-tighter mt-2">Planta Global</span>
              </div>
          </div>
        </div>

        <div className="lg:col-span-2 bg-[#1e293b] rounded-2xl border border-gray-800 p-8 shadow-2xl">
          <h3 className="text-sm font-bold text-white uppercase tracking-widest mb-8">Desempeño por Área (%)</h3>
          <div className="w-full" style={{ height: '300px' }}>
            <Recharts.ResponsiveContainer width="100%" height="100%">
              <Recharts.BarChart data={chartData} layout="vertical" margin={{ left: 10, right: 45 }}>
                <Recharts.XAxis type="number" domain={[0, 100]} hide />
                <Recharts.YAxis dataKey="name" type="category" width={120} tick={{fontSize: 11, fill: '#94a3b8'}} axisLine={false} tickLine={false} />
                <Recharts.Tooltip 
                  cursor={{fill: 'rgba(255,255,255,0.05)'}}
                  contentStyle={{ backgroundColor: '#0f172a', border: '1px solid #334155', borderRadius: '12px' }} 
                />
                <Recharts.Bar dataKey="score" radius={[0, 6, 6, 0]} barSize={24}>
                    {chartData.map((entry, index) => <Recharts.Cell key={`cell-${index}`} fill={getBarColor(entry.score)} />)}
                </Recharts.Bar>
              </Recharts.BarChart>
            </Recharts.ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export enum Rating {
  SI = 'SI',
  NO = 'NO',
  PARCIAL = 'PARCIAL',
  NA = 'N/A'
}

export interface Question {
  id: number;
  text: string;
}

export interface Answer {
  questionId: number;
  rating: Rating;
}

export interface AuditRecord {
  id: string;
  area: string;
  auditor: string;
  responsable?: string;
  date: string;
  answers: Answer[];
  score: number;
}

export type ActionStatus = 'PENDING' | 'IN_PROGRESS' | 'CLOSED';

export interface ActionItem {
  id: string;
  auditId: string;
  area: string;
  questionId: number;
  questionText: string;
  issueType: 'NO'; // Restringido solo a NO
  suggestedAction: string;
  responsable: string;
  dueDate: string;
  status: ActionStatus;
  comments?: string;
  createdAt: string;
}

export interface AppConfig {
  areas: string[];
  responsables: { name: string; area?: string }[];
  questions: Question[];
}

export type ViewState = 'home' | 'form' | 'dashboard' | 'history' | 'ai-editor' | 'consolidated' | 'actions' | 'settings';

import React, { useState, useEffect } from 'react';
import { Rating, Answer, AuditRecord, AppConfig, ActionItem } from '../types';
import { Save, User, MapPin, ClipboardCheck, Calendar, UserCircle, X } from 'lucide-react';

interface AuditFormProps {
  initialData?: AuditRecord | null;
  config: AppConfig;
  onSave: (record: AuditRecord, newActions: ActionItem[]) => void;
  onCancel: () => void;
}

export const AuditForm: React.FC<AuditFormProps> = ({ initialData, config, onSave, onCancel }) => {
  const [area, setArea] = useState(config.areas[0] || '');
  const [auditor, setAuditor] = useState('');
  const [responsable, setResponsable] = useState('');
  const [auditDate, setAuditDate] = useState(new Date().toISOString().split('T')[0]);
  const [answers, setAnswers] = useState<Record<number, Rating>>({});

  useEffect(() => {
    if (initialData) {
      setArea(initialData.area);
      setAuditor(initialData.auditor);
      setResponsable(initialData.responsable || getResponsableForArea(initialData.area));
      setAuditDate(initialData.date.split('T')[0]);
      const loadedAnswers: Record<number, Rating> = {};
      initialData.answers.forEach(a => { loadedAnswers[a.questionId] = a.rating; });
      setAnswers(loadedAnswers);
    } else {
      if (config.areas.length > 0) {
        const defaultArea = config.areas[0];
        setArea(defaultArea);
        setResponsable(getResponsableForArea(defaultArea));
      }
      setAuditDate(new Date().toISOString().split('T')[0]);
      const savedAuditor = localStorage.getItem('last_auditor_name');
      if (savedAuditor) setAuditor(savedAuditor);
    }
  }, [initialData, config]);

  useEffect(() => {
    if (!initialData || (initialData && area !== initialData.area)) {
       setResponsable(getResponsableForArea(area));
    }
  }, [area, initialData, config.responsables]);

  const getResponsableForArea = (areaName: string) => {
    const found = config.responsables.find(r => r.area === areaName);
    return found ? found.name : '';
  };

  const handleRatingChange = (questionId: number, rating: Rating) => {
    setAnswers(prev => ({ ...prev, [questionId]: rating }));
  };

  const calculateScore = () => {
    let totalPoints = 0;
    let maxPoints = 0;
    Object.values(answers).forEach(rating => {
      if (rating === Rating.SI) { totalPoints += 1; maxPoints += 1; }
      else if (rating === Rating.PARCIAL) { totalPoints += 0.5; maxPoints += 1; }
      else if (rating === Rating.NO) { maxPoints += 1; }
    });
    return maxPoints === 0 ? 0 : Math.round((totalPoints / maxPoints) * 100);
  };

  const currentScore = calculateScore();

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!auditor.trim()) { alert("Por favor ingrese el nombre del auditor"); return; }
    localStorage.setItem('last_auditor_name', auditor);

    const answerList: Answer[] = Object.entries(answers).map(([qId, rating]) => ({
      questionId: parseInt(qId),
      rating: rating as Rating
    }));

    const newId = initialData ? initialData.id : crypto.randomUUID();
    const [year, month, day] = auditDate.split('-').map(Number);
    const dateObj = new Date(year, month - 1, day); 

    const record: AuditRecord = {
      id: newId, area, auditor, responsable, date: dateObj.toISOString(), answers: answerList, score: currentScore,
    };

    const newActions: ActionItem[] = [];

    // Generación de acciones: SOLO para respuestas "NO"
    answerList.forEach(ans => {
        if (ans.rating === Rating.NO) {
            const q = config.questions.find(q => q.id === ans.questionId);
            if (q) {
                const dueDate = new Date(dateObj); 
                dueDate.setDate(dueDate.getDate() + 7);
                newActions.push({
                    id: crypto.randomUUID(),
                    auditId: newId,
                    area: area,
                    questionId: q.id,
                    questionText: q.text,
                    issueType: 'NO',
                    suggestedAction: `Corregir hallazgo crítico: "${q.text}"`,
                    responsable: responsable,
                    dueDate: dueDate.toISOString(),
                    status: 'PENDING',
                    createdAt: new Date().toISOString()
                });
            }
        }
    });

    onSave(record, newActions);
  };

  const getRatingColorClass = (rating: Rating, isSelected: boolean) => {
    if (!isSelected) return 'bg-[#0f172a] border-gray-700 text-gray-500 hover:bg-gray-800';
    switch (rating) {
      case Rating.SI: return 'bg-green-600 border-green-600 text-white shadow-[0_0_10px_rgba(34,197,94,0.3)]';
      case Rating.NO: return 'bg-red-600 border-red-600 text-white shadow-[0_0_10px_rgba(239,68,68,0.3)]';
      case Rating.PARCIAL: return 'bg-yellow-500 border-yellow-500 text-white shadow-[0_0_10px_rgba(234,179,8,0.3)]';
      case Rating.NA: return 'bg-gray-600 border-gray-600 text-white';
      default: return '';
    }
  };

  return (
    <div className="max-w-4xl mx-auto mb-24 animate-fade-in">
      <div className="flex items-center justify-between mb-6">
        <div>
          <h2 className="text-2xl font-bold text-gray-100">{initialData ? 'Editar Auditoría' : 'Nueva Auditoría'}</h2>
          <p className="text-xs text-gray-500 mt-1 uppercase tracking-widest font-bold">Solo las respuestas "NO" generarán plan de acción.</p>
        </div>
        <div className={`px-4 py-2 rounded-xl font-bold text-lg border ${
            currentScore >= 90 ? 'bg-green-900/20 text-green-400 border-green-500/30' :
            currentScore >= 70 ? 'bg-yellow-900/20 text-yellow-400 border-yellow-500/30' :
            'bg-red-900/20 text-red-400 border-red-500/30'
        }`}>
            {currentScore}% pts
        </div>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div className="bg-[#1e293b] rounded-2xl shadow-xl border border-gray-700 p-6">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
             <div className="space-y-2">
              <label className="text-xs font-bold text-gray-400 uppercase tracking-widest flex items-center gap-2">
                <Calendar className="w-4 h-4" /> Fecha de Auditoría
              </label>
              <input type="date" value={auditDate} onChange={(e) => setAuditDate(e.target.value)} className="w-full bg-[#0f172a] border border-gray-700 text-white rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none" required />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-400 uppercase tracking-widest flex items-center gap-2">
                <MapPin className="w-4 h-4 text-blue-400" /> Área a Evaluar
              </label>
              <select value={area} onChange={(e) => setArea(e.target.value)} className="w-full bg-[#0f172a] border border-gray-700 text-white rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none">
                {config.areas.map(a => <option key={a} value={a}>{a}</option>)}
              </select>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-400 uppercase tracking-widest flex items-center gap-2">
                <UserCircle className="w-4 h-4 text-purple-400" /> Responsable del Área
              </label>
              <input type="text" value={responsable} readOnly className="w-full bg-[#0f172a]/50 border border-gray-800 text-gray-400 rounded-xl p-3 font-medium cursor-not-allowed" />
            </div>

            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-400 uppercase tracking-widest flex items-center gap-2">
                <User className="w-4 h-4 text-gray-400" /> Nombre del Auditor
              </label>
              <input type="text" value={auditor} onChange={(e) => setAuditor(e.target.value)} placeholder="Su nombre completo" className="w-full bg-[#0f172a] border border-gray-700 text-white rounded-xl p-3 focus:ring-2 focus:ring-blue-500 outline-none" required />
            </div>
          </div>
        </div>

        <div className="space-y-3">
          {config.questions.map((q, index) => (
            <div key={q.id} className={`p-5 rounded-2xl border shadow-sm transition-all hover:bg-[#1e293b]/80 ${answers[q.id] === Rating.NO ? 'bg-red-900/10 border-red-500/30' : 'bg-[#1e293b] border-gray-800'}`}>
              <div className="flex justify-between items-start mb-4">
                <p className="text-gray-200 font-medium flex gap-3">
                    <span className="text-blue-500 font-bold">{index + 1}.</span> {q.text}
                </p>
                {answers[q.id] === Rating.NO && <span className="text-[10px] font-black text-red-500 uppercase bg-red-500/10 px-2 py-1 rounded">Genera Acción Correctiva</span>}
              </div>
              <div className="grid grid-cols-2 sm:grid-cols-4 gap-3 ml-6">
                {Object.values(Rating).map((rating) => (
                  <button key={rating} type="button" onClick={() => handleRatingChange(q.id, rating)} className={`py-2.5 px-3 rounded-xl border text-xs font-bold transition-all ${getRatingColorClass(rating, answers[q.id] === rating)}`}>
                    {rating}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>

        <div className="flex justify-end gap-4 sticky bottom-20 z-10 p-2 bg-[#0f172a]/80 backdrop-blur rounded-2xl border border-gray-800 shadow-2xl">
          <button type="button" onClick={onCancel} className="px-6 py-3 bg-[#1e293b] border border-gray-700 text-gray-300 rounded-xl hover:bg-gray-800 font-bold transition-all flex items-center gap-2">
            <X className="w-5 h-5" /> Cancelar
          </button>
          <button type="submit" className="px-8 py-3 bg-blue-600 text-white rounded-xl hover:bg-blue-700 font-bold shadow-lg shadow-blue-500/20 transition-all flex items-center gap-2">
            <Save className="w-5 h-5" /> Guardar Auditoría
          </button>
        </div>
      </form>
    </div>
  );
};

import React from 'react';
import { AuditRecord, ActionItem } from '../types';
import * as XLSX from 'xlsx';
import { Edit2, Trash2, FileSpreadsheet, Calendar, Share, Download } from 'lucide-react';

interface HistoryProps {
  records: AuditRecord[];
  actions: ActionItem[];
  onEdit: (record: AuditRecord) => void;
  onDelete: (id: string) => void;
}

export const History: React.FC<HistoryProps> = ({ records, actions, onEdit, onDelete }) => {

  const handleExportExcel = () => {
    // 1. Preparar datos de Auditorías
    const auditData = records.map(r => {
      const row: any = {
        'ID_Auditoria': r.id,
        'Fecha': new Date(r.date).toLocaleDateString(),
        'Area': r.area,
        'Responsable_Area': r.responsable || 'N/A',
        'Auditor': r.auditor,
        'Puntaje_Final': r.score
      };
      // Añadir respuestas individuales
      r.answers.forEach(a => { row[`Pregunta_${a.questionId}`] = a.rating; });
      return row;
    });

    // 2. Preparar datos del Plan de Acción
    const actionData = actions.map(a => ({
      'ID_Auditoria_Origen': a.auditId,
      'ID_Accion': a.id,
      'Area': a.area,
      'Hallazgo_Critico': a.questionText,
      'Accion_Sugerida': a.suggestedAction,
      'Responsable_Seguimiento': a.responsable,
      'Fecha_Vencimiento': new Date(a.dueDate).toLocaleDateString(),
      'Estado_Actual': a.status === 'PENDING' ? 'Pendiente' : a.status === 'IN_PROGRESS' ? 'En Proceso' : 'Cerrado',
      'Fecha_Registro': new Date(a.createdAt).toLocaleDateString()
    }));

    // 3. Crear el libro y las hojas
    const wb = XLSX.utils.book_new();

    const wsAudits = XLSX.utils.json_to_sheet(auditData);
    const wsActions = XLSX.utils.json_to_sheet(actionData);

    // 4. Adjuntar hojas al libro
    XLSX.utils.book_append_sheet(wb, wsAudits, "Auditorias");
    XLSX.utils.book_append_sheet(wb, wsActions, "Plan_de_Accion");

    // 5. Descargar archivo
    XLSX.writeFile(wb, `Reporte_Operativo_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const getScoreBadge = (score: number) => {
    let colorClass = score >= 90 ? 'bg-green-900/30 text-green-400 border-green-500/30' : 
                     score >= 70 ? 'bg-yellow-900/30 text-yellow-400 border-yellow-500/30' : 
                     'bg-red-900/30 text-red-400 border-red-500/30';
    return <span className={`px-2.5 py-0.5 text-xs font-bold rounded-full border ${colorClass}`}>{score}%</span>;
  };

  return (
    <div className="space-y-6 mb-24 animate-fade-in">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 bg-[#1e293b] p-6 rounded-2xl shadow-lg border border-gray-700">
        <div>
          <h2 className="text-2xl font-bold text-gray-100">Reportes Corporativos</h2>
          <p className="text-sm text-gray-400">Descargue el consolidado de auditorías y planes de acción para SharePoint.</p>
        </div>
        <button 
          onClick={handleExportExcel}
          className="flex items-center gap-2 bg-[#107c41] hover:bg-[#0b5c30] text-white px-6 py-3 rounded-xl transition-all font-bold shadow-lg w-full sm:w-auto justify-center group"
        >
          <Download className="w-5 h-5 group-hover:translate-y-0.5 transition-transform" /> 
          Exportar Reporte Completo
        </button>
      </div>

      <div className="bg-blue-900/20 border border-blue-500/30 p-4 rounded-xl flex items-start gap-3">
        <Share className="w-5 h-5 text-blue-400 mt-0.5" />
        <div className="text-xs text-gray-300">
            <span className="font-bold text-blue-300">Nota para SharePoint:</span> 
            <p>El archivo contiene dos pestañas. Puede importar la pestaña <code className="text-blue-200">Plan_de_Accion</code> directamente a una lista de SharePoint para dar seguimiento a los hallazgos críticos.</p>
        </div>
      </div>

      <div className="bg-[#1e293b] rounded-2xl shadow-lg border border-gray-700 overflow-hidden">
        <div className="p-4 bg-[#0f172a] border-b border-gray-800 flex items-center gap-2">
            <Calendar className="w-4 h-4 text-gray-500" />
            <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest">Historial de Evaluaciones</h3>
        </div>
        <div className="overflow-x-auto">
          <table className="min-w-full divide-y divide-gray-800">
            <thead className="bg-[#0f172a]">
              <tr>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase">Fecha</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase">Área</th>
                <th className="px-6 py-4 text-left text-xs font-bold text-gray-500 uppercase">Score</th>
                <th className="px-6 py-4 text-right text-xs font-bold text-gray-500 uppercase">Acción</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-800">
              {records.length === 0 ? (
                <tr>
                  <td colSpan={4} className="px-6 py-10 text-center text-gray-500 italic">No hay registros disponibles.</td>
                </tr>
              ) : (
                records.map((r) => (
                  <tr key={r.id} className="hover:bg-white/5 transition-colors group">
                    <td className="px-6 py-4 text-sm text-gray-400">{new Date(r.date).toLocaleDateString()}</td>
                    <td className="px-6 py-4 text-sm font-bold text-white">{r.area}</td>
                    <td className="px-6 py-4">{getScoreBadge(r.score)}</td>
                    <td className="px-6 py-4 text-right flex justify-end gap-2">
                      <button 
                        onClick={() => onEdit(r)} 
                        title="Editar auditoría"
                        className="text-blue-400 hover:bg-blue-400/10 p-2 rounded-lg transition-all"
                      >
                        <Edit2 className="w-4 h-4" />
                      </button>
                      <button 
                        onClick={() => {
                          if (confirm('¿Está seguro de eliminar esta auditoría?')) {
                            onDelete(r.id);
                          }
                        }} 
                        title="Eliminar registro"
                        className="text-red-500 hover:bg-red-500/10 p-2 rounded-lg transition-all"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { ViewState, AuditRecord, ActionItem, AppConfig, Rating } from './types';
import { QUESTIONS, AREA_MAPPING, AREAS } from './constants';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ConsolidatedView } from './components/ConsolidatedView';
import { ActionPlanView } from './components/ActionPlanView';
import { SettingsView } from './components/SettingsView';
import { 
  ClipboardList, 
  Plus, 
  FileText, 
  BarChart, 
  Settings, 
  Home, 
  Camera,
  Loader2,
  ListChecks
} from 'lucide-react';

const DEFAULT_CONFIG: AppConfig = {
  questions: QUESTIONS,
  areas: AREAS,
  responsables: AREA_MAPPING.map(am => ({ name: am.responsable, area: am.area }))
};

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('home');
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [actions, setActions] = useState<ActionItem[]>([]);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);

  useEffect(() => {
    const loadData = () => {
        try {
            const r = localStorage.getItem('audit_records');
            const a = localStorage.getItem('audit_actions');
            const c = localStorage.getItem('audit_config');
            if (r) setRecords(JSON.parse(r));
            if (a) setActions(JSON.parse(a));
            if (c) setConfig(JSON.parse(c));
        } catch (e) {
            console.error("Fallo al cargar estado local:", e);
        } finally {
            setIsInitializing(false);
        }
    };
    loadData();
  }, []);

  useEffect(() => {
    if (!isInitializing) {
        localStorage.setItem('audit_records', JSON.stringify(records));
        localStorage.setItem('audit_actions', JSON.stringify(actions));
        localStorage.setItem('audit_config', JSON.stringify(config));
    }
  }, [records, actions, config, isInitializing]);

  const handleSaveAudit = useCallback((record: AuditRecord, newActions: ActionItem[]) => {
    if (editingRecord) {
      setRecords(prev => prev.map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...prev]);
      if (newActions.length > 0) {
        setActions(prev => [...newActions, ...prev]);
      }
    }
    setView('dashboard');
  }, [editingRecord]);

  const handleDeleteAction = (actionId: string) => {
    setActions(prev => prev.filter(a => a.id !== actionId));
  };

  const handleClearActions = () => {
    setActions([]);
  };

  const generateDemo = () => {
    const demo = config.areas.slice(0, 8).map((area, i) => ({
        id: `demo-${i}-${Date.now()}`,
        area,
        auditor: 'Admin Demo',
        responsable: config.responsables.find(r => r.area === area)?.name || 'N/A',
        date: new Date().toISOString(),
        score: 70 + Math.floor(Math.random() * 25),
        answers: config.questions.map(q => ({ questionId: q.id, rating: Rating.SI }))
    }));
    setRecords(demo);
    setView('dashboard');
  };

  const NavIcon = ({active, onClick, icon: Icon, title}: any) => (
    <button 
      onClick={onClick} 
      title={title}
      className={`p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 ${active ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-gray-500 hover:bg-gray-800 hover:text-gray-300'}`}
    >
        <Icon className="w-5 h-5" />
        <span className="text-[9px] font-bold uppercase tracking-tighter sm:hidden">{title}</span>
    </button>
  );

  if (isInitializing) {
    return (
        <div className="min-h-screen bg-[#0f172a] flex flex-col items-center justify-center gap-4">
            <Loader2 className="w-12 h-12 text-blue-500 animate-spin" />
            <p className="text-blue-500 font-black tracking-widest text-xs uppercase">Cargando Sistema...</p>
        </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0f172a] text-gray-100 flex flex-col">
      <header className="bg-[#1e293b]/90 backdrop-blur-xl border-b border-gray-800 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setView('home')}>
            <div className="bg-blue-600 p-2 rounded-lg group-hover:scale-110 transition-transform">
                <ClipboardList className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-xl font-black tracking-tighter">Audit<span className="text-blue-500">Check</span></h1>
          </div>
          <nav className="flex items-center gap-1 sm:gap-2">
            <NavIcon active={view === 'home'} onClick={() => setView('home')} icon={Home} title="Inicio" />
            <NavIcon active={view === 'form'} onClick={() => { setEditingRecord(null); setView('form'); }} icon={Plus} title="Auditar" />
            <NavIcon active={view === 'dashboard' || view === 'consolidated'} onClick={() => setView('dashboard')} icon={BarChart} title="Métricas" />
            <NavIcon active={view === 'actions'} onClick={() => setView('actions')} icon={ListChecks} title="Planes" />
            <NavIcon active={view === 'history'} onClick={() => setView('history')} icon={FileText} title="Historial" />
            <NavIcon active={view === 'ai-editor'} onClick={() => setView('ai-editor')} icon={Camera} title="IA" />
            <NavIcon active={view === 'settings'} onClick={() => setView('settings')} icon={Settings} title="Ajustes" />
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 w-full flex-1">
        {view === 'home' && (
          <div className="max-w-xl mx-auto py-12 space-y-8 animate-fade-in">
             <div className="text-center space-y-2">
                <h2 className="text-5xl font-black text-white leading-tight">Gestión Operativa <br/><span className="text-blue-500 underline decoration-blue-500/30">Sin Papel</span></h2>
                <p className="text-gray-500 text-lg">Digitalice sus auditorías 5S y controle su planta en tiempo real.</p>
             </div>
             <div className="grid grid-cols-1 gap-4">
                <button onClick={() => { setEditingRecord(null); setView('form'); }} className="flex items-center justify-between p-8 bg-[#1e293b] border border-green-500/20 rounded-3xl hover:border-green-500/50 hover:bg-[#1e293b]/80 transition-all shadow-xl group">
                    <div className="flex items-center gap-6">
                        <div className="bg-green-600/10 p-4 rounded-2xl group-hover:bg-green-600/20 transition-colors">
                            <Plus className="w-10 h-10 text-green-500" />
                        </div>
                        <div className="text-left">
                            <p className="text-2xl font-black text-white">Nueva Auditoría</p>
                            <p className="text-sm text-gray-500">Iniciar inspección de área ahora</p>
                        </div>
                    </div>
                </button>
                <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => setView('dashboard')} className="p-6 bg-[#1e293b] border border-blue-500/20 rounded-3xl hover:border-blue-500/50 transition-all text-left">
                        <BarChart className="w-8 h-8 text-blue-500 mb-4" />
                        <p className="text-lg font-bold">Indicadores</p>
                        <p className="text-xs text-gray-500">Métricas de planta</p>
                    </button>
                    <button onClick={() => setView('actions')} className="p-6 bg-[#1e293b] border border-amber-500/20 rounded-3xl hover:border-amber-500/50 transition-all text-left">
                        <ListChecks className="w-8 h-8 text-amber-500 mb-4" />
                        <p className="text-lg font-bold">Planes de Acción</p>
                        <p className="text-xs text-gray-500">Hallazgos y tareas</p>
                    </button>
                </div>
             </div>
          </div>
        )}
        {view === 'form' && <AuditForm initialData={editingRecord} config={config} onSave={handleSaveAudit} onCancel={() => setView('home')} />}
        {view === 'dashboard' && <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} onGenerateDemo={generateDemo} />}
        {view === 'history' && <History records={records} actions={actions} onEdit={(r) => { setEditingRecord(r); setView('form'); }} onDelete={(id) => setRecords(prev => prev.filter(r => r.id !== id))} />}
        {view === 'consolidated' && <ConsolidatedView records={records} onBack={() => setView('dashboard')} />}
        {view === 'actions' && <ActionPlanView actions={actions} onUpdateAction={(ua) => setActions(prev => prev.map(a => a.id === ua.id ? ua : a))} onDeleteAction={handleDeleteAction} onClearActions={handleClearActions} />}
        {view === 'settings' && <SettingsView config={config} onUpdateConfig={setConfig} />}
        {view === 'ai-editor' && <AIEditor />}
      </main>

      <footer className="max-w-7xl mx-auto px-4 py-8 border-t border-gray-800 w-full opacity-30 text-center">
        <p className="text-[10px] font-bold tracking-widest uppercase">AuditCheck Pro v2.5 - Acceso Rápido Habilitado</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ActionItem, ActionStatus } from '../types';
import { CheckCircle2, Circle, Clock, AlertCircle, Search, Save, X, Users, Trash2, Edit2, Eraser } from 'lucide-react';

interface ActionPlanViewProps {
  actions: ActionItem[];
  onUpdateAction: (action: ActionItem) => void;
  onDeleteAction: (actionId: string) => void;
  onClearActions: () => void;
}

export const ActionPlanView: React.FC<ActionPlanViewProps> = ({ actions, onUpdateAction, onDeleteAction, onClearActions }) => {
  const [filterStatus, setFilterStatus] = useState<ActionStatus | 'ALL'>('ALL');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingAction, setEditingAction] = useState<ActionItem | null>(null);

  const filteredActions = actions.filter(a => {
    const matchesStatus = filterStatus === 'ALL' || a.status === filterStatus;
    const matchesSearch = 
        a.area.toLowerCase().includes(searchTerm.toLowerCase()) || 
        a.suggestedAction.toLowerCase().includes(searchTerm.toLowerCase()) ||
        a.questionText.toLowerCase().includes(searchTerm.toLowerCase()) ||
        a.responsable.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const getStatusLabel = (status: ActionStatus) => {
    switch (status) {
      case 'PENDING': return 'Pendiente';
      case 'IN_PROGRESS': return 'En Proceso';
      case 'CLOSED': return 'Cerrado';
    }
  };

  const handleSaveEdit = () => {
    if (editingAction) {
      onUpdateAction(editingAction);
      setEditingAction(null);
    }
  };

  const handleClearAll = () => {
    if (confirm('¿Está seguro de eliminar TODOS los planes de acción? Esta operación no se puede deshacer.')) {
      onClearActions();
    }
  };

  return (
    <div className="space-y-6 mb-24 animate-fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-100">Planes de Acción</h2>
          <p className="text-sm text-gray-500">Gestión de hallazgos y acciones correctivas.</p>
        </div>

        <div className="flex flex-col sm:flex-row gap-2">
            <button 
                onClick={handleClearAll}
                className="flex items-center justify-center gap-2 px-4 py-2 bg-red-600/10 text-red-400 border border-red-500/30 rounded-lg text-sm font-bold hover:bg-red-600 hover:text-white transition-all"
            >
                <Eraser className="w-4 h-4" /> Limpiar Todo
            </button>
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                <input 
                    type="text" 
                    placeholder="Buscar hallazgo o área..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-9 pr-4 py-2 border border-gray-700 bg-[#1e293b] text-white rounded-lg text-sm w-full sm:w-48 focus:ring-blue-500 focus:border-blue-500"
                />
            </div>
            <select 
                value={filterStatus}
                onChange={(e) => setFilterStatus(e.target.value as any)}
                className="px-4 py-2 border border-gray-700 bg-[#1e293b] text-white rounded-lg text-sm focus:ring-blue-500 focus:border-blue-500"
            >
                <option value="ALL">Todos los estados</option>
                <option value="PENDING">Pendientes</option>
                <option value="IN_PROGRESS">En Proceso</option>
                <option value="CLOSED">Cerrados</option>
            </select>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-4">
        <div className="bg-red-900/20 border border-red-500/30 p-4 rounded-xl text-center">
            <div className="text-2xl font-bold text-red-400">{actions.filter(a => a.status === 'PENDING').length}</div>
            <div className="text-xs font-medium text-red-300 uppercase tracking-wide">Pendientes</div>
        </div>
        <div className="bg-yellow-900/20 border border-yellow-500/30 p-4 rounded-xl text-center">
            <div className="text-2xl font-bold text-yellow-400">{actions.filter(a => a.status === 'IN_PROGRESS').length}</div>
            <div className="text-xs font-medium text-yellow-300 uppercase tracking-wide">En Proceso</div>
        </div>
        <div className="bg-green-900/20 border border-green-500/30 p-4 rounded-xl text-center">
            <div className="text-2xl font-bold text-green-400">{actions.filter(a => a.status === 'CLOSED').length}</div>
            <div className="text-xs font-medium text-green-300 uppercase tracking-wide">Cerrados</div>
        </div>
      </div>

      <div className="space-y-4">
        {filteredActions.length === 0 ? (
            <div className="text-center py-10 bg-[#1e293b] rounded-xl border border-gray-800">
                <p className="text-gray-500">No se encontraron acciones.</p>
            </div>
        ) : (
            filteredActions.map(action => (
                <div key={action.id} className="bg-[#1e293b] rounded-xl shadow-md border border-gray-800 overflow-hidden hover:border-gray-700 transition-all">
                    {editingAction?.id === action.id ? (
                        <div className="p-4 space-y-4 bg-blue-900/10">
                            <div className="flex justify-between items-center">
                                <h3 className="font-bold text-blue-300">Editando Acción</h3>
                                <button onClick={() => setEditingAction(null)} className="text-gray-400 hover:text-white">
                                    <X className="w-5 h-5" />
                                </button>
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-semibold text-gray-400">Hallazgo Detectado (Original)</label>
                                <textarea 
                                    value={editingAction.questionText}
                                    onChange={(e) => setEditingAction({...editingAction, questionText: e.target.value})}
                                    className="w-full p-2 border border-gray-600 rounded-md text-sm bg-[#0f172a] text-white"
                                    rows={2}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-semibold text-gray-400">Acción Sugerida / Plan</label>
                                <textarea 
                                    value={editingAction.suggestedAction}
                                    onChange={(e) => setEditingAction({...editingAction, suggestedAction: e.target.value})}
                                    className="w-full p-2 border border-gray-600 rounded-md text-sm bg-[#0f172a] text-white font-bold"
                                    rows={2}
                                />
                            </div>
                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <label className="text-xs font-semibold text-gray-400">Responsable</label>
                                    <input type="text" value={editingAction.responsable} onChange={(e) => setEditingAction({...editingAction, responsable: e.target.value})} className="w-full p-2 border border-gray-600 rounded-md text-sm bg-[#0f172a] text-white" />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-xs font-semibold text-gray-400">Fecha Compromiso</label>
                                    <input type="date" value={editingAction.dueDate.split('T')[0]} onChange={(e) => setEditingAction({...editingAction, dueDate: new Date(e.target.value).toISOString()})} className="w-full p-2 border border-gray-600 rounded-md text-sm bg-[#0f172a] text-white" />
                                </div>
                            </div>
                             <div className="space-y-1">
                                <label className="text-xs font-semibold text-gray-400">Estado</label>
                                <div className="flex gap-2">
                                    {(['PENDING', 'IN_PROGRESS', 'CLOSED'] as ActionStatus[]).map(s => (
                                        <button key={s} onClick={() => setEditingAction({...editingAction, status: s})} className={`px-3 py-1 rounded-full text-xs font-bold border transition-colors ${editingAction.status === s ? (s === 'CLOSED' ? 'bg-green-600 text-white' : s === 'IN_PROGRESS' ? 'bg-yellow-600 text-white' : 'bg-red-600 text-white') : 'bg-transparent text-gray-400 border-gray-600'}`}>{getStatusLabel(s)}</button>
                                    ))}
                                </div>
                            </div>
                            <button onClick={handleSaveEdit} className="w-full bg-blue-600 text-white py-2 rounded-lg font-medium hover:bg-blue-700 flex items-center justify-center gap-2 shadow-lg shadow-blue-500/20"><Save className="w-4 h-4" /> Actualizar Plan de Acción</button>
                        </div>
                    ) : (
                        <div className="p-4 flex flex-col md:flex-row gap-4">
                            <div className="flex-1 space-y-2">
                                <div className="flex items-start justify-between">
                                    <div className="flex items-center gap-2">
                                        <span className={`px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wide ${action.status === 'PENDING' ? 'bg-red-900/40 text-red-300' : action.status === 'IN_PROGRESS' ? 'bg-yellow-900/40 text-yellow-300' : 'bg-green-900/40 text-green-300'}`}>{getStatusLabel(action.status)}</span>
                                        <span className="text-xs text-gray-500">{new Date(action.createdAt).toLocaleDateString()}</span>
                                    </div>
                                    <div className="text-xs font-bold text-gray-400 uppercase tracking-widest">{action.area}</div>
                                </div>
                                <div>
                                    <p className="text-sm text-gray-200 font-medium mb-1 flex items-start gap-2">
                                        <AlertCircle className="w-4 h-4 text-red-400 mt-0.5 shrink-0" />
                                        <span>{action.questionText}</span>
                                    </p>
                                    <div className="text-sm text-gray-300 bg-[#0f172a] p-3 rounded-xl border border-gray-800 shadow-inner">
                                        <p className="font-black text-blue-400 text-[10px] uppercase tracking-widest mb-1">Acción Sugerida:</p>
                                        {action.suggestedAction}
                                    </div>
                                </div>
                                <div className="flex flex-wrap gap-4 text-[11px] text-gray-500 pt-1 font-bold">
                                    <span className="flex items-center gap-1.5"><Users className="w-3.5 h-3.5" /> RESPONSABLE: {action.responsable}</span>
                                    <span className={`flex items-center gap-1.5 ${new Date(action.dueDate) < new Date() && action.status !== 'CLOSED' ? 'text-red-400' : ''}`}>
                                        <Clock className="w-3.5 h-3.5" /> COMPROMISO: {new Date(action.dueDate).toLocaleDateString()}
                                    </span>
                                </div>
                            </div>
                            <div className="flex md:flex-col items-center justify-center border-t md:border-t-0 md:border-l border-gray-800 pt-3 md:pt-0 md:pl-4 gap-3">
                                <button 
                                    onClick={() => setEditingAction(action)} 
                                    className="flex items-center gap-1 text-blue-400 hover:text-blue-300 font-bold text-xs uppercase transition-colors"
                                    title="Editar acción"
                                >
                                    <Edit2 className="w-3.5 h-3.5" /> Gestionar
                                </button>
                                <button 
                                    onClick={() => {
                                        if(confirm('¿Desea eliminar esta acción del plan?')) {
                                            onDeleteAction(action.id);
                                        }
                                    }} 
                                    className="flex items-center gap-1 text-red-500/50 hover:text-red-500 font-bold text-xs uppercase transition-colors"
                                    title="Eliminar acción"
                                >
                                    <Trash2 className="w-3.5 h-3.5" /> Eliminar
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { ViewState, AuditRecord, ActionItem, AppConfig, Rating } from './types';
import { QUESTIONS, AREA_MAPPING, AREAS } from './constants';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ConsolidatedView } from './components/ConsolidatedView';
import { ActionPlanView } from './components/ActionPlanView';
import { SettingsView } from './components/SettingsView';
import { 
  ClipboardList, 
  Plus, 
  FileText, 
  BarChart, 
  Settings, 
  Home, 
  Camera,
  Loader2,
  ListChecks
} from 'lucide-react';

const DEFAULT_CONFIG: AppConfig = {
  questions: QUESTIONS,
  areas: AREAS,
  responsables: AREA_MAPPING.map(am => ({ name: am.responsable, area: am.area }))
};

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('home');
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [actions, setActions] = useState<ActionItem[]>([]);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);

  // Carga inicial
  useEffect(() => {
    const loadData = () => {
      try {
        const r = localStorage.getItem('audit_records');
        const a = localStorage.getItem('audit_actions');
        const c = localStorage.getItem('audit_config');
        if (r) setRecords(JSON.parse(r));
        if (a) setActions(JSON.parse(a));
        if (c) setConfig(JSON.parse(c));
      } catch (e) {
        console.error("Error cargando datos:", e);
      } finally {
        setIsInitializing(false);
      }
    };
    loadData();
  }, []);

  // Persistencia automática
  useEffect(() => {
    if (!isInitializing) {
      localStorage.setItem('audit_records', JSON.stringify(records));
      localStorage.setItem('audit_actions', JSON.stringify(actions));
      localStorage.setItem('audit_config', JSON.stringify(config));
    }
  }, [records, actions, config, isInitializing]);

  const handleSaveAudit = useCallback((record: AuditRecord, newActions: ActionItem[]) => {
    if (editingRecord) {
      setRecords(prev => prev.map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...prev]);
      if (newActions.length > 0) {
        setActions(prev => [...newActions, ...prev]);
      }
    }
    setView('dashboard');
  }, [editingRecord]);

  // Manejadores de Plan de Acción memoizados para evitar cierres de estado obsoletos
  const handleUpdateAction = useCallback((updatedAction: ActionItem) => {
    setActions(prev => prev.map(a => a.id === updatedAction.id ? updatedAction : a));
  }, []);

  const handleDeleteAction = useCallback((actionId: string) => {
    setActions(prev => prev.filter(a => a.id !== actionId));
  }, []);

  const handleClearActions = useCallback(() => {
    setActions([]);
  }, []);

  const generateDemo = () => {
    const demo = config.areas.slice(0, 8).map((area, i) => ({
      id: `demo-${i}-${Date.now()}`,
      area,
      auditor: 'Admin Demo',
      responsable: config.responsables.find(r => r.area === area)?.name || 'N/A',
      date: new Date().toISOString(),
      score: 70 + Math.floor(Math.random() * 25),
      answers: config.questions.map(q => ({ questionId: q.id, rating: Rating.SI }))
    }));
    setRecords(demo);
    setView('dashboard');
  };

  const NavIcon = ({ active, onClick, icon: Icon, title }: any) => (
    <button 
      onClick={onClick} 
      title={title}
      className={`p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 ${active ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-gray-500 hover:bg-gray-800 hover:text-gray-300'}`}
    >
      <Icon className="w-5 h-5" />
      <span className="text-[9px] font-bold uppercase tracking-tighter sm:hidden">{title}</span>
    </button>
  );

  if (isInitializing) {
    return (
      <div className="min-h-screen bg-[#0f172a] flex flex-col items-center justify-center gap-4">
        <Loader2 className="w-12 h-12 text-blue-500 animate-spin" />
        <p className="text-blue-500 font-black tracking-widest text-xs uppercase">Cargando Sistema...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0f172a] text-gray-100 flex flex-col">
      <header className="bg-[#1e293b]/90 backdrop-blur-xl border-b border-gray-800 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setView('home')}>
            <div className="bg-blue-600 p-2 rounded-lg group-hover:scale-110 transition-transform">
              <ClipboardList className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-xl font-black tracking-tighter">Audit<span className="text-blue-500">Check</span></h1>
          </div>
          <nav className="flex items-center gap-1 sm:gap-2">
            <NavIcon active={view === 'home'} onClick={() => setView('home')} icon={Home} title="Inicio" />
            <NavIcon active={view === 'form'} onClick={() => { setEditingRecord(null); setView('form'); }} icon={Plus} title="Auditar" />
            <NavIcon active={view === 'dashboard' || view === 'consolidated'} onClick={() => setView('dashboard')} icon={BarChart} title="Métricas" />
            <NavIcon active={view === 'actions'} onClick={() => setView('actions')} icon={ListChecks} title="Planes" />
            <NavIcon active={view === 'history'} onClick={() => setView('history')} icon={FileText} title="Historial" />
            <NavIcon active={view === 'ai-editor'} onClick={() => setView('ai-editor')} icon={Camera} title="IA" />
            <NavIcon active={view === 'settings'} onClick={() => setView('settings')} icon={Settings} title="Ajustes" />
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 w-full flex-1">
        {view === 'home' && (
          <div className="max-w-xl mx-auto py-12 space-y-8 animate-fade-in">
             <div className="text-center space-y-2">
                <h2 className="text-5xl font-black text-white leading-tight">Gestión Operativa <br/><span className="text-blue-500 underline decoration-blue-500/30">Sin Papel</span></h2>
                <p className="text-gray-500 text-lg">Digitalice sus auditorías 5S y controle su planta en tiempo real.</p>
             </div>
             <div className="grid grid-cols-1 gap-4">
                <button onClick={() => { setEditingRecord(null); setView('form'); }} className="flex items-center justify-between p-8 bg-[#1e293b] border border-green-500/20 rounded-3xl hover:border-green-500/50 hover:bg-[#1e293b]/80 transition-all shadow-xl group">
                    <div className="flex items-center gap-6">
                        <div className="bg-green-600/10 p-4 rounded-2xl group-hover:bg-green-600/20 transition-colors">
                            <Plus className="w-10 h-10 text-green-500" />
                        </div>
                        <div className="text-left">
                            <p className="text-2xl font-black text-white">Nueva Auditoría</p>
                            <p className="text-sm text-gray-500">Iniciar inspección de área ahora</p>
                        </div>
                    </div>
                </button>
                <div className="grid grid-cols-2 gap-4">
                    <button onClick={() => setView('dashboard')} className="p-6 bg-[#1e293b] border border-blue-500/20 rounded-3xl hover:border-blue-500/50 transition-all text-left">
                        <BarChart className="w-8 h-8 text-blue-500 mb-4" />
                        <p className="text-lg font-bold">Indicadores</p>
                        <p className="text-xs text-gray-500">Métricas de planta</p>
                    </button>
                    <button onClick={() => setView('actions')} className="p-6 bg-[#1e293b] border border-amber-500/20 rounded-3xl hover:border-amber-500/50 transition-all text-left">
                        <ListChecks className="w-8 h-8 text-amber-500 mb-4" />
                        <p className="text-lg font-bold">Planes de Acción</p>
                        <p className="text-xs text-gray-500">Hallazgos y tareas</p>
                    </button>
                </div>
             </div>
          </div>
        )}
        {view === 'form' && <AuditForm initialData={editingRecord} config={config} onSave={handleSaveAudit} onCancel={() => setView('home')} />}
        {view === 'dashboard' && <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} onGenerateDemo={generateDemo} />}
        {view === 'history' && <History records={records} actions={actions} onEdit={(r) => { setEditingRecord(r); setView('form'); }} onDelete={(id) => setRecords(prev => prev.filter(r => r.id !== id))} />}
        {view === 'consolidated' && <ConsolidatedView records={records} onBack={() => setView('dashboard')} />}
        {view === 'actions' && <ActionPlanView actions={actions} onUpdateAction={handleUpdateAction} onDeleteAction={handleDeleteAction} onClearActions={handleClearActions} />}
        {view === 'settings' && <SettingsView config={config} onUpdateConfig={setConfig} />}
        {view === 'ai-editor' && <AIEditor />}
      </main>

      <footer className="max-w-7xl mx-auto px-4 py-8 border-t border-gray-800 w-full opacity-30 text-center">
        <p className="text-[10px] font-bold tracking-widest uppercase">AuditCheck Pro v2.5 - Acceso Rápido Habilitado</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ActionItem, ActionStatus } from '../types';
import { CheckCircle2, Clock, AlertCircle, Search, Save, X, Users, Trash2, Edit2, Eraser } from 'lucide-react';

interface ActionPlanViewProps {
  actions: ActionItem[];
  onUpdateAction: (action: ActionItem) => void;
  onDeleteAction: (actionId: string) => void;
  onClearActions: () => void;
}

export const ActionPlanView: React.FC<ActionPlanViewProps> = ({ actions, onUpdateAction, onDeleteAction, onClearActions }) => {
  const [filterStatus, setFilterStatus] = useState<ActionStatus | 'ALL'>('ALL');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingAction, setEditingAction] = useState<ActionItem | null>(null);

  const filteredActions = actions.filter(a => {
    const matchesStatus = filterStatus === 'ALL' || a.status === filterStatus;
    const matchesSearch = 
        a.area.toLowerCase().includes(searchTerm.toLowerCase()) || 
        a.suggestedAction.toLowerCase().includes(searchTerm.toLowerCase()) ||
        a.questionText.toLowerCase().includes(searchTerm.toLowerCase()) ||
        a.responsable.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const getStatusLabel = (status: ActionStatus) => {
    switch (status) {
      case 'PENDING': return 'Pendiente';
      case 'IN_PROGRESS': return 'En Proceso';
      case 'CLOSED': return 'Cerrado';
    }
  };

  const handleSaveEdit = () => {
    if (editingAction) {
      onUpdateAction(editingAction);
      setEditingAction(null);
    }
  };

  const handleIndividualDelete = (id: string) => {
    if (window.confirm('¿Desea eliminar este hallazgo del plan de acción?')) {
      onDeleteAction(id);
    }
  };

  const handleClearAll = () => {
    if (window.confirm('¿Está seguro de eliminar TODOS los planes de acción? Esta operación limpiará el historial completo de tareas.')) {
      onClearActions();
    }
  };

  return (
    <div className="space-y-6 mb-24 animate-fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-100">Planes de Acción</h2>
          <p className="text-sm text-gray-500">Gestión estratégica de hallazgos críticos.</p>
        </div>

        <div className="flex flex-wrap items-center gap-2">
            <button 
                onClick={handleClearAll}
                className="flex items-center justify-center gap-2 px-4 py-2 bg-red-600/10 text-red-400 border border-red-500/30 rounded-xl text-xs font-bold hover:bg-red-600 hover:text-white transition-all shadow-sm"
            >
                <Eraser className="w-3.5 h-3.5" /> Limpiar Plan Completo
            </button>
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                <input 
                    type="text" 
                    placeholder="Buscar..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-9 pr-4 py-2 border border-gray-700 bg-[#1e293b] text-white rounded-xl text-xs w-full sm:w-40 focus:ring-blue-500 outline-none"
                />
            </div>
            <select 
                value={filterStatus}
                onChange={(e) => setFilterStatus(e.target.value as any)}
                className="px-4 py-2 border border-gray-700 bg-[#1e293b] text-white rounded-xl text-xs focus:ring-blue-500 outline-none"
            >
                <option value="ALL">Todos</option>
                <option value="PENDING">Pendientes</option>
                <option value="IN_PROGRESS">En Proceso</option>
                <option value="CLOSED">Cerrados</option>
            </select>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-3">
        <div className="bg-red-900/10 border border-red-500/20 p-4 rounded-2xl text-center">
            <div className="text-xl font-black text-red-500">{actions.filter(a => a.status === 'PENDING').length}</div>
            <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Pendientes</div>
        </div>
        <div className="bg-yellow-900/10 border border-yellow-500/20 p-4 rounded-2xl text-center">
            <div className="text-xl font-black text-yellow-500">{actions.filter(a => a.status === 'IN_PROGRESS').length}</div>
            <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">En Proceso</div>
        </div>
        <div className="bg-green-900/10 border border-green-500/20 p-4 rounded-2xl text-center">
            <div className="text-xl font-black text-green-500">{actions.filter(a => a.status === 'CLOSED').length}</div>
            <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Cerrados</div>
        </div>
      </div>

      <div className="space-y-4">
        {filteredActions.length === 0 ? (
            <div className="text-center py-16 bg-[#1e293b]/50 rounded-3xl border border-gray-800 border-dashed">
                <AlertCircle className="w-12 h-12 text-gray-700 mx-auto mb-3" />
                <p className="text-gray-500 font-medium">No se registran hallazgos para los filtros aplicados.</p>
            </div>
        ) : (
            filteredActions.map(action => (
                <div key={action.id} className="bg-[#1e293b] rounded-2xl shadow-sm border border-gray-800 overflow-hidden hover:border-gray-700 transition-all">
                    {editingAction?.id === action.id ? (
                        <div className="p-5 space-y-4 bg-blue-900/10 animate-fade-in">
                            <div className="flex justify-between items-center border-b border-blue-500/20 pb-3">
                                <h3 className="font-black text-blue-400 text-xs uppercase tracking-widest">Edición de Tarea Correctiva</h3>
                                <button onClick={() => setEditingAction(null)} className="text-gray-400 hover:text-white p-1">
                                    <X className="w-5 h-5" />
                                </button>
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-gray-500 uppercase">Hallazgo Original (Pregunta)</label>
                                <textarea 
                                    value={editingAction.questionText}
                                    onChange={(e) => setEditingAction({...editingAction, questionText: e.target.value})}
                                    className="w-full p-3 border border-gray-700 rounded-xl text-sm bg-[#0f172a] text-white focus:ring-1 focus:ring-blue-500 outline-none"
                                    rows={2}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-gray-500 uppercase">Plan de Acción / Resolución</label>
                                <textarea 
                                    value={editingAction.suggestedAction}
                                    onChange={(e) => setEditingAction({...editingAction, suggestedAction: e.target.value})}
                                    className="w-full p-3 border border-gray-700 rounded-xl text-sm bg-[#0f172a] text-white font-bold focus:ring-1 focus:ring-blue-500 outline-none"
                                    rows={2}
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-gray-500 uppercase">Responsable</label>
                                    <input type="text" value={editingAction.responsable} onChange={(e) => setEditingAction({...editingAction, responsable: e.target.value})} className="w-full p-2.5 border border-gray-700 rounded-xl text-sm bg-[#0f172a] text-white focus:ring-1 focus:ring-blue-500 outline-none" />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-gray-500 uppercase">Compromiso</label>
                                    <input type="date" value={editingAction.dueDate.split('T')[0]} onChange={(e) => setEditingAction({...editingAction, dueDate: new Date(e.target.value).toISOString()})} className="w-full p-2.5 border border-gray-700 rounded-xl text-sm bg-[#0f172a] text-white focus:ring-1 focus:ring-blue-500 outline-none" />
                                </div>
                            </div>
                             <div className="space-y-2 pt-2">
                                <label className="text-[10px] font-bold text-gray-500 uppercase">Estado Operativo</label>
                                <div className="flex gap-2">
                                    {(['PENDING', 'IN_PROGRESS', 'CLOSED'] as ActionStatus[]).map(s => (
                                        <button 
                                          key={s} 
                                          type="button"
                                          onClick={() => setEditingAction({...editingAction, status: s})} 
                                          className={`flex-1 py-2 rounded-xl text-[10px] font-black uppercase border transition-all ${editingAction.status === s ? (s === 'CLOSED' ? 'bg-green-600 border-green-600 text-white' : s === 'IN_PROGRESS' ? 'bg-yellow-600 border-yellow-600 text-white' : 'bg-red-600 border-red-600 text-white') : 'bg-transparent text-gray-500 border-gray-700 hover:border-gray-500'}`}
                                        >
                                          {getStatusLabel(s)}
                                        </button>
                                    ))}
                                </div>
                            </div>
                            <button onClick={handleSaveEdit} className="w-full bg-blue-600 text-white py-3 rounded-xl font-bold hover:bg-blue-700 flex items-center justify-center gap-2 shadow-lg shadow-blue-500/20 transition-all mt-4"><Save className="w-4 h-4" /> Actualizar Registro</button>
                        </div>
                    ) : (
                        <div className="p-5 flex flex-col md:flex-row gap-5">
                            <div className="flex-1 space-y-3">
                                <div className="flex items-start justify-between">
                                    <div className="flex items-center gap-2">
                                        <span className={`px-2 py-0.5 rounded-lg text-[10px] font-black uppercase tracking-widest ${action.status === 'PENDING' ? 'bg-red-500/10 text-red-500' : action.status === 'IN_PROGRESS' ? 'bg-yellow-500/10 text-yellow-500' : 'bg-green-500/10 text-green-500'}`}>{getStatusLabel(action.status)}</span>
                                        <span className="text-[10px] text-gray-600 font-bold">{new Date(action.createdAt).toLocaleDateString()}</span>
                                    </div>
                                    <div className="text-[11px] font-black text-blue-500 uppercase tracking-tighter bg-blue-500/5 px-2 py-0.5 rounded-md border border-blue-500/10">{action.area}</div>
                                </div>
                                <div>
                                    <p className="text-sm text-gray-100 font-semibold mb-2 flex items-start gap-2 leading-relaxed">
                                        <AlertCircle className="w-4 h-4 text-red-500 mt-0.5 shrink-0" />
                                        <span>{action.questionText}</span>
                                    </p>
                                    <div className="text-xs text-gray-400 bg-[#0f172a] p-4 rounded-2xl border border-gray-800 shadow-inner group-hover:border-gray-700 transition-colors">
                                        <p className="font-black text-gray-500 text-[9px] uppercase tracking-[0.2em] mb-2">Plan de Resolución Sugerido:</p>
                                        <span className="text-gray-300 leading-relaxed italic">"{action.suggestedAction}"</span>
                                    </div>
                                </div>
                                <div className="flex flex-wrap gap-4 text-[10px] text-gray-500 pt-2 font-bold uppercase tracking-tight">
                                    <span className="flex items-center gap-1.5 bg-[#0f172a] px-2 py-1 rounded-md border border-gray-800"><Users className="w-3.5 h-3.5 text-blue-500" /> Resp: {action.responsable}</span>
                                    <span className={`flex items-center gap-1.5 bg-[#0f172a] px-2 py-1 rounded-md border border-gray-800 ${new Date(action.dueDate) < new Date() && action.status !== 'CLOSED' ? 'text-red-500 border-red-500/20 animate-pulse' : ''}`}>
                                        <Clock className="w-3.5 h-3.5" /> Límite: {new Date(action.dueDate).toLocaleDateString()}
                                    </span>
                                </div>
                            </div>
                            <div className="flex md:flex-col items-stretch justify-center border-t md:border-t-0 md:border-l border-gray-800 pt-4 md:pt-0 md:pl-5 gap-2 min-w-[120px]">
                                <button 
                                    onClick={() => setEditingAction(action)} 
                                    className="flex items-center justify-center gap-2 px-3 py-2 bg-blue-500/10 text-blue-400 rounded-xl font-black text-[10px] uppercase hover:bg-blue-500 hover:text-white transition-all"
                                    title="Editar hallazgo y plan"
                                >
                                    <Edit2 className="w-3.5 h-3.5" /> Gestionar
                                </button>
                                <button 
                                    onClick={() => handleIndividualDelete(action.id)} 
                                    className="flex items-center justify-center gap-2 px-3 py-2 bg-red-500/5 text-gray-600 rounded-xl font-black text-[10px] uppercase hover:bg-red-600 hover:text-white transition-all"
                                    title="Eliminar esta acción"
                                >
                                    <Trash2 className="w-3.5 h-3.5" /> Eliminar
                                </button>
                            </div>
                        </div>
                    )}
                </div>
            ))
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { ViewState, AuditRecord, ActionItem, AppConfig, Rating } from './types';
import { QUESTIONS, AREA_MAPPING, AREAS } from './constants';
import { AuditForm } from './components/AuditForm';
import { Dashboard } from './components/Dashboard';
import { History } from './components/History';
import { AIEditor } from './components/AIEditor';
import { ConsolidatedView } from './components/ConsolidatedView';
import { ActionPlanView } from './components/ActionPlanView';
import { SettingsView } from './components/SettingsView';
import { 
  ClipboardList, 
  Plus, 
  FileText, 
  BarChart, 
  Settings, 
  Home, 
  Camera,
  Loader2,
  ListChecks
} from 'lucide-react';

const DEFAULT_CONFIG: AppConfig = {
  questions: QUESTIONS,
  areas: AREAS,
  responsables: AREA_MAPPING.map(am => ({ name: am.responsable, area: am.area }))
};

const App: React.FC = () => {
  const [view, setView] = useState<ViewState>('home');
  const [records, setRecords] = useState<AuditRecord[]>([]);
  const [actions, setActions] = useState<ActionItem[]>([]);
  const [config, setConfig] = useState<AppConfig>(DEFAULT_CONFIG);
  const [editingRecord, setEditingRecord] = useState<AuditRecord | null>(null);
  const [isInitializing, setIsInitializing] = useState(true);

  // Carga inicial de datos
  useEffect(() => {
    const loadData = () => {
      try {
        const r = localStorage.getItem('audit_records');
        const a = localStorage.getItem('audit_actions');
        const c = localStorage.getItem('audit_config');
        if (r) setRecords(JSON.parse(r));
        if (a) setActions(JSON.parse(a));
        if (c) setConfig(JSON.parse(c));
      } catch (e) {
        console.error("Error al cargar datos de localStorage:", e);
      } finally {
        setIsInitializing(false);
      }
    };
    loadData();
  }, []);

  // Guardado automático cada vez que cambien los estados principales
  useEffect(() => {
    if (!isInitializing) {
      localStorage.setItem('audit_records', JSON.stringify(records));
      localStorage.setItem('audit_actions', JSON.stringify(actions));
      localStorage.setItem('audit_config', JSON.stringify(config));
    }
  }, [records, actions, config, isInitializing]);

  const handleSaveAudit = useCallback((record: AuditRecord, newActions: ActionItem[]) => {
    if (editingRecord) {
      setRecords(prev => prev.map(r => r.id === record.id ? record : r));
      setEditingRecord(null);
    } else {
      setRecords(prev => [record, ...prev]);
      if (newActions && newActions.length > 0) {
        setActions(prev => [...newActions, ...prev]);
      }
    }
    setView('dashboard');
  }, [editingRecord]);

  const handleUpdateAction = (updatedAction: ActionItem) => {
    setActions(prev => prev.map(a => a.id === updatedAction.id ? updatedAction : a));
  };

  const handleDeleteAction = (actionId: string) => {
    setActions(prev => prev.filter(a => a.id !== actionId));
  };

  const handleClearActions = () => {
    setActions([]);
  };

  const generateDemo = () => {
    const demo = config.areas.slice(0, 8).map((area, i) => ({
      id: `demo-${i}-${Date.now()}`,
      area,
      auditor: 'Admin Demo',
      responsable: config.responsables.find(r => r.area === area)?.name || 'N/A',
      date: new Date().toISOString(),
      score: 70 + Math.floor(Math.random() * 25),
      answers: config.questions.map(q => ({ questionId: q.id, rating: Rating.SI }))
    }));
    setRecords(demo);
    setView('dashboard');
  };

  const NavIcon = ({ active, onClick, icon: Icon, title }: any) => (
    <button 
      type="button"
      onClick={onClick} 
      title={title}
      className={`p-2.5 rounded-xl transition-all flex flex-col items-center gap-1 ${active ? 'bg-blue-600 text-white shadow-lg shadow-blue-600/20' : 'text-gray-500 hover:bg-gray-800 hover:text-gray-300'}`}
    >
      <Icon className="w-5 h-5" />
      <span className="text-[9px] font-bold uppercase tracking-tighter sm:hidden">{title}</span>
    </button>
  );

  if (isInitializing) {
    return (
      <div className="min-h-screen bg-[#0f172a] flex flex-col items-center justify-center gap-4">
        <Loader2 className="w-12 h-12 text-blue-500 animate-spin" />
        <p className="text-blue-500 font-black tracking-widest text-xs uppercase">Iniciando Aplicación...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#0f172a] text-gray-100 flex flex-col">
      <header className="bg-[#1e293b]/90 backdrop-blur-xl border-b border-gray-800 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={() => setView('home')}>
            <div className="bg-blue-600 p-2 rounded-lg group-hover:scale-110 transition-transform">
              <ClipboardList className="w-5 h-5 text-white" />
            </div>
            <h1 className="text-xl font-black tracking-tighter">Audit<span className="text-blue-500">Check</span></h1>
          </div>
          <nav className="flex items-center gap-1 sm:gap-2">
            <NavIcon active={view === 'home'} onClick={() => setView('home')} icon={Home} title="Inicio" />
            <NavIcon active={view === 'form'} onClick={() => { setEditingRecord(null); setView('form'); }} icon={Plus} title="Auditar" />
            <NavIcon active={view === 'dashboard' || view === 'consolidated'} onClick={() => setView('dashboard')} icon={BarChart} title="Métricas" />
            <NavIcon active={view === 'actions'} onClick={() => setView('actions')} icon={ListChecks} title="Planes" />
            <NavIcon active={view === 'history'} onClick={() => setView('history')} icon={FileText} title="Historial" />
            <NavIcon active={view === 'ai-editor'} onClick={() => setView('ai-editor')} icon={Camera} title="IA" />
            <NavIcon active={view === 'settings'} onClick={() => setView('settings')} icon={Settings} title="Ajustes" />
          </nav>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 w-full flex-1">
        {view === 'home' && (
          <div className="max-w-xl mx-auto py-12 space-y-8 animate-fade-in">
             <div className="text-center space-y-2">
                <h2 className="text-5xl font-black text-white leading-tight">Gestión Operativa <br/><span className="text-blue-500 underline decoration-blue-500/30">Sin Papel</span></h2>
                <p className="text-gray-500 text-lg">Digitalice sus auditorías 5S y controle su planta en tiempo real.</p>
             </div>
             <div className="grid grid-cols-1 gap-4">
                <button type="button" onClick={() => { setEditingRecord(null); setView('form'); }} className="flex items-center justify-between p-8 bg-[#1e293b] border border-green-500/20 rounded-3xl hover:border-green-500/50 hover:bg-[#1e293b]/80 transition-all shadow-xl group">
                    <div className="flex items-center gap-6">
                        <div className="bg-green-600/10 p-4 rounded-2xl group-hover:bg-green-600/20 transition-colors">
                            <Plus className="w-10 h-10 text-green-500" />
                        </div>
                        <div className="text-left">
                            <p className="text-2xl font-black text-white">Nueva Auditoría</p>
                            <p className="text-sm text-gray-500">Iniciar inspección de área ahora</p>
                        </div>
                    </div>
                </button>
                <div className="grid grid-cols-2 gap-4">
                    <button type="button" onClick={() => setView('dashboard')} className="p-6 bg-[#1e293b] border border-blue-500/20 rounded-3xl hover:border-blue-500/50 transition-all text-left">
                        <BarChart className="w-8 h-8 text-blue-500 mb-4" />
                        <p className="text-lg font-bold">Indicadores</p>
                        <p className="text-xs text-gray-500">Métricas de planta</p>
                    </button>
                    <button type="button" onClick={() => setView('actions')} className="p-6 bg-[#1e293b] border border-amber-500/20 rounded-3xl hover:border-amber-500/50 transition-all text-left">
                        <ListChecks className="w-8 h-8 text-amber-500 mb-4" />
                        <p className="text-lg font-bold">Planes de Acción</p>
                        <p className="text-xs text-gray-500">Hallazgos y tareas</p>
                    </button>
                </div>
             </div>
          </div>
        )}
        {view === 'form' && <AuditForm initialData={editingRecord} config={config} onSave={handleSaveAudit} onCancel={() => setView('home')} />}
        {view === 'dashboard' && <Dashboard records={records} actions={actions} onViewConsolidated={() => setView('consolidated')} onViewActions={() => setView('actions')} onGenerateDemo={generateDemo} />}
        {view === 'history' && <History records={records} actions={actions} onEdit={(r) => { setEditingRecord(r); setView('form'); }} onDelete={(id) => setRecords(prev => prev.filter(r => r.id !== id))} />}
        {view === 'consolidated' && <ConsolidatedView records={records} onBack={() => setView('dashboard')} />}
        {view === 'actions' && (
          <ActionPlanView 
            actions={actions} 
            onUpdateAction={handleUpdateAction} 
            onDeleteAction={handleDeleteAction} 
            onClearActions={handleClearActions} 
          />
        )}
        {view === 'settings' && <SettingsView config={config} onUpdateConfig={setConfig} />}
        {view === 'ai-editor' && <AIEditor />}
      </main>

      <footer className="max-w-7xl mx-auto px-4 py-8 border-t border-gray-800 w-full opacity-30 text-center">
        <p className="text-[10px] font-bold tracking-widest uppercase">AuditCheck Pro v2.5 - Acceso Rápido Habilitado</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { ActionItem, ActionStatus } from '../types';
import { CheckCircle2, Clock, AlertCircle, Search, Save, X, Users, Trash2, Edit2, Eraser } from 'lucide-react';

interface ActionPlanViewProps {
  actions: ActionItem[];
  onUpdateAction: (action: ActionItem) => void;
  onDeleteAction: (actionId: string) => void;
  onClearActions: () => void;
}

export const ActionPlanView: React.FC<ActionPlanViewProps> = ({ actions, onUpdateAction, onDeleteAction, onClearActions }) => {
  const [filterStatus, setFilterStatus] = useState<ActionStatus | 'ALL'>('ALL');
  const [searchTerm, setSearchTerm] = useState('');
  const [editingAction, setEditingAction] = useState<ActionItem | null>(null);

  const filteredActions = actions.filter(a => {
    const matchesStatus = filterStatus === 'ALL' || a.status === filterStatus;
    const matchesSearch = 
        a.area.toLowerCase().includes(searchTerm.toLowerCase()) || 
        a.suggestedAction.toLowerCase().includes(searchTerm.toLowerCase()) ||
        a.questionText.toLowerCase().includes(searchTerm.toLowerCase()) ||
        a.responsable.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesStatus && matchesSearch;
  });

  const getStatusLabel = (status: ActionStatus) => {
    switch (status) {
      case 'PENDING': return 'Pendiente';
      case 'IN_PROGRESS': return 'En Proceso';
      case 'CLOSED': return 'Cerrado';
    }
  };

  const handleSaveEdit = () => {
    if (editingAction) {
      onUpdateAction(editingAction);
      setEditingAction(null);
    }
  };

  const onConfirmDeleteAction = (id: string) => {
    if (confirm('¿Desea eliminar este hallazgo del plan de acción definitivamente?')) {
      onDeleteAction(id);
    }
  };

  const onConfirmClearAll = () => {
    if (confirm('ATENCIÓN: ¿Está seguro de eliminar TODOS los planes de acción de la lista? Esta acción no se puede deshacer.')) {
      onClearActions();
    }
  };

  return (
    <div className="space-y-6 mb-24 animate-fade-in">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold text-gray-100">Planes de Acción</h2>
          <p className="text-sm text-gray-500">Gestión estratégica de hallazgos críticos.</p>
        </div>

        <div className="flex flex-wrap items-center gap-2">
            <button 
                type="button"
                onClick={onConfirmClearAll}
                className="flex items-center justify-center gap-2 px-4 py-2 bg-red-600/20 text-red-400 border border-red-500/30 rounded-xl text-xs font-bold hover:bg-red-600 hover:text-white transition-all shadow-sm"
            >
                <Eraser className="w-3.5 h-3.5" /> Limpiar Todo el Plan
            </button>
            <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                <input 
                    type="text" 
                    placeholder="Buscar..." 
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-9 pr-4 py-2 border border-gray-700 bg-[#1e293b] text-white rounded-xl text-xs w-full sm:w-40 focus:ring-blue-500 outline-none"
                />
            </div>
            <select 
                value={filterStatus}
                onChange={(e) => setFilterStatus(e.target.value as any)}
                className="px-4 py-2 border border-gray-700 bg-[#1e293b] text-white rounded-xl text-xs focus:ring-blue-500 outline-none"
            >
                <option value="ALL">Todos</option>
                <option value="PENDING">Pendientes</option>
                <option value="IN_PROGRESS">En Proceso</option>
                <option value="CLOSED">Cerrados</option>
            </select>
        </div>
      </div>

      <div className="grid grid-cols-3 gap-3">
        <div className="bg-red-900/10 border border-red-500/20 p-4 rounded-2xl text-center">
            <div className="text-xl font-black text-red-500">{actions.filter(a => a.status === 'PENDING').length}</div>
            <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Pendientes</div>
        </div>
        <div className="bg-yellow-900/10 border border-yellow-500/20 p-4 rounded-2xl text-center">
            <div className="text-xl font-black text-yellow-500">{actions.filter(a => a.status === 'IN_PROGRESS').length}</div>
            <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">En Proceso</div>
        </div>
        <div className="bg-green-900/10 border border-green-500/20 p-4 rounded-2xl text-center">
            <div className="text-xl font-black text-green-500">{actions.filter(a => a.status === 'CLOSED').length}</div>
            <div className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">Cerrados</div>
        </div>
      </div>

      <div className="space-y-4">
        {filteredActions.length === 0 ? (
            <div className="text-center py-16 bg-[#1e293b]/50 rounded-3xl border border-gray-800 border-dashed">
                <AlertCircle className="w-12 h-12 text-gray-700 mx-auto mb-3" />
                <p className="text-gray-500 font-medium">No se registran hallazgos para los filtros aplicados.</p>
            </div>
        ) : (
            filteredActions.map(action => (
                <div key={action.id} className="bg-[#1e293b] rounded-2xl shadow-sm border border-gray-800 overflow-hidden hover:border-gray-700 transition-all">
                    {editingAction?.id === action.id ? (
                        <div className="p-5 space-y-4 bg-blue-900/10 animate-fade-in">
                            <div className="flex justify-between items-center border-b border-blue-500/20 pb-3">
                                <h3 className="font-black text-blue-400 text-xs uppercase tracking-widest">Edición de Tarea Correctiva</h3>
                                <button type="button" onClick={() => setEditingAction(null)} className="text-gray-400 hover:text-white p-1">
                                    <X className="w-5 h-5" />
                                </button>
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-gray-500 uppercase">Hallazgo Original (Pregunta)</label>
                                <textarea 
                                    value={editingAction.questionText}
                                    onChange={(e) => setEditingAction({...editingAction, questionText: e.target.value})}
                                    className="w-full p-3 border border-gray-700 rounded-xl text-sm bg-[#0f172a] text-white focus:ring-1 focus:ring-blue-500 outline-none"
                                    rows={2}
                                />
                            </div>
                            <div className="space-y-2">
                                <label className="text-[10px] font-bold text-gray-500 uppercase">Plan de Acción / Resolución</label>
                                <textarea 
                                    value={editingAction.suggestedAction}
                                    onChange={(e) => setEditingAction({...editingAction, suggestedAction: e.target.value})}
                                    className="w-full p-3 border border-gray-700 rounded-xl text-sm bg-[#0f172a] text-white font-bold focus:ring-1 focus:ring-blue-500 outline-none"
                                    rows={2}
                                />
                            </div>
                            <div className="grid grid-cols-2 gap-4">
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-gray-500 uppercase">Responsable</label>
                                    <input type="text" value={editingAction.responsable} onChange={(e) => setEditingAction({...editingAction, responsable: e.target.value})} className="w-full p-2.5 border border-gray-700 rounded-xl text-sm bg-[#0f172a] text-white focus:ring-1 focus:ring-blue-500 outline-none" />
                                </div>
                                <div className="space-y-1">
                                    <label className="text-[10px] font-bold text-gray-500 uppercase">Compromiso</label>
                                    <input type="date" value={editingAction.dueDate.split('T')[0]} onChange={(e) => setEditingAction({...editingAction, dueDate: new Date(e.target.value).toISOString()})} className="w-full p-2.5 border border-gray-700 rounded-xl text-sm bg-[#0f172a] text-white focus:ring-1 focus:ring-blue-500 outline-none" />
                                </div>
                            </div>
                             <div className="space-y-2 pt-2">
                                <label className="text-[10px] font-bold text-gray-500 uppercase">Estado Operativo</label>
                                <div className="flex gap-2">
                                    {(['PENDING', 'IN_PROGRESS', 'CLOSED'] as ActionStatus[]).map(s => (
                                        <button 
                                          key={s} 
