                className="flex items-center gap-2 bg-red-600/10 text-red-500 border border-red-500/20 px-5 py-3 rounded-2xl transition-all font-bold text-sm hover:bg-red-600 hover:text-white"
            >
                <Eraser className="w-5 h-5" /> 
